const PARCEL_CATEGORY_TREE = {
  pants: ["sweat pant", "cargo pant", "jeans pant", "others pants"],
  dress: ["long dress", "short dress", "2 pieces"],
  tops: ["lady tops", "unisex T-shirt", "men shirt"],
  jacket: ["jacket"],
  kids: ["baby kids", "big kids"],
  shoes: ["sport shoes", "office shoes", "lady shoes", "kids shoes"],
  bags: ["bags"],
  cosmetics: ["cosmetics"],
  others: ["others"],
};

function getBaseCategoryMainForSubCategory(subCategory = "") {
  const normalizedSub = String(subCategory || "").trim().toLowerCase();
  if (!normalizedSub) {
    return "";
  }
  return Object.entries(PARCEL_CATEGORY_TREE).find(([, subCategories]) =>
    (Array.isArray(subCategories) ? subCategories : []).some(
      (value) => String(value || "").trim().toLowerCase() === normalizedSub,
    ),
  )?.[0] || "";
}

function canAttachSubCategoryToMain(mainCategory = "", subCategory = "") {
  const mainValue = String(mainCategory || "").trim();
  const subValue = String(subCategory || "").trim();
  if (!mainValue || !subValue) {
    return false;
  }
  const baseMain = getBaseCategoryMainForSubCategory(subValue);
  return !baseMain || baseMain === mainValue;
}

function appendCategoryPairToTree(tree, mainCategory = "", subCategory = "") {
  const mainValue = String(mainCategory || "").trim();
  const subValue = String(subCategory || "").trim();
  if (!canAttachSubCategoryToMain(mainValue, subValue)) {
    return false;
  }
  if (!Array.isArray(tree[mainValue])) {
    tree[mainValue] = [];
  }
  if (!tree[mainValue].includes(subValue)) {
    tree[mainValue].push(subValue);
  }
  return true;
}

