function humanizeFieldName(name) {
  if (!name) {
    return "填写内容";
  }
  return name
    .replaceAll("_", " ")
    .replace(/\b\w/g, (char) => char.toUpperCase());
}

function getFieldLabelText(control) {
  const explicit = control.dataset.fieldLabel?.trim();
  if (explicit) {
    return explicit;
  }
  const name = control.getAttribute("name") || "";
  if (FIELD_LABELS[name]) {
    return FIELD_LABELS[name];
  }
  const placeholder = control.getAttribute("placeholder")?.trim();
  if (placeholder) {
    return placeholder.replace(/（.*?）/g, "").replace(/\(.*?\)/g, "").trim();
  }
  return humanizeFieldName(name);
}

function getFieldHelpText(control) {
  const explicit = control.dataset.fieldHelp?.trim();
  if (explicit) {
    return explicit;
  }
  const name = control.getAttribute("name") || "";
  if (FIELD_HELP[name]) {
    return FIELD_HELP[name];
  }
  const placeholder = control.getAttribute("placeholder")?.trim();
  if (placeholder) {
    return `请填写：${placeholder}`;
  }
  return "请按当前流程填写这个字段。";
}

function ensureFieldIdsAndLabels() {
  const controls = document.querySelectorAll(".form-grid input, .form-grid select, .form-grid textarea");
  controls.forEach((control, index) => {
    const type = control.getAttribute("type");
    if (["hidden", "submit", "button", "radio", "checkbox"].includes(type || "")) {
      return;
    }
    if (control.classList.contains("json-raw-field")) {
      return;
    }
    if (control.closest(".field-stack")) {
      return;
    }
    if (!control.id) {
      control.id = `field-${control.name || "input"}-${index + 1}`;
    }
    if (control.closest(".field-group")) {
      return;
    }
    const wrapper = document.createElement("div");
    wrapper.className = "field-group";
    const label = document.createElement("label");
    label.className = "field-label";
    label.htmlFor = control.id;
    label.textContent = getFieldLabelText(control);
    const shouldHideHelp = Boolean(control.closest(".form-clean-placeholders"));
    control.parentNode.insertBefore(wrapper, control);
    wrapper.appendChild(label);
    if (!shouldHideHelp) {
      const help = document.createElement("div");
      help.className = "field-help";
      help.textContent = getFieldHelpText(control);
      wrapper.appendChild(help);
    }
    wrapper.appendChild(control);
  });
}

function pretty(value) {
  return JSON.stringify(value, null, 2);
}

function getOutputTypeLabel(value) {
  if (Array.isArray(value)) {
    return "列表";
  }
  if (value && typeof value === "object") {
    return "对象";
  }
  return "文本";
}

function buildOutputPreview(value, rawText) {
  const safeText = String(rawText || "");
  const lineCount = safeText ? safeText.split("\n").length : 0;
  const charCount = safeText.length;
  const typeLabel = getOutputTypeLabel(value);
  const previewLines = [];

  if (Array.isArray(value)) {
    previewLines.push(`共 ${value.length} 条${typeLabel}数据`);
    if (value.length) {
      const first = value[0];
      if (first && typeof first === "object") {
        const keys = Object.keys(first).slice(0, 5);
        if (keys.length) {
          previewLines.push(`首条字段：${keys.join(" / ")}`);
        }
      }
    }
  } else if (value && typeof value === "object") {
    const keys = Object.keys(value);
    previewLines.push(`共 ${keys.length} 个字段`);
    if (keys.length) {
      previewLines.push(`字段预览：${keys.slice(0, 6).join(" / ")}`);
    }
  } else if (safeText) {
    previewLines.push(safeText.slice(0, 180));
  }

  previewLines.push(`原始内容较大，已自动压缩显示（${charCount} 字符 / ${lineCount} 行）。`);
  return previewLines.filter(Boolean).join("\n");
}

