function formatBilingualLabel(englishLabel = "", chineseLabel = "") {
  const en = String(englishLabel || "").trim();
  const zh = String(chineseLabel || "").trim();
  if (!en) {
    return zh;
  }
  if (!zh || zh.toLowerCase() === en.toLowerCase()) {
    return en;
  }
  return `${en} / ${zh}`;
}

function getSupplierDisplayLabel(supplierName = "", { bilingual = false, includeCode = false } = {}) {
  const row = getSupplierDirectoryRowByName(supplierName);
  const englishLabel = String(row?.name || supplierName || "").trim();
  const chineseLabel = String(row?.name_zh || "").trim();
  const mainLabel = bilingual ? formatBilingualLabel(englishLabel, chineseLabel) : englishLabel;
  const codeLabel = String(row?.code || "").trim();
  return includeCode && codeLabel ? `${mainLabel} · ${codeLabel}` : mainLabel;
}

