function buildBaleSalesRebaleNo() {
  const today = getLocalDateKey(new Date().toISOString()).replaceAll("-", "");
  const nextIndex = ensureBaleSalesRebaleEntryState().filter((row) => String(row?.rebale_entry_no || "").includes(today)).length + 1;
  return `RBS-${today}-${String(nextIndex).padStart(3, "0")}`;
}

function normalizeBaleSalesRebaleEntries(rows = []) {
  return (Array.isArray(rows) ? rows : [])
    .map((row) => ({
      rebale_entry_no: String(row?.rebale_entry_no || "").trim().toUpperCase(),
      bale_barcode: String(row?.bale_barcode || "").trim().toUpperCase(),
      source_task_no: String(row?.source_task_no || "").trim().toUpperCase(),
      source_order_no: String(row?.source_order_no || "").trim().toUpperCase(),
      supplier_name: String(row?.supplier_name || "").trim(),
      category_main: String(row?.category_main || "").trim(),
      category_sub: String(row?.category_sub || "").trim(),
      weight_kg: roundToTwo(Number(row?.weight_kg || 0)),
      bale_count: Math.max(1, Number(row?.bale_count || 1) || 1),
      status: String(row?.status || "in_pool").trim().toLowerCase(),
      note: String(row?.note || "").trim(),
      created_at: String(row?.created_at || "").trim(),
      updated_at: String(row?.updated_at || row?.created_at || "").trim(),
      entered_bale_sales_pool_at: String(row?.entered_bale_sales_pool_at || row?.created_at || "").trim(),
    }))
    .filter((row) => row.rebale_entry_no && row.bale_barcode)
    .sort((left, right) => new Date(right.updated_at || right.created_at || 0).getTime() - new Date(left.updated_at || left.created_at || 0).getTime());
}

