function normalizeOpsDataTopics(rows = []) {
  const defaults = [...DEFAULT_OPS_DATA_TOPICS];
  const merged = defaults.map((row) => ({ ...row }));
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const topicCode = String(row?.topic_code || "").trim();
    if (!topicCode) {
      return;
    }
    const index = merged.findIndex((item) => item.topic_code === topicCode);
    const normalized = {
      topic_code: topicCode,
      topic_name: String(row?.topic_name || merged[index]?.topic_name || topicCode).trim(),
      source_system: String(row?.source_system || "").trim(),
      update_frequency: String(row?.update_frequency || "").trim(),
      use_case: String(row?.use_case || merged[index]?.use_case || "").trim(),
      owner_role: String(row?.owner_role || "").trim(),
      status: String(row?.status || "not_started").trim(),
      blocker: String(row?.blocker || "").trim(),
      next_action: String(row?.next_action || "").trim(),
      last_checked_at: String(row?.last_checked_at || "").trim(),
    };
    if (index >= 0) {
      merged[index] = { ...merged[index], ...normalized };
    } else {
      merged.push(normalized);
    }
  });
  return merged;
}

