function normalizeOaPayrollBatches(rows = []) {
  return (Array.isArray(rows) ? rows : [])
    .map((row) => {
      const basePayTotal = roundToTwo(Number(row?.base_pay_total || 0));
      const commissionTotal = roundToTwo(Number(row?.commission_total || 0));
      const allowanceTotal = roundToTwo(Number(row?.allowance_total || 0));
      const deductionTotal = roundToTwo(Number(row?.deduction_total || 0));
      const grossPayTotal = roundToTwo(basePayTotal + commissionTotal + allowanceTotal);
      const netPayTotal = roundToTwo(grossPayTotal - deductionTotal);
      return {
        payroll_no: String(row?.payroll_no || "").trim().toUpperCase(),
        payroll_month: String(row?.payroll_month || "").trim(),
        store_scope: String(row?.store_scope || "").trim().toUpperCase(),
        headcount: Number(row?.headcount || 0),
        base_pay_total: basePayTotal,
        commission_total: commissionTotal,
        allowance_total: allowanceTotal,
        deduction_total: deductionTotal,
        gross_pay_total: grossPayTotal,
        net_pay_total: netPayTotal,
        status: String(row?.status || "draft").trim(),
        prepared_by: String(row?.prepared_by || "").trim(),
        created_at: String(row?.created_at || "").trim(),
        updated_at: String(row?.updated_at || row?.created_at || "").trim(),
        released_at: String(row?.released_at || "").trim(),
      };
    })
    .filter((row) => row.payroll_no && row.payroll_month)
    .sort((left, right) => new Date(right.updated_at || right.created_at || 0).getTime() - new Date(left.updated_at || left.created_at || 0).getTime());
}

