function normalizeApparelPieceWeightRows(rows = []) {
  const seen = new Set();
  return (Array.isArray(rows) ? rows : [])
    .map((row) => ({
      category_main: String(row?.category_main || "").trim(),
      category_sub: String(row?.category_sub || "").trim(),
      standard_weight_kg: roundToTwo(Number(row?.standard_weight_kg || 0)),
      note: String(row?.note || "").trim(),
    }))
    .filter((row) => row.category_main && row.category_sub && row.standard_weight_kg > 0)
    .filter((row) => {
      const key = `${row.category_main.toLowerCase()}||${row.category_sub.toLowerCase()}`;
      if (seen.has(key)) {
        return false;
      }
      seen.add(key);
      return true;
    })
    .sort((left, right) => {
      const leftKey = `${left.category_main}/${left.category_sub}`;
      const rightKey = `${right.category_main}/${right.category_sub}`;
      return leftKey.localeCompare(rightKey, "zh-CN");
    });
}

