function roundToTwo(value) {
  return Number(Number(value || 0).toFixed(2));
}

function getSalesFxRatesToKes() {
  return SALES_FX_RATES_TO_KES;
}

function convertAmountToKes(amount = 0, currency = "") {
  const normalizedCurrency = String(currency || "").trim().toUpperCase();
  const numericAmount = Number(amount || 0);
  const rate = getSalesFxRatesToKes()[normalizedCurrency];
  if (!(numericAmount > 0) || !(rate > 0)) {
    return 0;
  }
  return roundToTwo(numericAmount * rate);
}

function formatKesAmount(amount = 0, fallback = "待补录") {
  return Number(amount || 0) > 0 ? `KES ${formatCurrency(amount)}` : fallback;
}

function formatWholeAmount(value = 0, fallback = "待补录") {
  const numeric = Number(value || 0);
  if (!(numeric > 0)) {
    return fallback;
  }
  return new Intl.NumberFormat("en-US", {
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(Math.round(numeric));
}

function buildCurrencyTotals(entries = []) {
  const totals = new Map();
  (Array.isArray(entries) ? entries : []).forEach((entry) => {
    const currency = String(entry?.currency || "").trim().toUpperCase();
    const amount = Number(entry?.amount || 0);
    if (!currency || !(amount > 0)) {
      return;
    }
    totals.set(currency, roundToTwo((totals.get(currency) || 0) + amount));
  });
  return [...totals.entries()].map(([currency, amount]) => ({ currency, amount }));
}

function mergeCurrencyTotals(...groups) {
  return buildCurrencyTotals(
    groups.flatMap((group) => (Array.isArray(group) ? group : []))
      .map((entry) => ({ currency: entry.currency, amount: entry.amount })),
  );
}

function formatCurrencyTotals(entries = [], { suffix = "", fallback = "待补录" } = {}) {
  const rows = Array.isArray(entries) ? entries.filter((entry) => entry && entry.currency) : [];
  if (!rows.length) {
    return fallback;
  }
  return rows
    .map((entry) => `${entry.currency} ${formatCurrency(entry.amount)}${suffix}`)
    .join(" · ");
}

function getChinaSourceGoodsCostTotals(record) {
  const lines = Array.isArray(record?.lines) ? record.lines : [];
  return buildCurrencyTotals(
    lines.map((row) => ({
      currency: String(row?.unit_cost_currency || "").trim().toUpperCase(),
      amount: Number(row?.unit_cost_amount || 0) * Number(row?.package_count || 0),
    })),
  );
}

function getChinaSourceExtraCostTotals(record) {
  const costEntries = record?.cost_entries || {};
  return buildCurrencyTotals(
    ["head_transport", "customs_clearance", "tail_transport"].map((key) => ({
      currency: String(costEntries[key]?.currency || "").trim().toUpperCase(),
      amount: Number(costEntries[key]?.amount || 0),
    })),
  );
}

function getChinaSourceCombinedCostTotals(record) {
  return mergeCurrencyTotals(getChinaSourceGoodsCostTotals(record), getChinaSourceExtraCostTotals(record));
}

function sumCurrencyTotalsToKes(entries = []) {
  return roundToTwo(
    (Array.isArray(entries) ? entries : []).reduce(
      (sum, entry) => sum + convertAmountToKes(entry?.amount || 0, entry?.currency || ""),
      0,
    ),
  );
}

function getCurrencyAmount(entries = [], currency = "") {
  const normalizedCurrency = String(currency || "").trim().toUpperCase();
  if (!normalizedCurrency) {
    return 0;
  }
  return roundToTwo(
    (Array.isArray(entries) ? entries : []).reduce((sum, entry) => {
      return String(entry?.currency || "").trim().toUpperCase() === normalizedCurrency
        ? sum + Number(entry?.amount || 0)
        : sum;
    }, 0),
  );
}

function getChinaSourceGoodsCostKes(record) {
  return sumCurrencyTotalsToKes(getChinaSourceGoodsCostTotals(record));
}

function getChinaSourceExtraCostKes(record) {
  return sumCurrencyTotalsToKes(getChinaSourceExtraCostTotals(record));
}

function getChinaSourceCombinedCostKes(record) {
  return sumCurrencyTotalsToKes(getChinaSourceCombinedCostTotals(record));
}

function getChinaSourceCostPerKgKes(record) {
  const totalWeight = Number(record?.domestic_total_weight_kg || 0);
  if (!(totalWeight > 0)) {
    return 0;
  }
  return roundToTwo(getChinaSourceCombinedCostKes(record) / totalWeight);
}

function getChinaSourceCostPerKgTotals(record) {
  const totalWeight = Number(record?.domestic_total_weight_kg || 0);
  if (!(totalWeight > 0)) {
    return [];
  }
  return getChinaSourceCombinedCostTotals(record).map((entry) => ({
    currency: entry.currency,
    amount: roundToTwo(entry.amount / totalWeight),
  }));
}

function getChinaSourceFinanceCompletion(record) {
  const costEntries = record?.cost_entries || {};
  const stageKeys = ["head_transport", "customs_clearance", "tail_transport"];
  const completedCount = stageKeys.filter((key) => Number(costEntries[key]?.amount || 0) > 0).length;
  const statusLabel = completedCount === 3
    ? "三段成本已补齐"
    : (completedCount > 0 ? "成本补填中" : "待补三段成本");
  return { completedCount, stageKeys, statusLabel };
}

function getInboundShipmentByCustomsNotice(customsNoticeNo = "") {
  const normalized = String(customsNoticeNo || "").trim().toUpperCase();
  if (!normalized) {
    return null;
  }
  return inboundShipmentState.find(
    (row) => String(row?.customs_notice_no || "").trim().toUpperCase() === normalized,
  ) || null;
}

function getSortingTasksForShipment(shipmentNo = "") {
  const normalized = normalizeShipmentNo(shipmentNo).toUpperCase();
  if (!normalized) {
    return [];
  }
  return sortingTaskState.filter(
    (row) => String(row?.shipment_no || "").trim().toUpperCase() === normalized,
  );
}

function getChinaSourceWorkflowMeta(record) {
  const finance = getChinaSourceFinanceCompletion(record);
  const shipment = getInboundShipmentByCustomsNotice(record?.customs_notice_no || "");
  const recorded = shipment ? getShipmentRecordedSummary(shipment.shipment_no) : null;
  const intakeStatus = String(shipment?.intake_status || "").trim().toLowerCase();
  const sortingRows = shipment ? getSortingTasksForShipment(shipment.shipment_no) : [];
  const hasOpenSortingTask = sortingRows.some((row) => String(row?.status || "").trim() === "open");

  const kenyaStatusLabel = !shipment
    ? "待肯方建主档"
    : (!recorded?.totalPackages
        ? "待肯方录实收"
        : (["confirmed", "bales_ready"].includes(intakeStatus) ? "已完成实收确认" : "已录实收待总确认"));

  const sortingStatusLabel = !shipment
    ? "未进入分拣"
    : (!sortingRows.length
        ? (["confirmed", "bales_ready"].includes(intakeStatus) ? "待创建分拣任务" : "未进入分拣")
        : (hasOpenSortingTask ? "分拣中" : "已完成分拣确认"));

  let nextAction = "中方财务先补齐头程、清关、尾程成本。";
  if (finance.completedCount >= 3) {
    if (!shipment) {
      nextAction = "肯方用这张船单创建入库主档。";
    } else if (!recorded?.totalPackages) {
      nextAction = "肯方在包裹入库页选择来源项并录实收。";
    } else if (!["confirmed", "bales_ready"].includes(intakeStatus)) {
      nextAction = "肯方在总确认页核对中方预报与本地实收。";
    } else if (!sortingRows.length) {
      nextAction = "仓库创建分拣任务，安排分拣人开始作业。";
    } else if (hasOpenSortingTask) {
      nextAction = "仓库主管确认并完成分拣，再进入件数入库。";
    } else {
      nextAction = "进入分拣确认入库，按件生成商品 barcode token。";
    }
  }

  return {
    financeStatusLabel: finance.statusLabel,
    kenyaStatusLabel,
    sortingStatusLabel,
    shipment,
    recorded,
    sortingRows,
    nextAction,
  };
}

function getChinaSourceCategoryTree() {
  const merged = Object.fromEntries(
    Object.entries(PARCEL_CATEGORY_TREE).map(([key, values]) => [key, [...values]]),
  );
  Object.entries(ensureChinaSourceCustomCategoryState()).forEach(([mainCategory, subCategories]) => {
    (Array.isArray(subCategories) ? subCategories : []).forEach((value) => {
      appendCategoryPairToTree(merged, mainCategory, value);
    });
  });
  Object.values(ensureSupplierCategoryScopeState()).forEach((supplierTree) => {
    if (!supplierTree || typeof supplierTree !== "object" || Array.isArray(supplierTree)) {
      return;
    }
    Object.entries(supplierTree).forEach(([mainCategory, subCategories]) => {
      (Array.isArray(subCategories) ? subCategories : []).forEach((value) => {
        appendCategoryPairToTree(merged, mainCategory, value);
      });
    });
  });
  ensureChinaSourceBaleState().forEach((record) => {
    (Array.isArray(record?.lines) ? record.lines : []).forEach((line) => {
      appendCategoryPairToTree(merged, line?.category_main, line?.category_sub);
    });
  });
  Object.keys(merged).forEach((mainCategory) => {
    merged[mainCategory] = [...new Set((merged[mainCategory] || []).map((value) => String(value || "").trim()).filter(Boolean))]
      .sort((left, right) => String(left).localeCompare(String(right), "zh-CN"));
  });
  return merged;
}

function categoryMainOptionsHtml(selectedValue = "", { includeNew = false, supplierName = "" } = {}) {
  const hasSupplierScope = Boolean(String(supplierName || "").trim());
  const categoryTree = hasSupplierScope ? getSupplierScopedCategoryTree(supplierName) : getChinaSourceCategoryTree();
  const options = [
    `<option value="">${hasSupplierScope ? "请选择当前供应商的大类" : "请选择商品大类"}</option>`,
  ].concat(
    Object.keys(categoryTree).map(
      (key) => `<option value="${escapeHtml(key)}"${key === selectedValue ? " selected" : ""}>${escapeHtml(key)}</option>`,
    ),
  );
  if (includeNew && hasSupplierScope) {
    options.push(`<option value="__new__"${selectedValue === "__new__" ? " selected" : ""}>+ 给当前供应商新建品类</option>`);
  }
  return options.join("");
}

function categorySubOptionsHtml(mainCategory = "", selectedValue = "", { supplierName = "" } = {}) {
  const hasSupplierScope = Boolean(String(supplierName || "").trim());
  const categoryTree = hasSupplierScope ? getSupplierScopedCategoryTree(supplierName) : getChinaSourceCategoryTree();
  const placeholder = !mainCategory || mainCategory === "__new__"
    ? (hasSupplierScope ? "请先选择当前供应商的大类" : "请选择商品小类")
    : "请选择商品小类";
  const options = [`<option value="">${placeholder}</option>`];
  (categoryTree[mainCategory] || []).forEach((value) => {
    options.push(`<option value="${escapeHtml(value)}"${value === selectedValue ? " selected" : ""}>${escapeHtml(value)}</option>`);
  });
  return options.join("");
}

function renderProductCategoryScopeSummary(message = "") {
  const target = document.querySelector("#productCategoryScopeSummary");
  const form = document.querySelector("#productForm");
  if (!(target instanceof HTMLElement) || !(form instanceof HTMLFormElement)) {
    return;
  }
  const supplierName = String(form.querySelector("[name='supplier_name']")?.value || "").trim();
  if (!supplierName || supplierName === "__new__") {
    target.className = "candidate-summary empty-state";
    target.textContent = "先锁供应商。这里会显示当前供应商可用的大类 / 小类，并支持直接编辑。";
    return;
  }
  const rows = getSupplierScopedCategoryRows(supplierName);
  const mainCount = new Set(rows.map((row) => row.category_main)).size;
  const supplierLabel = getSupplierDisplayLabel(supplierName, { bilingual: true });
  const summaryMessage = message || `${supplierLabel} 当前可用 ${mainCount} 个大类、${rows.length} 个小类。切换供应商后会切到另一套品类树。`;
  target.className = "report-summary";
  target.innerHTML = `
    <div class="alert-banner">${escapeHtml(summaryMessage)}</div>
    <div class="report-summary-grid">
      <article class="store-metric"><strong>已锁供应商</strong><span>${escapeHtml(supplierLabel)}</span></article>
      <article class="store-metric"><strong>当前大类数</strong><span>${mainCount}</span></article>
      <article class="store-metric"><strong>当前小类数</strong><span>${rows.length}</span></article>
      <article class="store-metric"><strong>编辑方式</strong><span>先选供应商，再编辑该供应商自己的品类</span></article>
    </div>
  `;
}

function renderProductCategoryScopeList() {
  const target = document.querySelector("#productCategoryScopeList");
  const form = document.querySelector("#productForm");
  if (!(target instanceof HTMLElement) || !(form instanceof HTMLFormElement)) {
    return;
  }
  const supplierName = String(form.querySelector("[name='supplier_name']")?.value || "").trim();
  if (!supplierName || supplierName === "__new__") {
    target.className = "candidate-summary empty-state";
    target.textContent = "当前还没有选择供应商，无法显示这个供应商的品类范围。";
    return;
  }
  const rows = getSupplierScopedCategoryRows(supplierName);
  if (!rows.length) {
    target.className = "candidate-summary empty-state";
    target.textContent = `${getSupplierDisplayLabel(supplierName, { bilingual: true })} 还没有可用品类。请在上方直接给这个供应商新增大类 / 小类。`;
    return;
  }
  const grouped = rows.reduce((accumulator, row) => {
    const bucket = accumulator[row.category_main] || [];
    bucket.push(row);
    accumulator[row.category_main] = bucket;
    return accumulator;
  }, {});
  target.className = "category-library-grid";
  target.innerHTML = Object.entries(grouped)
    .sort(([left], [right]) => String(left).localeCompare(String(right), "zh-CN"))
    .map(([categoryMain, subRows]) => `
      <article class="category-library-card">
        <div class="category-library-head">
          <strong>${escapeHtml(getCategoryMainDisplayLabel(categoryMain, { supplierName, bilingual: true }))}</strong>
          <span>${subRows.length} 个小类</span>
        </div>
        <div class="category-library-sub-list">
          ${subRows
            .map((row) => `
              <div class="category-library-sub-item">
                <div class="category-library-sub-text">
                  <span>${escapeHtml(getCategorySubDisplayLabel(row.category_main, row.category_sub, { supplierName, bilingual: true }))}</span>
                  <em>${row.source === "source" ? "来源于中方记录" : "当前供应商自定义"}</em>
                </div>
                ${
                  row.source === "custom"
                    ? `<div class="button-row">
                        <button type="button" class="ghost-button mini-button" data-product-category-edit="${escapeHtml(row.key)}">编辑</button>
                        <button type="button" class="ghost-button mini-button" data-product-category-remove="${escapeHtml(row.key)}">删除</button>
                      </div>`
                    : `<div class="subtle small">这条来自中方来源记录，如需修改请回上游来源数据。</div>`
                }
              </div>
            `)
            .join("")}
        </div>
      </article>
    `)
    .join("");
}

function refreshProductCategoryControls({ selectedMain = "", selectedSub = "", notice = "" } = {}) {
  const form = document.querySelector("#productForm");
  if (!(form instanceof HTMLFormElement)) {
    return;
  }
  const supplierName = String(form.querySelector("[name='supplier_name']")?.value || "").trim();
  const mainSelect = form.querySelector("[data-product-category-main]");
  const subSelect = form.querySelector("[data-product-category-sub]");
  const inlinePanel = document.querySelector("#productCategoryInline");
  if (!(mainSelect instanceof HTMLSelectElement) || !(subSelect instanceof HTMLSelectElement)) {
    return;
  }
  if (!supplierName || supplierName === "__new__") {
    mainSelect.innerHTML = '<option value="">请先选择供应商</option>';
    subSelect.innerHTML = '<option value="">请先选择商品大类</option>';
    if (inlinePanel instanceof HTMLElement) {
      inlinePanel.classList.add("hidden-screen");
    }
    renderProductCategoryScopeSummary();
    renderProductCategoryScopeList();
    return;
  }
  const categoryTree = getSupplierScopedCategoryTree(supplierName);
  const fallbackMain = selectedMain || mainSelect.value || "";
  const validMain = fallbackMain === "__new__" || Object.prototype.hasOwnProperty.call(categoryTree, fallbackMain) ? fallbackMain : "";
  mainSelect.innerHTML = categoryMainOptionsHtml(validMain, { includeNew: true, supplierName, bilingual: true });
  mainSelect.value = validMain || "";

  const fallbackSub = selectedSub || subSelect.value || "";
  const validSub = validMain && validMain !== "__new__" && (categoryTree[validMain] || []).includes(fallbackSub) ? fallbackSub : "";
  subSelect.innerHTML = categorySubOptionsHtml(validMain, validSub, { supplierName, bilingual: true });
  subSelect.value = validSub || "";

  if (inlinePanel instanceof HTMLElement) {
    inlinePanel.classList.toggle("hidden-screen", validMain !== "__new__");
  }
  renderProductCategoryScopeSummary(notice);
  renderProductCategoryScopeList();
}

function prefillProductCategoryInlineEditor({
  supplierName = "",
  categoryMain = "",
  categorySub = "",
  categoryMainZh = "",
  categorySubZh = "",
  editingKey = "",
} = {}) {
  const panel = document.querySelector("#productCategoryInline");
  const form = document.querySelector("#productForm");
  if (!(panel instanceof HTMLElement) || !(form instanceof HTMLFormElement)) {
    return;
  }
  if (!supplierName || supplierName === "__new__") {
    panel.classList.add("hidden-screen");
    return;
  }
  form.querySelector("[name='product_category_main_new']").value = categoryMain;
  form.querySelector("[name='product_category_sub_new']").value = categorySub;
  form.querySelector("[name='product_category_main_zh_new']").value = categoryMainZh;
  form.querySelector("[name='product_category_sub_zh_new']").value = categorySubZh;
  form.querySelector("[name='product_category_editing_key']").value = editingKey;
  panel.classList.remove("hidden-screen");
}

function getApparelPieceWeightByCategory(mainCategory = "", subCategory = "") {
  const normalizedMain = String(mainCategory || "").trim().toLowerCase();
  const normalizedSub = String(subCategory || "").trim().toLowerCase();
  if (!normalizedMain || !normalizedSub) {
    return null;
  }
  return ensureApparelPieceWeightState().find(
    (row) =>
      String(row?.category_main || "").trim().toLowerCase() === normalizedMain
      && String(row?.category_sub || "").trim().toLowerCase() === normalizedSub,
  ) || null;
}

function parseCategoryPair(categoryName = "") {
  const parts = String(categoryName || "")
    .split("/")
    .map((part) => part.trim())
    .filter(Boolean);
  return {
    category_main: parts[0] || "",
    category_sub: parts[1] || "",
  };
}

function getStandardPieceWeightKgForCategory(categoryName = "") {
  const pair = parseCategoryPair(categoryName);
  const matched = getApparelPieceWeightByCategory(pair.category_main, pair.category_sub);
  return matched ? Number(matched.standard_weight_kg || 0) : 0;
}

function getApparelDefaultCostByCategoryGrade(mainCategory = "", subCategory = "", grade = "") {
  const finder = apparelDefaultCostFlow.findApparelDefaultCostRecord;
  if (typeof finder === "function") {
    return finder(ensureApparelDefaultCostState(), mainCategory, subCategory, grade);
  }
  const normalizedMain = String(mainCategory || "").trim().toLowerCase();
  const normalizedSub = String(subCategory || "").trim().toLowerCase();
  const normalizedGrade = String(grade || "").trim().toUpperCase();
  return ensureApparelDefaultCostState().find(
    (row) =>
      String(row?.category_main || "").trim().toLowerCase() === normalizedMain
      && String(row?.category_sub || "").trim().toLowerCase() === normalizedSub
      && String(row?.grade || "").trim().toUpperCase() === normalizedGrade,
  ) || null;
}

function getApparelSortingRackByCategoryGradeCost(mainCategory = "", subCategory = "", grade = "", defaultCostKes = 0) {
  const finder = apparelSortingRackFlow.findApparelSortingRackRecord;
  if (typeof finder === "function") {
    return finder(ensureApparelSortingRackState(), mainCategory, subCategory, grade, defaultCostKes);
  }
  const normalizedMain = String(mainCategory || "").trim().toLowerCase();
  const normalizedSub = String(subCategory || "").trim().toLowerCase();
  const normalizedGrade = String(grade || "").trim().toUpperCase();
  const normalizedCost = roundToTwo(Number(defaultCostKes || 0));
  return ensureApparelSortingRackState().find(
    (row) =>
      String(row?.category_main || "").trim().toLowerCase() === normalizedMain
      && String(row?.category_sub || "").trim().toLowerCase() === normalizedSub
      && String(row?.grade || "").trim().toUpperCase() === normalizedGrade
      && roundToTwo(Number(row?.default_cost_kes || 0)) === normalizedCost,
  ) || null;
}

function buildSortingResultCategoryName(categoryMain = "", categorySub = "") {
  const builder = sortingResultFlow.buildSortingResultCategoryName;
  if (typeof builder === "function") {
    return builder(categoryMain, categorySub);
  }
  const main = String(categoryMain || "").trim();
  const sub = String(categorySub || "").trim();
  return main && sub ? `${main} / ${sub}` : (main || sub);
}

function inflateSortingResultBuilderRows(value) {
  const inflator = sortingResultFlow.inflateSortingResultRows;
  if (typeof inflator === "function") {
    return inflator(value);
  }
  return Array.isArray(value)
    ? value.map((row) => {
      const pair = parseCategoryPair(row?.category_name || "");
      return {
        category_main: pair.category_main,
        category_sub: pair.category_sub,
        grade: String(row?.grade || "").trim().toUpperCase() || "P",
        actual_weight_kg: Number(row?.actual_weight_kg || row?.weight_kg || row?.estimated_total_weight_kg || 0) || "",
        qty: Number(row?.qty || 1),
        rack_code: row?.rack_code || "",
        default_cost_kes: Number(row?.default_cost_kes || 0) || "",
        confirm_to_inventory: String(row?.confirm_to_inventory) === "false" ? "false" : "true",
      };
    })
    : [];
}

function buildSortingResultOutputRows(rows = []) {
  const serializer = sortingResultFlow.buildSortingResultOutputRows;
  if (typeof serializer === "function") {
    return serializer(rows, {
      defaultCosts: ensureApparelDefaultCostState(),
      defaultRacks: ensureApparelSortingRackState(),
    });
  }
  return (Array.isArray(rows) ? rows : []).map((row) => {
    const categoryMain = row?.category_main || "";
    const categorySub = row?.category_sub || "";
    const grade = String(row?.grade || "").trim().toUpperCase() || "P";
    const matchedCost = getApparelDefaultCostByCategoryGrade(categoryMain, categorySub, grade);
    const matchedCostValue = matchedCost?.default_cost_kes;
    const defaultCostKes = Number(matchedCostValue || 0) > 0
      ? Number(matchedCostValue || 0)
      : (Number(row?.default_cost_kes || 0) || null);
    const matchedRack = defaultCostKes
      ? getApparelSortingRackByCategoryGradeCost(categoryMain, categorySub, grade, defaultCostKes)
      : null;
    return {
      category_name: buildSortingResultCategoryName(categoryMain, categorySub),
      grade,
      actual_weight_kg: Number(row?.actual_weight_kg || 0) || null,
      qty: Number(row?.qty || 0),
      rack_code: matchedRack?.rack_code || row?.rack_code || "",
      default_cost_kes: defaultCostKes,
      confirm_to_inventory: String(row?.confirm_to_inventory) !== "false",
    };
  });
}

function getSortingResultCategoryMainOptions() {
  return Object.keys(getChinaSourceCategoryTree()).map((mainCategory) => ({
    value: mainCategory,
    label: mainCategory,
  }));
}

function getSortingResultCategorySubOptions(categoryMain = "") {
  const categoryTree = getChinaSourceCategoryTree();
  const options = [{ value: "", label: "请选择商品小类" }];
  (categoryTree[String(categoryMain || "").trim()] || []).forEach((subCategory) => {
    options.push({ value: subCategory, label: subCategory });
  });
  return options;
}

function getSortingResultDefaultCostDisplay(row = {}) {
  const resolver = sortingResultFlow.resolveSortingResultDefaultCost;
  const matched = typeof resolver === "function"
    ? resolver(ensureApparelDefaultCostState(), row)
    : getApparelDefaultCostByCategoryGrade(row?.category_main || "", row?.category_sub || "", row?.grade || "");
  const value = matched?.default_cost_kes ?? Number(row?.default_cost_kes || 0);
  return value > 0 ? formatKesAmount(value, "KES 0.00") : "待配置";
}

function getSortingResultDefaultCostValue(row = {}) {
  const resolver = sortingResultFlow.resolveSortingResultDefaultCost;
  const matched = typeof resolver === "function"
    ? resolver(ensureApparelDefaultCostState(), row)
    : getApparelDefaultCostByCategoryGrade(row?.category_main || "", row?.category_sub || "", row?.grade || "");
  const matchedValue = matched?.default_cost_kes;
  if (Number(matchedValue || 0) > 0) {
    return Number(matchedValue || 0);
  }
  return Number(row?.default_cost_kes || 0) || 0;
}

function getSortingResultCostEstimateForRow(rowIndex = 0) {
  const taskNo = String(document.querySelector("#sortingResultForm [name='task_no']")?.value || "").trim();
  const task = getSortingTaskByNo(taskNo);
  if (!task) {
    return null;
  }
  const currentRows = normalizeBuilderRows("sorting-result-items", jsonBuilderState["sorting-result-items"] || []);
  const costMeta = getSortingTaskFormalCostPayload(task, buildSortingResultOutputRows(currentRows), getSortingLossRecordFromDom());
  return (costMeta.row_estimates || []).find((entry) => Number(entry.row_index) === Number(rowIndex)) || null;
}

function getSortingResultUnitCostDisplay(row = {}, rowIndex = 0) {
  const rowEstimate = getSortingResultCostEstimateForRow(rowIndex);
  const value = rowEstimate?.estimated_unit_cost_kes;
  if (Number(value || 0) > 0) {
    return formatKesAmount(value, "KES 0.00");
  }
  if (!row?.category_main || !row?.category_sub || !(Number(row?.qty || 0) > 0)) {
    return "待选择";
  }
  return "待分摊";
}

function refreshSortingResultCostDisplays() {
  const rows = normalizeBuilderRows("sorting-result-items", jsonBuilderState["sorting-result-items"] || []);
  rows.forEach((row, rowIndex) => {
    const unitCostInput = document.querySelector(
      `[data-builder-input="sorting-result-items"][data-row-index="${rowIndex}"][data-field-key="unit_cost_display"]`,
    );
    if (unitCostInput instanceof HTMLInputElement) {
      unitCostInput.value = getSortingResultUnitCostDisplay(row, rowIndex);
    }
    const metaTarget = document.querySelector(
      `[data-builder-row-meta="sorting-result-items"][data-row-index="${rowIndex}"]`,
    );
    if (metaTarget instanceof HTMLElement) {
      metaTarget.innerHTML = renderSortingResultRowCostHint(row, rowIndex);
    }
  });
}

function getSortingResultDefaultRackDisplay(row = {}) {
  const defaultCostKes = getSortingResultDefaultCostValue(row);
  const resolver = sortingResultFlow.resolveSortingResultDefaultRack;
  const matched = typeof resolver === "function"
    ? resolver(ensureApparelSortingRackState(), { ...row, default_cost_kes: defaultCostKes })
    : getApparelSortingRackByCategoryGradeCost(
      row?.category_main || "",
      row?.category_sub || "",
      row?.grade || "",
      defaultCostKes,
    );
  return matched?.rack_code || String(row?.rack_code || "").trim().toUpperCase() || "待配置";
}

