function emptyProductImportRow() {
  return {
    row_no: productImportPreviewState.length + 1,
    supplier_name: "",
    category_main: "",
    category_sub: "",
    product_name: "",
    valid: false,
    issues: [],
  };
}

function productImportSupplierOptionsHtml(selectedValue = "") {
  const options = ['<option value="">请选择供应商</option>'];
  const names = supplierDirectoryState.map((row) => row.name);
  if (selectedValue && !names.includes(selectedValue)) {
    options.push(`<option value="${escapeHtml(selectedValue)}" selected>${escapeHtml(selectedValue)}</option>`);
  }
  options.push(
    ...supplierDirectoryState.map(
      (row) =>
        `<option value="${escapeHtml(row.name)}"${row.name === selectedValue ? " selected" : ""}>${escapeHtml(getSupplierDisplayLabel(row.name, { bilingual: true, includeCode: true }))}</option>`,
    ),
  );
  return options.join("");
}

function productImportCategoryMainOptionsHtml(selectedValue = "", supplierName = "") {
  const supplierKey = String(supplierName || "").trim();
  const categoryTree = supplierKey ? getSupplierScopedCategoryTree(supplierKey) : {};
  const categoryMains = Object.keys(categoryTree);
  const options = [`<option value="">${supplierKey ? "请选择当前供应商的大类" : "请先选择供应商"}</option>`];
  if (selectedValue && !categoryMains.includes(selectedValue)) {
    options.push(`<option value="${escapeHtml(selectedValue)}" selected>${escapeHtml(selectedValue)}</option>`);
  }
  options.push(
    ...categoryMains.map(
      (key) => `<option value="${escapeHtml(key)}"${key === selectedValue ? " selected" : ""}>${escapeHtml(getCategoryMainDisplayLabel(key, { supplierName, bilingual: true }))}</option>`,
    ),
  );
  return options.join("");
}

function productImportCategorySubOptionsHtml(mainCategory = "", selectedValue = "", supplierName = "") {
  const supplierKey = String(supplierName || "").trim();
  const categoryTree = supplierKey ? getSupplierScopedCategoryTree(supplierKey) : {};
  const placeholder = supplierKey
    ? (mainCategory ? "请选择商品小类" : "请先选择商品大类")
    : "请先选择供应商";
  const options = [`<option value="">${placeholder}</option>`];
  const categorySubs = categoryTree[mainCategory] || [];
  if (selectedValue && !categorySubs.includes(selectedValue) && canAttachSubCategoryToMain(mainCategory, selectedValue)) {
    options.push(`<option value="${escapeHtml(selectedValue)}" selected>${escapeHtml(selectedValue)}</option>`);
  }
  categorySubs.forEach((value) => {
    options.push(`<option value="${escapeHtml(value)}"${value === selectedValue ? " selected" : ""}>${escapeHtml(getCategorySubDisplayLabel(mainCategory, value, { supplierName, bilingual: true }))}</option>`);
  });
  return options.join("");
}

function syncProductImportRowsFromDom() {
  const rows = [...document.querySelectorAll("#productImportRowsBuilder [data-product-import-row]")].map((rowNode, index) => {
    const supplierName = String(rowNode.querySelector("[data-product-import-field='supplier_name']")?.value || "").trim();
    const categoryMain = String(rowNode.querySelector("[data-product-import-field='category_main']")?.value || "").trim();
    const categorySub = String(rowNode.querySelector("[data-product-import-field='category_sub']")?.value || "").trim();
    const issues = [];
    if (!supplierName) issues.push("缺少供应商");
    if (!categoryMain) issues.push("缺少商品大类");
    if (!categorySub) issues.push("缺少商品小类");
    return {
      row_no: Number(rowNode.dataset.rowNo || index + 1),
      supplier_name: supplierName,
      category_main: categoryMain,
      category_sub: categorySub,
      product_name: categorySub || categoryMain,
      valid: !issues.length,
      issues,
    };
  });
  productImportPreviewState = rows;
  return productImportPreviewState;
}

function renderProductImportPreviewSummary(result = null) {
  const target = document.querySelector("#productImportPreviewSummary");
  if (!(target instanceof HTMLElement)) {
    return;
  }
  if (!result && !productImportPreviewState.length) {
    target.className = "candidate-summary empty-state";
    target.textContent = "上传后，这里会显示识别结果；下面的识别框可以直接改，再批量创建。";
    return;
  }
  const rows = result?.rows || productImportPreviewState;
  const totalRows = rows.length;
  const validRows = rows.filter((row) => row.valid).length;
  const invalidRows = totalRows - validRows;
  target.className = "candidate-summary";
  target.innerHTML = `
    <div class="report-summary-grid">
      <article class="store-metric"><strong>识别总行数</strong><span>${totalRows}</span></article>
      <article class="store-metric"><strong>可导入</strong><span>${validRows}</span></article>
      <article class="store-metric"><strong>待修正</strong><span>${invalidRows}</span></article>
      <article class="store-metric"><strong>来源文件</strong><span>${escapeHtml(result?.file_name || "手动编辑")}</span></article>
    </div>
    <div class="subtle small">上传后可直接在下面修改供应商 / 大类 / 小类，再点击“批量创建商品”。</div>
  `;
}

function renderProductImportRows() {
  const container = document.querySelector("#productImportRowsBuilder");
  if (!(container instanceof HTMLElement)) {
    return;
  }
  const rows = productImportPreviewState.length ? productImportPreviewState : [emptyProductImportRow()];
  productImportPreviewState = rows;
  container.innerHTML = rows
    .map((row, index) => {
      const supplierName = String(row.supplier_name || "").trim();
      const categoryMain = String(row.category_main || "").trim();
      const issues = Array.isArray(row.issues) ? row.issues.filter(Boolean) : [];
      return `
        <div class="line-builder-row" data-product-import-row data-row-no="${row.row_no || index + 1}">
          <div class="line-builder-grid">
            <div class="field-stack">
              <label>供应商</label>
              <select data-product-import-field="supplier_name">
                ${productImportSupplierOptionsHtml(supplierName)}
              </select>
            </div>
            <div class="field-stack">
              <label>商品大类</label>
              <select data-product-import-field="category_main">
                ${productImportCategoryMainOptionsHtml(categoryMain, supplierName)}
              </select>
            </div>
            <div class="field-stack">
              <label>商品小类</label>
              <select data-product-import-field="category_sub">
                ${productImportCategorySubOptionsHtml(categoryMain, row.category_sub || "", supplierName)}
              </select>
            </div>
          </div>
          <div class="line-builder-meta">
            <span class="meta-pill">第 ${index + 1} 行</span>
            <span class="meta-pill">${issues.length ? `待修正 ${issues.join(" / ")}` : "可直接创建"}</span>
          </div>
          <div class="button-row">
            <button type="button" class="ghost-button mini-button" data-product-import-remove="${index}">移除这一行</button>
          </div>
        </div>
      `;
    })
    .join("");
}

function renderChinaSourceImportPreviewSummary(result = null) {
  const target = document.querySelector("#chinaSourceImportPreviewSummary");
  if (!(target instanceof HTMLElement)) {
    return;
  }
  let rows = Array.isArray(result?.rows) ? result.rows : null;
  if (!rows) {
    rows = Array.isArray(chinaSourceImportPreviewState) && chinaSourceImportPreviewState.length
      ? chinaSourceImportPreviewState
      : [];
  }
  if (!rows.length) {
    target.className = "candidate-summary empty-state";
    target.textContent = "上传后会直接写入下面的识别框；这里只保留导入状态提示。";
    return;
  }
  const totalRows = rows.length;
  const validRows = rows.filter((row) => row.valid).length;
  const invalidRows = totalRows - validRows;
  const totalPackages = rows.reduce((sum, row) => sum + Number(row.package_count || 0), 0);
  const totalWeight = rows.reduce((sum, row) => sum + (Number(row.package_count || 0) * Number(row.unit_weight_kg || 0)), 0);
  const missingSupplierRows = rows.filter((row) => Array.isArray(row.issues) && row.issues.includes("缺少供应商")).length;
  const missingCategoryRows = rows.filter((row) => Array.isArray(row.issues) && (row.issues.includes("缺少商品大类") || row.issues.includes("缺少商品小类"))).length;
  target.className = "candidate-summary compact-empty";
  target.innerHTML = invalidRows
    ? `<div class="alert-banner">已导入 ${escapeHtml(totalRows)} 行、${escapeHtml(totalPackages.toLocaleString("en-US"))} 包、${escapeHtml(formatWholeAmount(totalWeight, "0"))} KG。当前还有 ${escapeHtml(invalidRows)} 行待修正。${missingSupplierRows ? ` 其中 ${escapeHtml(missingSupplierRows)} 行缺少供应商。` : ""}${missingCategoryRows ? ` ${escapeHtml(missingCategoryRows)} 行缺少大类/小类。` : ""}</div>`
    : `<div class="success-banner">已导入 ${escapeHtml(totalRows)} 行、${escapeHtml(totalPackages.toLocaleString("en-US"))} 包、${escapeHtml(formatWholeAmount(totalWeight, "0"))} KG，请直接在下面识别框继续修改并保存。</div>`;
}

function hasMeaningfulChinaSourceContainerRows(rows = chinaSourceContainerRowState) {
  const list = Array.isArray(rows) ? rows : [];
  return list.some((row) => {
    const packageCode = String(row?.package_code || "").trim();
    const supplierName = String(row?.supplier_name || "").trim();
    const categoryMain = String(row?.category_main || "").trim();
    const categorySub = String(row?.category_sub || "").trim();
    const packageCount = Number(row?.package_count || 0);
    const unitWeight = Number(row?.unit_weight_kg || 0);
    const unitCost = Number(row?.unit_cost_amount || 0);
    return Boolean(
      packageCode
      || supplierName
      || categoryMain
      || categorySub
      || packageCount > 1
      || unitWeight > 0
      || unitCost > 0,
    );
  });
}

async function loadChinaSourceImportPreviewFromFile(file) {
  if (!file) {
    throw new Error("请先选择要上传的 Excel 或 CSV 文件。");
  }
  const payload = new FormData();
  payload.append("file", file);
  const result = await request("/china-source/import-preview", {
    method: "POST",
    body: payload,
  });
  chinaSourceImportPreviewState = Array.isArray(result?.rows)
    ? result.rows.map((row, index) => ({
      ...row,
      row_no: row.row_no || index + 1,
      issues: Array.isArray(row.issues) ? row.issues : [],
      valid: Boolean(row.valid),
    }))
    : [];
  chinaSourceContainerRowState = chinaSourceImportPreviewState.length
    ? chinaSourceImportPreviewState.map((row) => ({
      package_code: String(row.package_code || "").trim(),
      supplier_name: String(row.supplier_name || "").trim(),
      supplier_name_zh: String(row.supplier_name_zh || "").trim(),
      category_main: String(row.category_main || "").trim(),
      category_main_zh: String(row.category_main_zh || "").trim(),
      category_sub_zh: String(row.category_sub_zh || "").trim(),
      category_sub: String(row.category_sub || "").trim(),
      package_count: Number(row.package_count || 0) || 1,
      unit_weight_kg: Number(row.unit_weight_kg || 0) || "",
      unit_cost_amount: Number(row.unit_cost_amount || 0) || "",
      unit_cost_currency: String(row.unit_cost_currency || "CNY").trim() || "CNY",
    }))
    : [emptyChinaSourceContainerRow()];
  renderChinaSourceImportPreviewSummary(result);
  renderChinaSourceContainerRows();
  renderChinaSourceBalePreview();
  return result;
}

async function triggerChinaSourceImportPreview() {
  const fileInput = document.querySelector("#chinaSourceImportFile");
  if (!(fileInput instanceof HTMLInputElement) || !fileInput.files?.length) {
    throw new Error("请先选择要上传的 Excel 或 CSV 文件。");
  }
  await loadChinaSourceImportPreviewFromFile(fileInput.files[0]);
}

async function submitChinaSourceImportPreview(event) {
  event.preventDefault();
  await triggerChinaSourceImportPreview();
}

function renderProductBulkCreateSummary(rows = []) {
  const target = document.querySelector("#productResultSummary");
  if (!(target instanceof HTMLElement)) {
    return;
  }
  const list = Array.isArray(rows) ? rows : [];
  if (!list.length) {
    renderProductResultSummary(null);
    return;
  }
  const supplierCount = new Set(list.map((row) => String(row?.supplier_name || "").trim()).filter(Boolean)).size;
  const categoryCount = new Set(
    list
      .map((row) => `${String(row?.category_main || "").trim()}|||${String(row?.category_sub || "").trim()}`)
      .filter((value) => !value.startsWith("|||")),
  ).size;
  const preview = list
    .slice(0, 4)
    .map((row) => `${row.product_name || row.category_sub || "-"}（${row.supplier_name || "-"}）`)
    .join("、");
  target.className = "report-summary";
  target.innerHTML = `
    <div class="alert-banner">批量创建完成，本次共创建 ${list.length} 条商品主档。</div>
    <div class="report-summary-grid">
      <article class="store-metric"><strong>创建条数</strong><span>${list.length}</span></article>
      <article class="store-metric"><strong>涉及供应商</strong><span>${supplierCount}</span></article>
      <article class="store-metric"><strong>涉及品类</strong><span>${categoryCount}</span></article>
      <article class="store-metric"><strong>最新商品</strong><span>${escapeHtml(list[list.length - 1]?.product_name || list[list.length - 1]?.category_sub || "-")}</span></article>
    </div>
    <div class="subtle small">已创建：${escapeHtml(preview)}${list.length > 4 ? " 等" : ""}。成本和售价继续走后面的成本绑定与门店编辑流程。</div>
  `;
}

async function submitProductImportPreview(event) {
  event.preventDefault();
  const form = event.currentTarget;
  if (!(form instanceof HTMLFormElement)) {
    return;
  }
  const fileInput = form.querySelector("[name='import_file']");
  if (!(fileInput instanceof HTMLInputElement) || !fileInput.files?.length) {
    throw new Error("请先选择要上传的 Excel 或 CSV 文件。");
  }
  const payload = new FormData();
  payload.append("file", fileInput.files[0]);
  const result = await request("/products/import-preview", {
    method: "POST",
    body: payload,
  });
  productImportPreviewState = Array.isArray(result?.rows)
    ? result.rows.map((row, index) => ({
      ...row,
      row_no: row.row_no || index + 1,
      product_name: row.product_name || row.category_sub || row.category_main || "",
      issues: Array.isArray(row.issues) ? row.issues : [],
      valid: Boolean(row.valid),
    }))
    : [];
  writeOutput("#productOutput", result);
  renderProductImportPreviewSummary(result);
  renderProductImportRows();
}

async function submitProductBulkCreate() {
  const rows = syncProductImportRowsFromDom();
  if (!rows.length) {
    throw new Error("请先上传文件或在识别框里新增至少一行。");
  }
  const invalidRows = rows.filter((row) => !row.valid);
  if (invalidRows.length) {
    throw new Error(`还有 ${invalidRows.length} 行待修正，请先把供应商 / 大类 / 小类补完整。`);
  }
  const payload = {
    items: rows.map((row) => ({
      supplier_name: row.supplier_name,
      category_main: row.category_main,
      category_sub: row.category_sub,
      product_name: row.category_sub || row.category_main,
      cost_price: 0,
      launch_price: 0,
      rack_code: "",
      label_template_code: "apparel_60x40",
    })),
  };
  const result = await request("/products/bulk-create", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  rows.forEach((row) => {
    addSupplierScopedCategoryPair(row.supplier_name, row.category_main, row.category_sub);
  });
  writeOutput("#productOutput", result);
  renderProductBulkCreateSummary(result);
  refreshProductCategoryControls({
    notice: `批量创建完成，共 ${result.length} 条。后续切到单条建档时，也会复用这批供应商品类关系。`,
  });
  productImportPreviewState = [];
  const fileInput = document.querySelector("#productImportFile");
  if (fileInput instanceof HTMLInputElement) {
    fileInput.value = "";
  }
  renderProductImportPreviewSummary();
  renderProductImportRows();
  await loadDashboard();
}

