function formatBalePackagePosition(row, totalPackages = 0) {
  const serialNo = Number(row?.serial_no || 0);
  const total = Number(totalPackages || 0) || serialNo || 1;
  return `第 ${serialNo || "-"} 包 / 共 ${total} 包`;
}

function groupBalesByBatch(rows = []) {
  const groups = new Map();
  rows.forEach((row) => {
    const batchNo = String(row?.parcel_batch_no || "").trim() || "未分批次";
    if (!groups.has(batchNo)) {
      groups.set(batchNo, {
        batchNo,
        supplierName: String(row?.supplier_name || "").trim() || "未填供应商",
        categoryMain: String(row?.category_main || "").trim(),
        categorySub: String(row?.category_sub || "").trim(),
        rows: [],
      });
    }
    groups.get(batchNo).rows.push(row);
  });
  return [...groups.values()]
    .map((group) => {
      const sortedRows = [...group.rows].sort((left, right) => Number(left?.serial_no || 0) - Number(right?.serial_no || 0));
      return {
        ...group,
        rows: sortedRows,
        totalPackages: sortedRows.length,
        printedCount: sortedRows.filter((row) => row?.printed_at).length,
      };
    })
    .sort((left, right) => left.batchNo.localeCompare(right.batchNo, "zh-CN"));
}

function getBaleBatchGroupKey(group = {}) {
  return String(group.batchNo || "").trim().toUpperCase();
}

function getNextPendingBaleBatchKey(batchGroups = []) {
  const nextGroup = batchGroups.find((group) => group.rows.some((row) => !row?.printed_at)) || batchGroups[0] || null;
  return nextGroup ? getBaleBatchGroupKey(nextGroup) : "";
}

function syncBaleBatchExpansionState(batchGroups = []) {
  const validKeys = new Set(batchGroups.map((group) => getBaleBatchGroupKey(group)).filter(Boolean));
  expandedBaleBatchKeys = new Set([...expandedBaleBatchKeys].filter((key) => validKeys.has(key)));
  if (!validKeys.has(activeBaleBatchKey)) {
    activeBaleBatchKey = getNextPendingBaleBatchKey(batchGroups);
  }
  if (!expandedBaleBatchKeys.size && activeBaleBatchKey) {
    expandedBaleBatchKeys.add(activeBaleBatchKey);
  }
}

function resetBaleScannerTestState(shipmentNo = "") {
  baleScannerTestState = {
    shipmentNo: normalizeShipmentNo(shipmentNo),
    draftValue: "",
    startedAtMs: 0,
    pendingSubmitMode: "",
    lastResult: null,
    history: [],
  };
  const input = document.querySelector("#baleScannerTestInput");
  if (input instanceof HTMLInputElement) {
    input.value = "";
  }
}

function ensureBaleScannerTestState(shipmentNo = "") {
  const normalizedShipmentNo = normalizeShipmentNo(shipmentNo);
  if (baleScannerTestState.shipmentNo !== normalizedShipmentNo) {
    resetBaleScannerTestState(normalizedShipmentNo);
  }
  return baleScannerTestState;
}

function getBaleScannerSubmitLabel(mode = "") {
  const labels = {
    button: "按钮",
    enter: "回车",
    tab: "Tab",
  };
  return labels[String(mode || "").trim().toLowerCase()] || "手动";
}

function getBaleScannerResultTone(result = null) {
  return result?.status === "matched" ? "success-banner" : "alert-banner";
}

function getBaleScannerResultMessage(result = null, shipmentNo = "") {
  if (!result) {
    return "扫码枪测试不改打印状态，只验证输入、回车和识别结果。";
  }
  if (result.status === "matched") {
    return result.approximate
      ? `已识别到当前船单 ${shipmentNo} 里的最接近 bale，当前扫码疑似有丢字。`
      : `已识别当前船单 ${shipmentNo} 里的 bale，可以继续连续扫码。`;
  }
  if (result.status === "foreign_shipment") {
    return `扫码有值，但这张 bale 属于别的船单 ${result.shipmentNo || "-" }。`;
  }
  if (result.status === "not_found") {
    return `系统里没有找到 ${result.barcode || "这次扫码"} 对应的 bale。`;
  }
  return "这次没有读到条码。请确认扫码枪已经对准输入框，并检查回车/Tab 后缀设置。";
}

function focusBaleScannerTestInput() {
  const input = document.querySelector("#baleScannerTestInput");
  if (!(input instanceof HTMLInputElement)) {
    return;
  }
  ensureWorkspaceVisibleForElement(input);
  input.focus();
  input.select();
}

function renderBaleScannerTestPanel(shipmentNo = "", rows = []) {
  const state = ensureBaleScannerTestState(shipmentNo);
  const lastResult = state.lastResult;
  const recentHistory = Array.isArray(state.history) ? state.history.slice(0, 5) : [];
  const statusLabelMap = {
    matched: "本船命中",
    foreign_shipment: "别船条码",
    not_found: "系统未收录",
    empty: "未读到条码",
  };
  return `
    <section class="candidate-summary">
      <div class="${getBaleScannerResultTone(lastResult)}">${escapeHtml(getBaleScannerResultMessage(lastResult, shipmentNo))}</div>
      <form id="baleScannerTestForm" class="form-grid compact">
        <input
          id="baleScannerTestInput"
          name="barcode"
          value="${escapeHtml(state.draftValue || "")}"
          placeholder="点这里后直接扫 bale 短码或完整 bale 号"
          autocomplete="off"
          autocapitalize="off"
          spellcheck="false"
        />
        <button type="submit" data-bale-scanner-submit="true">识别本次扫码</button>
      </form>
      <div class="button-row">
        <button type="button" class="ghost-button mini-button" data-bale-scanner-focus="true">聚焦扫码框</button>
        <button type="button" class="ghost-button mini-button" data-bale-scanner-clear="true">清空输入</button>
      </div>
      <div class="subtle small">锁定船单后，先点“聚焦扫码框”，再用扫码枪扫已打出来的 bale 标签。现在支持扫短码，也兼容输入完整 bale 号。带回车的扫码枪会直接识别；带 Tab 的也支持；如果没有后缀，就扫完后点“识别本次扫码”。当前船单共 ${rows.length} 张可测。</div>
      ${
        lastResult
          ? `
            <div class="report-summary-grid">
              <article class="store-metric"><strong>最近条码</strong><span>${escapeHtml(lastResult.barcode || "-")}</span></article>
              <article class="store-metric"><strong>命中 bale</strong><span>${escapeHtml(lastResult.baleBarcode || "-")}</span></article>
              <article class="store-metric"><strong>识别结果</strong><span>${escapeHtml(statusLabelMap[lastResult.status] || lastResult.status || "-")}</span></article>
              <article class="store-metric"><strong>提交方式</strong><span>${escapeHtml(getBaleScannerSubmitLabel(lastResult.submittedBy))}</span></article>
              <article class="store-metric"><strong>录入耗时</strong><span>${escapeHtml(`${Math.max(0, Number(lastResult.durationMs || 0))} ms`)}</span></article>
              <article class="store-metric"><strong>所属船单</strong><span>${escapeHtml(lastResult.shipmentNo || shipmentNo || "-")}</span></article>
              <article class="store-metric"><strong>包位</strong><span>${escapeHtml(lastResult.serialNo ? `第 ${lastResult.serialNo} 包` : "-")}</span></article>
              <article class="store-metric"><strong>批次</strong><span>${escapeHtml(lastResult.batchNo || "-")}</span></article>
              <article class="store-metric"><strong>类别</strong><span>${escapeHtml(lastResult.categoryDisplay || "-")}</span></article>
              <article class="store-metric"><strong>供应商</strong><span>${escapeHtml(lastResult.supplierName || "-")}</span></article>
              <article class="store-metric"><strong>贴码状态</strong><span>${escapeHtml(lastResult.printed ? "已贴码" : (lastResult.status === "matched" ? "待贴码" : "-"))}</span></article>
              <article class="store-metric"><strong>识别时间</strong><span>${escapeHtml(new Date(lastResult.capturedAt || Date.now()).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" }))}</span></article>
              <article class="store-metric"><strong>当前锁定</strong><span>${escapeHtml(shipmentNo || "-")}</span></article>
            </div>
          `
          : ""
      }
      ${
        recentHistory.length
          ? `
            <div class="completed-bale-list">
              ${recentHistory
                .map((entry) => `
                  <article class="completed-bale-card">
                    <strong>${escapeHtml(entry.barcode || "-")}</strong>
                    <span>${escapeHtml(statusLabelMap[entry.status] || entry.status || "-")}</span>
                    <div class="chip-row">
                      <span class="meta-pill">${escapeHtml(getBaleScannerSubmitLabel(entry.submittedBy))}</span>
                      <span class="meta-pill">${escapeHtml(`${Math.max(0, Number(entry.durationMs || 0))} ms`)}</span>
                      <span class="meta-pill">${escapeHtml(entry.shipmentNo || shipmentNo || "-")}</span>
                    </div>
                  </article>
                `)
                .join("")}
            </div>
          `
          : ""
      }
    </section>
  `;
}

function commitBaleScannerTestScan(submittedBy = "button") {
  const shipmentNo =
    String(document.querySelector("#baleBarcodeViewForm [name='shipment_no']")?.value || "").trim()
    || resolveCurrentInboundShipmentNo();
  if (!shipmentNo) {
    throw new Error("请先锁定一张船单，再测试扫码枪。");
  }
  const rows = getBalesForShipment(shipmentNo);
  const input = document.querySelector("#baleScannerTestInput");
  const barcode = String(input instanceof HTMLInputElement ? input.value : baleScannerTestState.draftValue || "").trim();
  const endedAtMs = Date.now();
  const startedAtMs = Number(baleScannerTestState.startedAtMs || endedAtMs);
  const baseResult = balePrintFlow.getBaleScanTestResult
    ? balePrintFlow.getBaleScanTestResult({
      shipmentNo,
      barcode,
      shipmentRows: rows,
      allRows: baleBarcodeState,
    })
    : {
      status: barcode ? "not_found" : "empty",
      barcode: String(barcode || "").trim().toUpperCase(),
      baleBarcode: "",
      scanToken: "",
      shipmentNo,
      batchNo: "",
      groupKey: "",
      supplierName: "",
      categoryDisplay: "",
      serialNo: 0,
      printed: false,
    };
  const scanResult = {
    ...baseResult,
    submittedBy,
    durationMs: Math.max(0, endedAtMs - startedAtMs),
    capturedAt: new Date(endedAtMs).toISOString(),
  };
  baleScannerTestState.lastResult = scanResult;
  baleScannerTestState.history = [scanResult, ...(Array.isArray(baleScannerTestState.history) ? baleScannerTestState.history : [])].slice(0, 5);
  baleScannerTestState.draftValue = "";
  baleScannerTestState.startedAtMs = 0;
  baleScannerTestState.pendingSubmitMode = "";
  if (scanResult.status === "matched" && scanResult.groupKey) {
    activeBaleBatchKey = scanResult.groupKey;
    expandedBaleBatchKeys.add(scanResult.groupKey);
  }
  renderBaleBarcodeDirectorySummary(shipmentNo);
  requestAnimationFrame(() => focusBaleScannerTestInput());
  return scanResult;
}

function renderBaleBarcodeDirectorySummary(shipmentNo = document.querySelector("#baleBarcodeViewForm [name='shipment_no']")?.value || "") {
  const target = document.querySelector("#baleBarcodeDirectorySummary");
  const nextButton = document.querySelector("#balePrintConfirmButton");
  renderBaleShipmentLockSummary(shipmentNo);
  if (!target) {
    return;
  }
  const normalizedShipmentNo = String(shipmentNo || "").trim();
  if (!normalizedShipmentNo) {
    target.className = "candidate-summary empty-state";
    target.textContent = "先选择一张船单，这里会显示这一柜已经生成的所有 bale barcode。";
    if (nextButton instanceof HTMLButtonElement) {
      nextButton.disabled = true;
      nextButton.textContent = "确认全部贴码完成，进入分拣";
    }
    return;
  }
  const shipment = getInboundShipmentRecord(normalizedShipmentNo);
  const rows = getBalesForShipment(normalizedShipmentNo);
  const batchGroups = groupBalesByBatch(rows);
  syncBaleBatchExpansionState(batchGroups);
  const printedCount = rows.filter((row) => row.printed_at).length;
  const pendingCount = rows.length - printedCount;
  const categoryCount = batchGroups.length;
  const completedGroups = batchGroups.filter((group) => group.totalPackages > 0 && group.printedCount >= group.totalPackages);
  const pendingGroups = batchGroups.filter((group) => group.totalPackages > group.printedCount);
  const selectedTemplate = getSelectedBaleTemplate();
  if (!rows.length) {
    target.className = "candidate-summary";
    target.innerHTML = `
      <div class="flow-summary-note">${escapeHtml(normalizedShipmentNo)} 这张船单目前还没有生成 bale barcode。</div>
    `;
    if (nextButton instanceof HTMLButtonElement) {
      nextButton.disabled = true;
      nextButton.textContent = "确认全部贴码完成，进入分拣";
    }
    return;
  }
  target.className = "bale-workbench";
  target.innerHTML = `
    ${
      baleBarcodeDirectoryNotice
        ? `<div class="flow-summary-note ${baleBarcodeDirectoryNotice.type === "success" ? "success" : ""}">${escapeHtml(baleBarcodeDirectoryNotice.message)}</div>`
        : ""
    }
    <div class="bale-print-shell bale-print-shell-clean">
      <section class="bale-print-primary">
        <div class="bale-print-panel-head">
          <div>
            <span class="inbound-flow-eyebrow">待打印类别</span>
            <strong>${escapeHtml(normalizedShipmentNo)}</strong>
            <div class="subtle small">先选任意一类，再进打印窗直连打印。当前使用 ${escapeHtml(`${selectedTemplate.barcode_type || "Code128"} · ${selectedTemplate.width_mm || 60}x${selectedTemplate.height_mm || 40}`)}。</div>
          </div>
          <div class="bale-print-inline-stats">
            <span class="meta-pill">${rows.length} 包</span>
            <span class="meta-pill">${printedCount} 已贴</span>
            <span class="meta-pill">${pendingCount} 待贴</span>
            <span class="meta-pill">${categoryCount} 类</span>
          </div>
        </div>
        <div class="button-row bale-workbench-list-actions">
          <button type="button" class="ghost-button mini-button" data-bale-batch-toggle-all="true">${pendingGroups.length && pendingGroups.every((group) => expandedBaleBatchKeys.has(getBaleBatchGroupKey(group))) ? "收起全部" : "展开全部"}</button>
          <button type="button" class="ghost-button mini-button" data-bale-batch-focus-next="true">${pendingCount ? "下一类待贴" : "已全部贴完"}</button>
        </div>
        ${renderBaleScannerTestPanel(normalizedShipmentNo, rows)}
        <div class="bale-batch-list">
          ${pendingGroups.length
            ? pendingGroups
            .map((group) => {
              const groupKey = getBaleBatchGroupKey(group);
              const categoryDisplay = [group.categoryMain, group.categorySub].filter(Boolean).join(" / ") || "未填大类 / 小类";
              const pendingInBatch = group.totalPackages - group.printedCount;
              const isExpanded = expandedBaleBatchKeys.has(groupKey);
              const isActive = groupKey === activeBaleBatchKey;
              return `
                <article class="bale-batch-card ${isActive ? "is-active" : ""}">
                  <div class="bale-batch-head">
                    <div class="bale-batch-title">
                      <strong>${escapeHtml(group.supplierName)}</strong>
                      <span>${escapeHtml(categoryDisplay)}</span>
                    </div>
                    <div class="bale-batch-head-actions">
                      <div class="bale-batch-progress">${group.printedCount}/${group.totalPackages} 已贴码</div>
                      <button type="button" class="ghost-button mini-button" data-bale-batch-activate="${escapeHtml(groupKey)}">${isActive ? "当前贴这一类" : "先贴这一类"}</button>
                      <button type="button" class="ghost-button mini-button" data-bale-batch-toggle="${escapeHtml(groupKey)}">${isExpanded ? "收起" : "展开"}</button>
                    </div>
                  </div>
                  <div class="chip-row bale-batch-meta">
                    <span class="meta-pill">批次 ${escapeHtml(group.batchNo)}</span>
                    <span class="meta-pill">共 ${group.totalPackages} 包</span>
                    <span class="meta-pill">待贴 ${pendingInBatch} 包</span>
                  </div>
                  <div class="bale-batch-items ${isExpanded ? "" : "hidden-screen"}">
                    ${group.rows
                      .map(
                        (row) => `
                          <div class="bale-batch-item">
                            <div class="bale-batch-item-code">
                              <strong>${escapeHtml(row.bale_barcode || "-")}</strong>
                              <span>${escapeHtml(formatBalePackagePosition(row, group.totalPackages))}</span>
                            </div>
                            <span class="bale-status-pill ${row.printed_at ? "is-done" : "is-pending"}">${row.printed_at ? "已贴码" : "待贴码"}</span>
                          </div>
                        `,
                      )
                      .join("")}
                  </div>
                  <div class="button-row bale-batch-card-actions">
                    <button type="button" class="ghost-button mini-button" data-bale-batch-print="${escapeHtml(groupKey)}">开始打印</button>
                    <button type="button" class="ghost-button mini-button" data-bale-batch-complete="${escapeHtml(groupKey)}">确认本类已贴完</button>
                  </div>
                </article>
              `;
            })
            .join("")
            : `<div class="candidate-summary empty-state">这张船单的类别已经全部打印完成，可以直接进入分拣。</div>`}
        </div>
      </section>
      <aside class="bale-print-finished">
        <section class="printer-status-card bale-completed-panel">
          <span class="inbound-flow-eyebrow">已完成打印的类别</span>
          <strong class="bale-completed-title">${completedGroups.length ? `已完成 ${completedGroups.length} 类` : "还没有完成的类别"}</strong>
          ${
            completedGroups.length
              ? `<div class="completed-bale-list">
                  ${completedGroups
                    .map((group) => {
                      const categoryDisplay = [group.categoryMain, group.categorySub].filter(Boolean).join(" / ") || "未填大类 / 小类";
                      return `
                        <article class="completed-bale-card">
                          <strong>${escapeHtml(group.supplierName)}</strong>
                          <span>${escapeHtml(categoryDisplay)}</span>
                          <div class="chip-row">
                            <span class="meta-pill">批次 ${escapeHtml(group.batchNo)}</span>
                            <span class="meta-pill">${group.printedCount}/${group.totalPackages} 已完成</span>
                          </div>
                        </article>
                      `;
                    })
                    .join("")}
                </div>`
              : `<div class="candidate-summary empty-state">完成某一类后，它会出现在这里，方便你确认已做完的类别。</div>`
          }
        </section>
      </aside>
    </div>
  `;
  if (nextButton instanceof HTMLButtonElement) {
    nextButton.disabled = pendingCount > 0;
    nextButton.textContent = pendingCount ? "还有待贴类别，先继续贴码" : "全部类别贴码完成，进入分拣";
    nextButton.classList.toggle("hidden-screen", pendingCount > 0);
  }
}

function getQueuedBalePrintJobsForShipment(shipmentNo = "") {
  const normalizedShipmentNo = String(shipmentNo || "").trim().toUpperCase();
  return balePrinterJobState.filter((job) => {
    const matchesType = String(job.job_type || "") === "bale_barcode_label";
    const matchesStatus = String(job.status || "") === "queued";
    const matchesShipment = !normalizedShipmentNo || String(job.document_no || "").trim().toUpperCase() === normalizedShipmentNo;
    return matchesType && matchesStatus && matchesShipment;
  });
}

async function loadSystemPrinters() {
  const rows = await request("/system/printers");
  systemPrinterState = Array.isArray(rows) ? rows : [];
  syncSystemPrinterSelectOptions();
  return systemPrinterState;
}

function normalizePrinterName(name = "") {
  return String(name || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "");
}

function findSystemPrinterBySelectedName(selectedName = "") {
  const normalizedSelected = normalizePrinterName(selectedName);
  if (!normalizedSelected) {
    return null;
  }
  return (
    systemPrinterState.find((row) => normalizePrinterName(row.name || "") === normalizedSelected)
    || systemPrinterState.find((row) => normalizePrinterName(row.name || "").includes(normalizedSelected))
    || systemPrinterState.find((row) => normalizedSelected.includes(normalizePrinterName(row.name || "")))
    || null
  );
}

function normalizePrinterPageSizeToken(value = "") {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "");
}

function isTsplRawPrinter(printer = null) {
  if (!printer) {
    return false;
  }
  const fingerprint = `${printer.name || ""} ${printer.device_uri || ""}`.toLowerCase();
  return fingerprint.includes("deli") || fingerprint.includes("dl-720") || fingerprint.includes("dl720");
}

function getSelectedBaleTemplateSizeLabel(template = null) {
  const row = template || getSelectedBaleTemplate();
  return `${Math.round(Number(row?.width_mm || 60))}x${Math.round(Number(row?.height_mm || 40))}`;
}

function printerSupportsBaleTemplate(printer, template = null) {
  if (!printer) {
    return false;
  }
  if (isTsplRawPrinter(printer)) {
    return true;
  }
  const templateSize = getSelectedBaleTemplateSizeLabel(template);
  const normalizedTemplateSize = normalizePrinterPageSizeToken(templateSize);
  const sizes = Array.isArray(printer?.supported_page_sizes) ? printer.supported_page_sizes : [];
  if (!sizes.length) {
    return false;
  }
  return sizes.some((size) => {
    const normalizedSize = normalizePrinterPageSizeToken(size);
    return normalizedSize.includes(normalizedTemplateSize) || normalizedTemplateSize.includes(normalizedSize);
  });
}

function getPrinterConnectionStatusLabel(printer) {
  if (!printer) {
    return "系统未安装该打印机";
  }
  if (isTsplRawPrinter(printer)) {
    return `TSPL 直打模式 · ${printer.status_text || "以实际出纸为准"}`;
  }
  if (printer.is_ready) {
    return `CUPS 就绪 · ${printer.status_text || "可用"}`;
  }
  return `CUPS ${printer.status_text || "未知"}`;
}

function sortPrintJobsNewestFirst(rows = []) {
  const list = Array.isArray(rows) ? [...rows] : [];
  return list.sort((left, right) => {
    const leftTime = String(left?.printed_at || left?.created_at || "").trim();
    const rightTime = String(right?.printed_at || right?.created_at || "").trim();
    if (leftTime && rightTime && leftTime !== rightTime) {
      return rightTime.localeCompare(leftTime);
    }
    return Number(right?.id || 0) - Number(left?.id || 0);
  });
}

function getPrintJobStatusLabel(status = "") {
  const normalized = String(status || "").trim().toLowerCase();
  const labels = {
    queued: "排队中",
    printed: "已打印",
    failed: "失败",
  };
  return labels[normalized] || String(status || "-").trim() || "-";
}

function buildStorePrinterStatusContext(selectedPrinterName = "", relatedJobs = []) {
  const printerName = String(selectedPrinterName || "").trim();
  const matchedPrinter = findSystemPrinterBySelectedName(printerName);
  const sortedJobs = sortPrintJobsNewestFirst(relatedJobs);
  const latestJob = sortedJobs[0] || null;
  return {
    printerName: printerName || "未选择打印机",
    matchedPrinter,
    printerStatusLabel: getPrinterConnectionStatusLabel(matchedPrinter),
    installedCount: Array.isArray(systemPrinterState) ? systemPrinterState.length : 0,
    queuedCount: sortedJobs.filter((job) => String(job?.status || "").trim() === "queued").length,
    failedCount: sortedJobs.filter((job) => String(job?.status || "").trim() === "failed").length,
    printedCount: sortedJobs.filter((job) => String(job?.status || "").trim() === "printed").length,
    latestJob,
  };
}

function renderStorePrinterStatusCard({
  title = "蓝牙打印状态",
  selectedPrinterName = "",
  relatedJobs = [],
  extraMeta = [],
} = {}) {
  const context = buildStorePrinterStatusContext(selectedPrinterName, relatedJobs);
  const latestJob = context.latestJob;
  const latestLabel = latestJob
    ? `${getPrintJobStatusLabel(latestJob.status || "")} · #${latestJob.id}`
    : "暂无任务";
  return `
    <section class="printer-status-card store-printer-status">
      <div class="subtle small">${escapeHtml(title)}</div>
      <div class="printer-status-name">${escapeHtml(context.printerName)}</div>
      <div class="printer-status-flag ${context.matchedPrinter ? "is-ready" : "is-waiting"}">
        ${context.printerStatusLabel}
      </div>
      <div class="printer-status-meta">
        <div><strong>系统打印机</strong><span>${context.installedCount} 台</span></div>
        <div><strong>排队中</strong><span>${context.queuedCount}</span></div>
        <div><strong>失败任务</strong><span>${context.failedCount}</span></div>
        <div><strong>最近结果</strong><span>${escapeHtml(latestLabel)}</span></div>
        ${extraMeta
          .map((item) => `<div><strong>${escapeHtml(item.label || "-")}</strong><span>${escapeHtml(item.value || "-")}</span></div>`)
          .join("")}
      </div>
    </section>
  `;
}

function syncSystemPrinterSelectOptions() {
  const select = document.querySelector("#balePrinterConsoleForm [name='printer_name']");
  if (!(select instanceof HTMLSelectElement)) {
    return;
  }
  const currentValue = String(select.value || "").trim();
  const printers = Array.isArray(systemPrinterState) ? systemPrinterState : [];
  if (!printers.length) {
    return;
  }
  select.innerHTML = printers
    .map((printer) => {
      const name = String(printer.name || "").trim();
      const label = name.replace(/_/g, " ");
      return `<option value="${escapeHtml(name)}">${escapeHtml(label)}</option>`;
    })
    .join("");
  const currentMatch = findSystemPrinterBySelectedName(currentValue);
  if (currentMatch?.name) {
    select.value = String(currentMatch.name || "");
    return;
  }
  const deliMatch = printers.find((printer) => normalizePrinterName(printer.name || "").includes("deli"))
    || printers[0];
  if (deliMatch?.name) {
    select.value = String(deliMatch.name || "");
  }
}

function renderBalePrinterConsoleSummary(shipmentNo = document.querySelector("#balePrinterConsoleForm [name='shipment_no']")?.value || "") {
  const target = document.querySelector("#balePrinterConsoleSummary");
  if (!target) {
    return;
  }
  const normalizedShipmentNo = String(shipmentNo || "").trim();
  if (normalizedShipmentNo) {
    setCurrentInboundShipment(normalizedShipmentNo);
  }
  const selectedPrinterName = String(document.querySelector("#balePrinterConsoleForm [name='printer_name']")?.value || "Deli DL-720C").trim();
  const selectedPrinter = findSystemPrinterBySelectedName(selectedPrinterName);
  const hasInstalledPrinters = systemPrinterState.length > 0;
  const isPrinterConnected = Boolean(selectedPrinter);
  const selectedTemplate = getSelectedBaleTemplate();
  const supportsTemplate = printerSupportsBaleTemplate(selectedPrinter, selectedTemplate);
  if (!normalizedShipmentNo) {
    target.className = "candidate-summary empty-state";
    target.textContent = hasInstalledPrinters
      ? "先选择船单，这里会显示要发给条码打印机的 bale barcode 任务。"
      : "这台电脑当前没有安装任何系统打印机。请先去「系统设置 > 打印机与扫描仪」添加 Deli DL-720C。";
    return;
  }
  const queuedJobs = getQueuedBalePrintJobsForShipment(normalizedShipmentNo);
  target.className = queuedJobs.length ? "report-summary" : "candidate-summary";
  target.innerHTML = `
    ${
      balePrinterConsoleNotice
        ? `<div class="alert-banner ${balePrinterConsoleNotice.type === "success" ? "success-banner" : ""}">${escapeHtml(balePrinterConsoleNotice.message)}</div>`
        : ""
    }
    <div class="report-summary-grid">
      <article class="store-metric"><strong>船单</strong><span>${escapeHtml(normalizedShipmentNo)}</span></article>
      <article class="store-metric"><strong>打印机</strong><span>${escapeHtml(selectedPrinterName)}</span></article>
      <article class="store-metric"><strong>设备状态</strong><span>${escapeHtml(getPrinterConnectionStatusLabel(selectedPrinter))}</span></article>
      <article class="store-metric"><strong>标签尺寸</strong><span>${escapeHtml(getSelectedBaleTemplateSizeLabel(selectedTemplate))}</span></article>
      <article class="store-metric"><strong>待打任务</strong><span>${queuedJobs.length}</span></article>
      <article class="store-metric"><strong>系统打印机</strong><span>${hasInstalledPrinters ? `${systemPrinterState.length} 台` : "0 台"}</span></article>
    </div>
    ${
      hasInstalledPrinters
        ? (!isPrinterConnected
            ? `<div class="alert-banner">系统里已经有打印机，但还没有找到名为 ${escapeHtml(selectedPrinterName)} 的打印机。请检查打印机名称，或在系统设置里重新添加。</div>`
            : `${supportsTemplate
                ? `<div class="subtle small">打印机队列已安装，当前显示为 ${escapeHtml(selectedPrinter?.status_text || "就绪")}。你可以先打测试单确认是否真实出纸。</div>`
                : `<div class="alert-banner">当前系统打印机队列没有暴露 ${escapeHtml(getSelectedBaleTemplateSizeLabel(selectedTemplate))} 标签纸尺寸。现在点打印，任务可能会发出去，但打印机不一定出纸。建议先把 Deli 队列重新配置成标签机纸张。</div>`}`)
        : `<div class="alert-banner">这台 Mac 当前没有安装任何系统打印机。先去「系统设置 > 打印机与扫描仪」添加 Deli DL-720C，然后回来点“检测系统打印机”。</div>`
    }
    ${
      queuedJobs.length
        ? `
          <div class="candidate-list">
            ${queuedJobs
              .map(
                (job) => `
                  <article class="candidate-row selected-bale-row">
                    <div class="selected-bale-body">
                      <strong>${escapeHtml(job.barcode || "-")}</strong>
                      <div class="subtle small">${escapeHtml(`${job.product_name || "-"} · 打印 ${job.copies || 1} 份 · 任务 #${job.id}`)}</div>
                    </div>
                    <div class="button-row selected-bale-actions">
                      <button type="button" class="ghost-button mini-button" data-bale-printer-action="preview" data-job-id="${escapeHtml(job.id)}">系统打印</button>
                      <button type="button" class="ghost-button mini-button" data-bale-printer-action="complete" data-job-id="${escapeHtml(job.id)}">已打印</button>
                      <button type="button" class="ghost-button mini-button" data-bale-printer-action="fail" data-job-id="${escapeHtml(job.id)}">失败</button>
                    </div>
                  </article>
                `,
              )
              .join("")}
          </div>
        `
        : `<div class="empty-state">这张船单当前没有待打印的 bale barcode 任务。你可以回上一步继续选包裹并确认打印。</div>`
    }
  `;
}

async function loadBalePrinterConsole(shipmentNo = "") {
  const fallbackShipmentNo =
    String(document.querySelector("#balePrinterConsoleForm [name='shipment_no']")?.value || "").trim() ||
    String(document.querySelector("#baleBarcodeViewForm [name='shipment_no']")?.value || "").trim();
  const normalizedShipmentNo = String(shipmentNo || fallbackShipmentNo).trim();
  if (normalizedShipmentNo) {
    setInputValue("#balePrinterConsoleForm [name='shipment_no']", normalizedShipmentNo);
  }
  await loadSystemPrinters();
  const rows = await request("/print-jobs?status=queued");
  balePrinterJobState = Array.isArray(rows) ? rows : [];
  renderBalePrinterConsoleSummary(normalizedShipmentNo);
  focusElement("#balePrinterConsoleSummary");
  return balePrinterJobState;
}

function jumpToBalePrinterConsole(shipmentNo = "") {
  const normalizedShipmentNo =
    String(shipmentNo || "").trim() ||
    String(document.querySelector("#balePrinterConsoleForm [name='shipment_no']")?.value || "").trim() ||
    String(document.querySelector("#baleBarcodeViewForm [name='shipment_no']")?.value || "").trim();
  openInboundFlowStep("barcodes", normalizedShipmentNo);
}

async function reloadBaleShipmentPrintRows(shipmentNo = "") {
  const normalizedShipmentNo = String(shipmentNo || "").trim();
  if (!normalizedShipmentNo) {
    return [];
  }
  const refreshedRows = await request(`/warehouse/bale-barcodes?shipment_no=${encodeURIComponent(normalizedShipmentNo)}`);
  baleBarcodeState = [
    ...refreshedRows,
    ...baleBarcodeState.filter((row) => String(row.shipment_no || "").trim().toUpperCase() !== normalizedShipmentNo.toUpperCase()),
  ];
  return refreshedRows;
}

function renderBaleShipmentPrintProgress(shipmentNo = "") {
  const normalizedShipmentNo = String(shipmentNo || "").trim();
  if (!normalizedShipmentNo) {
    return;
  }
  renderInboundFlowContext(normalizedShipmentNo);
  renderBaleBarcodeDirectorySummary(normalizedShipmentNo);
  renderBalePrinterConsoleSummary(normalizedShipmentNo);
}

function addBaleToPrintSelectionTop(baleCode, copies = 1) {
  const normalizedCode = String(baleCode || "").trim();
  if (!normalizedCode) {
    return;
  }
  const existingCopies = selectedBalePrintMap.get(normalizedCode) || copies;
  selectedBalePrintMap = new Map([
    [normalizedCode, existingCopies],
    ...[...selectedBalePrintMap.entries()].filter(([code]) => code !== normalizedCode),
  ]);
}

function prioritizeBalesInPrintSelection(baleCodes = [], copies = 1) {
  const normalizedCodes = baleCodes
    .map((code) => String(code || "").trim())
    .filter(Boolean);
  if (!normalizedCodes.length) {
    return;
  }
  const uniquePriorityCodes = [...new Set(normalizedCodes)];
  const prioritySet = new Set(uniquePriorityCodes);
  selectedBalePrintMap = new Map([
    ...uniquePriorityCodes.map((code) => [code, selectedBalePrintMap.get(code) || copies]),
    ...[...selectedBalePrintMap.entries()].filter(([code]) => !prioritySet.has(code)),
  ]);
}

