function buildStoreClerkAssignmentView(row = {}) {
  if (typeof storeExecutionFlow.buildClerkAssignment === "function") {
    return storeExecutionFlow.buildClerkAssignment({
      baleNo: row.bale_no || "",
      storeCode: row.store_code || "",
      assignedEmployee: row.assigned_employee || "",
      flowType: row.flow_type || "sorting",
      itemCount: row.item_count || 0,
      assignedAt: row.assigned_at || "",
      note: row.assignment_note || "",
      status: row.status || "",
    });
  }
  return {
    entityType: "clerk_assignment",
    baleNo: String(row.bale_no || "").trim().toUpperCase(),
    storeCode: String(row.store_code || "").trim().toUpperCase(),
    assignedEmployee: String(row.assigned_employee || "").trim(),
    flowType: String(row.flow_type || "sorting").trim().toLowerCase() || "sorting",
    itemCount: Number(row.item_count || 0),
    assignedAt: String(row.assigned_at || "").trim(),
    note: String(row.assignment_note || "").trim(),
    status: String(row.status || "").trim(),
  };
}

function buildStoreClerkShelvingTaskView(result = {}) {
  const analysis = result.analysis_summary || {};
  if (typeof storeExecutionFlow.buildClerkShelvingTask === "function") {
    return storeExecutionFlow.buildClerkShelvingTask({
      sessionNo: result.session_no || "",
      baleNo: result.bale_no || "",
      storeCode: result.store_code || "",
      assignedEmployee: result.assigned_employee || "",
      status: result.status || "",
      tokenCount: analysis.token_count || 0,
      placedCount: analysis.placed_count || 0,
      pendingCount: analysis.pending_count || 0,
    });
  }
  return {
    entityType: "clerk_shelving_task",
    sessionNo: String(result.session_no || "").trim().toUpperCase(),
    baleNo: String(result.bale_no || "").trim().toUpperCase(),
    storeCode: String(result.store_code || "").trim().toUpperCase(),
    assignedEmployee: String(result.assigned_employee || "").trim(),
    status: String(result.status || "").trim(),
    tokenCount: Number(analysis.token_count || 0),
    placedCount: Number(analysis.placed_count || 0),
    pendingCount: Number(analysis.pending_count || 0),
  };
}

function splitCategoryLabel(categoryName = "") {
  const raw = String(categoryName || "").trim();
  const [main = "", sub = ""] = raw.split("/").map((part) => String(part || "").trim());
  return {
    main: main || raw || "-",
    sub: sub || raw || "-",
  };
}

