function buildDirectHangIdentityNo(baleNo = "", index = 1) {
  const normalized = slugifyText(baleNo).replaceAll("-", "").toUpperCase().slice(-12) || "DIRECT";
  return `DHI-${normalized}-${String(index).padStart(4, "0")}`;
}

function buildDirectHangBarcodeValue(identityNo = "") {
  const normalized = String(identityNo || "").trim().toUpperCase();
  return normalized ? `DHB-${normalized}` : "";
}

function ensureDirectHangItemsForBale(baleNo = "") {
  const normalizedBaleNo = String(baleNo || "").trim().toUpperCase();
  if (!normalizedBaleNo) {
    return [];
  }
  const existing = ensureDirectHangStoreItemState().filter(
    (row) => String(row?.bale_no || "").trim().toUpperCase() === normalizedBaleNo,
  );
  if (existing.length) {
    return existing;
  }
  const bale = ensureDirectHangDispatchBaleState().find(
    (row) => String(row?.bale_no || "").trim().toUpperCase() === normalizedBaleNo,
  );
  if (!bale) {
    return [];
  }
  const unpack = getDirectHangUnpackByNo(bale.direct_hang_unwrap_no || "");
  const total = Math.max(0, Number(bale.item_count || 0));
  const rows = Array.from({ length: total }, (_, index) => ({
    bale_no: normalizedBaleNo,
    transfer_no: bale.transfer_no || "",
    direct_hang_unwrap_no: bale.direct_hang_unwrap_no || "",
    source_bale_token: bale.source_bale_token || "",
    store_code: bale.store_code || "",
    assigned_employee: bale.assigned_employee || "",
    supplier_name: bale.supplier_name || unpack?.supplier_name || "",
    category_main: splitCategoryLabel(bale.category_name || "").main,
    category_sub: splitCategoryLabel(bale.category_name || "").sub,
    unit_cost_amount: Number(unpack?.unit_cost_amount || 0),
    unit_cost_currency: unpack?.source_unit_cost_currency || "",
    unit_cost_kes: Number(unpack?.unit_cost_kes || 0),
    qty_index: index + 1,
    qty_total: total,
    suggested_price_kes: "",
    selling_price_kes: null,
    suggested_rack_code: "",
    store_rack_code: "",
    identity_no: "",
    barcode_value: "",
    status: "pending_edit",
    printed_at: "",
    shelved_at: "",
  }));
  directHangStoreItemState = [...ensureDirectHangStoreItemState(), ...rows];
  persistDirectHangStoreItemState();
  return rows;
}

function getDirectHangItemsByBale(baleNo = "", assignedEmployee = "") {
  const normalizedBaleNo = String(baleNo || "").trim().toUpperCase();
  if (!normalizedBaleNo) {
    return [];
  }
  const rows = ensureDirectHangItemsForBale(normalizedBaleNo);
  const normalizedEmployee = String(assignedEmployee || "").trim();
  return normalizedEmployee
    ? rows.filter((row) => String(row.assigned_employee || "").trim() === normalizedEmployee)
    : rows;
}

function getPreferredItemTokenTemplateCode(preferredValue = "") {
  const preferred = String(preferredValue || "").trim().toLowerCase();
  const productTemplates = getLabelTemplatesByScope("product");
  if (preferred && productTemplates.some((row) => String(row?.template_code || "").trim().toLowerCase() === preferred)) {
    return preferred;
  }
  const currentValue = String(document.querySelector("#itemTokenPrintQueueForm [name='template_code']")?.value || "").trim().toLowerCase();
  if (currentValue && productTemplates.some((row) => String(row?.template_code || "").trim().toLowerCase() === currentValue)) {
    return currentValue;
  }
  return String(productTemplates[0]?.template_code || "apparel_40x30").trim().toLowerCase();
}

