function deriveBaleLabelDisplayParts(barcodeValue = "", supplierName = "", categoryDisplay = "", packagePosition = "") {
  const raw = String(barcodeValue || "").trim().toUpperCase();
  const parts = raw.split("-").map((part) => String(part || "").trim()).filter(Boolean);
  let primaryIdentity = String(supplierName || categoryDisplay || raw || "-").trim();
  let packageCompact = String(packagePosition || "")
    .replace("PKG ", "")
    .replace("/", "-")
    .replace("第 ", "")
    .replace(" 包 / 共 ", "-")
    .replace(/ 包/g, "")
    .trim();
  let shipmentDate = "";
  if (parts.length >= 7 && parts[0] === "BALE" && parts[1] === "BL") {
    shipmentDate = parts[2] || "";
    primaryIdentity = `${parts[3] || ""}-${parts[4] || ""}`.replace(/^-|-$/g, "") || primaryIdentity;
    packageCompact = `${parts[5] || ""}-${parts[6] || ""}`.replace(/^-|-$/g, "") || packageCompact;
  }
  const bottomHuman = packageCompact || (raw.length > 18 ? raw.slice(-18) : raw || "-");
  return {
    raw,
    primaryIdentity,
    packageCompact,
    shipmentDate,
    bottomHuman,
  };
}

function getBalePrintModalCloseAction() {
  const jobs = Array.isArray(balePrintModalState.jobs) ? balePrintModalState.jobs : [];
  const templateScope = getActiveBaleTemplateScope();
  if (templateScope !== "bale") {
    return {
      action: "allow_close",
      pendingCount: jobs.length,
      message: "",
    };
  }
  if (balePrintFlow.getBaleModalCloseAction) {
    return balePrintFlow.getBaleModalCloseAction({
      pendingCount: jobs.length,
      hasSuccessfulBatchPrint: balePrintModalState.hasSuccessfulBatchPrint,
    });
  }
  return {
    action: "allow_close",
    pendingCount: jobs.length,
    message: jobs.length ? `当前仅关闭打印窗并返回页面，不会把这 ${jobs.length} 包标记为已打印或已贴完。` : "",
  };
}

function isBalePrintModalAlreadyComplete(completionAction = null) {
  const jobs = Array.isArray(balePrintModalState.jobs) ? balePrintModalState.jobs : [];
  if (completionAction && completionAction.action === "already_complete") {
    return true;
  }
  return !jobs.length && getBalePrintModalCloseAction().action === "allow_close";
}

function closeBalePrintModal(options = {}) {
  if (!(balePrintModal instanceof HTMLElement)) {
    return false;
  }
  balePrintModal.classList.add("hidden-screen");
  const frame = document.querySelector("#balePrintPreviewFrame");
  if (frame instanceof HTMLIFrameElement) {
    frame.removeAttribute("srcdoc");
    frame.src = "about:blank";
  }
  return true;
}

function getLocalPrintAgentUrl() {
  const current = String(localPrintAgentState.url || localStorage.getItem(STORAGE_KEYS.localPrintAgentUrl) || "http://127.0.0.1:8719").trim();
  return current || "http://127.0.0.1:8719";
}

function setLocalPrintAgentMessage(type, message) {
  balePrinterConsoleNotice = { type, message };
  localPrintAgentState.lastMessage = String(message || "").trim();
}

function renderBaleLocalPrintAgentStatus() {
  const statusArea = document.querySelector("#balePrintModalLocalAgentStatus");
  if (!(statusArea instanceof HTMLElement)) {
    return;
  }
  const agentUrl = getLocalPrintAgentUrl();
  const statusText = localPrintAgentState.checking
    ? "checking"
    : (localPrintAgentState.connected ? "connected" : "not connected");
  const suffix = localPrintAgentState.lastMessage ? ` · ${localPrintAgentState.lastMessage}` : "";
  statusArea.className = "candidate-summary";
  statusArea.textContent = `Local print agent: ${statusText} · URL: ${agentUrl}${suffix}`;
}

async function checkLocalPrintAgentHealth() {
  const agentUrl = getLocalPrintAgentUrl();
  localPrintAgentState.url = agentUrl;
  localPrintAgentState.checking = true;
  localPrintAgentState.lastMessage = "";
  renderBaleLocalPrintAgentStatus();
  try {
    const response = await fetch(`${agentUrl}/health`, { method: "GET" });
    if (!response.ok) {
      throw new Error(`health check failed (${response.status})`);
    }
    const payload = await response.json();
    if (String(payload?.status || "").trim().toLowerCase() !== "ok") {
      throw new Error("agent returned unexpected health status");
    }
    localPrintAgentState.connected = true;
    localPrintAgentState.checking = false;
    localPrintAgentState.lastMessage = "health ok";
    setLocalPrintAgentMessage("success", `本地打印代理可用：${agentUrl}`);
    localStorage.setItem(STORAGE_KEYS.localPrintAgentUrl, agentUrl);
    renderBalePrintModal();
    return payload;
  } catch (error) {
    localPrintAgentState.connected = false;
    localPrintAgentState.checking = false;
    localPrintAgentState.lastMessage = "health failed";
    setLocalPrintAgentMessage("error", `本地打印代理不可用（${agentUrl}）。请先启动 FW-ERP Local Print Agent，或改用“用浏览器打印 / Use browser print”。`);
    renderBalePrintModal();
    throw error;
  }
}

function getCurrentBalePreviewHtml() {
  const frame = document.querySelector("#balePrintPreviewFrame");
  if (!(frame instanceof HTMLIFrameElement)) {
    throw new Error("当前找不到打印预览窗口。");
  }
  if (typeof frame.srcdoc === "string" && frame.srcdoc.trim()) {
    return frame.srcdoc;
  }
  const frameDocument = frame.contentDocument;
  if (!frameDocument || !frameDocument.documentElement) {
    throw new Error("当前预览还没加载完成，请先点“刷新预览”后重试。");
  }
  return `<!doctype html>\n${frameDocument.documentElement.outerHTML}`;
}

async function printCurrentBaleModalViaLocalAgent() {
  const jobs = Array.isArray(balePrintModalState.jobs) ? balePrintModalState.jobs : [];
  const currentJob = jobs[balePrintModalState.currentIndex] || null;
  if (!currentJob) {
    throw new Error("当前没有可打印的标签。");
  }
  const html = getCurrentBalePreviewHtml();
  const printerName = String(document.querySelector("[data-bale-modal-printer-select]")?.value || document.querySelector("#balePrinterConsoleForm [name='printer_name']")?.value || "Deli DL-720C").trim();
  if (!printerName) {
    throw new Error("请先选择打印机。");
  }
  const agentUrl = getLocalPrintAgentUrl();
  const response = await fetch(`${agentUrl}/print/html`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      html,
      printer: printerName,
    }),
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok || payload?.ok === false) {
    throw new Error(String(payload?.message || `本地代理打印失败（${response.status}）`));
  }
  localPrintAgentState.connected = true;
  localPrintAgentState.lastMessage = "print submitted";
  setLocalPrintAgentMessage("success", String(payload?.message || `已通过本地代理发送打印：${printerName}`));
  renderBalePrintModal();
}

function renderBalePrintModal() {
  if (!(balePrintModal instanceof HTMLElement)) {
    return;
  }
  const summary = document.querySelector("#balePrintModalSummary");
  const queue = document.querySelector("#balePrintModalQueue");
  const subhead = document.querySelector("#balePrintModalSubhead");
  const frame = document.querySelector("#balePrintPreviewFrame");
  const prevButton = document.querySelector("#balePrintModalPrevButton");
  const nextButton = document.querySelector("#balePrintModalNextButton");
  const refreshButton = document.querySelector("#balePrintModalRefreshButton");
  const checkLocalAgentButton = document.querySelector("#balePrintModalCheckLocalAgentButton");
  const localAgentPrintButton = document.querySelector("#balePrintModalLocalAgentPrintButton");
  const connectButton = document.querySelector("#balePrintModalConnectButton");
  const directPrintButton = document.querySelector("#balePrintModalDirectPrintButton");
  const printAllButton = document.querySelector("#balePrintModalPrintAllButton");
  const sendToStationButton = document.querySelector("#balePrintModalSendToStationButton");
  const browserPrintButton = document.querySelector("#balePrintModalBrowserPrintButton");
  const completeButton = document.querySelector("#balePrintModalCompleteButton");
  const closeAndRefreshButton = document.querySelector("#balePrintModalCloseAndRefreshButton");
  const jobs = Array.isArray(balePrintModalState.jobs) ? balePrintModalState.jobs : [];
  const currentIndex = Math.max(0, Math.min(Number(balePrintModalState.currentIndex || 0), Math.max(jobs.length - 1, 0)));
  balePrintModalState.currentIndex = currentIndex;
  const currentJob = jobs[currentIndex] || null;
  const templateScope = getActiveBaleTemplateScope();
  const activeTaskType = getActiveBaleModalTaskType();
  const completionAction = templateScope !== "bale"
    ? {
      action: jobs.length ? "complete_group" : "already_complete",
      pendingCount: jobs.length,
    }
    : (balePrintFlow.getBaleModalCompletionAction
    ? balePrintFlow.getBaleModalCompletionAction({
      pendingCount: jobs.length,
      hasSuccessfulBatchPrint: balePrintModalState.hasSuccessfulBatchPrint,
    })
    : {
      action: jobs.length ? (balePrintModalState.hasSuccessfulBatchPrint ? "complete_group" : "print_first") : "already_complete",
      pendingCount: jobs.length,
    });
  const closeAction = getBalePrintModalCloseAction();
  const alreadyComplete = isBalePrintModalAlreadyComplete(completionAction);
  const selectedTemplateCode = getActiveBaleTemplateCode(balePrintModalState.preferredTemplateCode || currentJob?.template_code || currentJob?.print_payload?.template_code || "");
  balePrintModalState.preferredTemplateCode = selectedTemplateCode;
  const selectedTemplate = getSelectedBaleTemplate(selectedTemplateCode, templateScope, activeTaskType);
  const selectedPrinterName = String(document.querySelector("#balePrinterConsoleForm [name='printer_name']")?.value || "Deli DL-720C").trim();
  const selectedPrinter = findSystemPrinterBySelectedName(selectedPrinterName);
  const supportsTemplate = printerSupportsBaleTemplate(selectedPrinter, selectedTemplate);
  const usesTsplMode = isTsplRawPrinter(selectedPrinter);
  const baleTemplateOptions = getBaleModalTemplateOptions(templateScope, selectedTemplate.template_code);
  const printerOptions = (Array.isArray(systemPrinterState) && systemPrinterState.length
    ? systemPrinterState
    : [{ name: selectedPrinterName }])
    .map((printer) => {
      const name = String(printer?.name || "").trim();
      return `<option value="${escapeHtml(name)}" ${normalizePrinterName(name) === normalizePrinterName(selectedPrinterName) ? "selected" : ""}>${escapeHtml(name.replace(/_/g, " "))}</option>`;
    })
    .join("");

  const currentPackageLabel = String(
    currentJob?.print_payload?.package_position_label
      || currentJob?.print_payload?.package_position
      || `第 ${currentJob?.print_payload?.serial_no || currentIndex + 1} 包 / 共 ${currentJob?.print_payload?.total_packages || jobs.length || 1} 包`,
  ).trim();
  const displayParts = currentJob
    ? deriveBaleLabelDisplayParts(
        currentJob.barcode || currentJob.print_payload?.barcode_value || "",
        currentJob.print_payload?.supplier_name || balePrintModalState.supplierName || "",
        currentJob.print_payload?.category_display || balePrintModalState.categoryDisplay || currentJob.product_name || "",
        currentPackageLabel,
      )
    : null;

  if (subhead) {
    subhead.textContent = currentJob
      ? `${displayParts?.primaryIdentity || balePrintModalState.supplierName || "-"} · ${displayParts?.packageCompact || `第 ${currentIndex + 1} 包`} · ${displayParts?.shipmentDate || ""}`.replace(/ · $/, "")
      : `${balePrintModalState.supplierName || "-"} · ${balePrintModalState.categoryDisplay || "-"} · 当前类别已经全部打印完成`;
  }

  if (summary) {
    summary.className = "candidate-summary";
    summary.innerHTML = `
      <div class="bale-modal-toolbar bale-modal-toolbar-clean">
        <div class="bale-modal-title-block">
          <strong>${escapeHtml(displayParts?.primaryIdentity || currentJob?.barcode || balePrintModalState.categoryDisplay || "当前类别")}</strong>
          <div class="subtle small">${currentJob ? `Code128 一维码 · ${escapeHtml(displayParts?.packageCompact || `第 ${currentIndex + 1} 包 / 共 ${jobs.length} 包`)}${displayParts?.shipmentDate ? ` · ${escapeHtml(displayParts.shipmentDate)}` : ""}` : "这一类已经全部打印完成，可以关闭弹层并继续下一类。"}</div>
        </div>
        <div class="bale-modal-inline-grid">
          <label class="field-stack compact-select">
            <span>打印模板</span>
            <select data-bale-template-select data-bale-modal-template-select>
              ${baleTemplateOptions
                .map(
                  (row) => `
                    <option value="${escapeHtml(row.template_code)}" ${row.disabled ? "disabled" : ""} ${row.selected || String(row.template_code || "").trim().toLowerCase() === String(selectedTemplate.template_code || "").trim().toLowerCase() ? "selected" : ""}>
                      ${escapeHtml(`${getBaleTemplateOptionLabel(row)}${row.disabled ? " · 不可用于当前页面" : ""}`)}
                    </option>
                  `,
                )
                .join("")}
            </select>
          </label>
          <label class="field-stack compact-select">
            <span>打印机</span>
            <select data-bale-modal-printer-select>
              ${printerOptions}
            </select>
          </label>
        </div>
        <div class="button-row bale-modal-status-row">
          <span class="meta-pill">${escapeHtml(selectedTemplate.barcode_type || "Code128")} 一维码</span>
          <span class="meta-pill">当前测试 ${selectedTemplate.width_mm || 60}x${selectedTemplate.height_mm || 40}</span>
          <span class="meta-pill">${escapeHtml(selectedPrinter ? getPrinterConnectionStatusLabel(selectedPrinter) : "待安装打印机")}</span>
          <span class="meta-pill ${supportsTemplate ? "" : "warning-pill"}">${usesTsplMode ? "标签机 TSPL 直打" : (supportsTemplate ? `支持 ${escapeHtml(getSelectedBaleTemplateSizeLabel(selectedTemplate))}` : `当前队列不支持 ${escapeHtml(getSelectedBaleTemplateSizeLabel(selectedTemplate))}`)}</span>
          ${
            balePrinterConsoleNotice
              ? `<span class="meta-pill">${escapeHtml(balePrinterConsoleNotice.message)}</span>`
              : ""
          }
        </div>
        ${selectedPrinter && !supportsTemplate && !usesTsplMode
          ? `<div class="alert-banner">当前这台 ${escapeHtml(selectedPrinterName.replace(/_/g, " "))} 打印队列没有暴露 ${escapeHtml(getSelectedBaleTemplateSizeLabel(selectedTemplate))} 标签纸尺寸。任务可能发送成功，但打印机不会实际出纸。</div>`
          : ""}
        ${selectedPrinter && usesTsplMode
          ? `<div class="flow-summary-note success">当前已切换为 TSPL 原始指令直打，不依赖 macOS 的 A4/Letter 纸张队列。请直接测试是否正常出纸。</div>`
          : ""}
        <div class="flow-summary-note">“直接打印本张（仅本地/LAN 后端）”仅适用于本地/LAN 部署后端。Cloud staging 建议优先使用本地打印代理或浏览器打印兜底。</div>
        ${closeAction.action !== "allow_close"
          ? `<div class="flow-summary-note">当前这轮贴码流程不会因为关闭弹窗而结束。核对实体出纸后，请点“确认本类已贴完”。</div>`
          : ""}
      </div>
    `;
  }

  if (queue) {
    queue.className = jobs.length ? "candidate-list" : "candidate-summary empty-state";
    queue.innerHTML = jobs.length
      ? jobs
          .map((job, index) => `
            <article class="candidate-row ${index === currentIndex ? "selected-bale-row" : ""}">
              <div class="selected-bale-body">
                ${(() => {
                  const queueLabel = String(job.print_payload?.package_position_label || job.print_payload?.package_position || `第 ${index + 1} 包 / 共 ${jobs.length} 包`).trim();
                  const queueParts = deriveBaleLabelDisplayParts(
                    job.barcode || job.print_payload?.barcode_value || "",
                    job.print_payload?.supplier_name || balePrintModalState.supplierName || "",
                    job.print_payload?.category_display || balePrintModalState.categoryDisplay || job.product_name || "",
                    queueLabel,
                  );
                  return `
                    <strong>${escapeHtml(queueParts.primaryIdentity || job.barcode || "-")}</strong>
                    <div class="subtle small">${escapeHtml(queueParts.packageCompact || `第 ${index + 1} 包`)}${queueParts.shipmentDate ? ` · ${escapeHtml(queueParts.shipmentDate)}` : ""}</div>
                  `;
                })()}
              </div>
            </article>
          `)
          .join("")
      : alreadyComplete
        ? "当前类别已经全部打印完成。可以点击“关闭并返回当前页”，或继续下一类待贴码。"
        : "当前类别下没有待打印任务。";
  }

  if (frame instanceof HTMLIFrameElement) {
    if (!currentJob) {
      frame.removeAttribute("srcdoc");
      frame.src = "about:blank";
    } else if (isBaleModalDirectOnlyJob(currentJob)) {
      frame.src = "about:blank";
      frame.srcdoc = renderDirectOnlyBaleModalPreview(currentJob, selectedTemplate);
    } else {
      frame.removeAttribute("srcdoc");
      frame.src = `${getPrintJobPreviewUrl(currentJob.id, { autoPrint: false, templateCode: selectedTemplate.template_code })}&ts=${Date.now()}`;
    }
  }

  if (prevButton instanceof HTMLButtonElement) {
    prevButton.disabled = !currentJob || currentIndex <= 0;
  }
  if (nextButton instanceof HTMLButtonElement) {
    nextButton.disabled = !currentJob || currentIndex >= jobs.length - 1;
  }
  if (refreshButton instanceof HTMLButtonElement) {
    refreshButton.disabled = !currentJob && !alreadyComplete;
  }
  if (checkLocalAgentButton instanceof HTMLButtonElement) {
    checkLocalAgentButton.disabled = Boolean(localPrintAgentState.checking);
  }
  if (localAgentPrintButton instanceof HTMLButtonElement) {
    localAgentPrintButton.disabled = !currentJob;
  }
  if (connectButton instanceof HTMLButtonElement) {
    connectButton.disabled = false;
  }
  if (directPrintButton instanceof HTMLButtonElement) {
    directPrintButton.disabled = !currentJob;
  }
  if (printAllButton instanceof HTMLButtonElement) {
    printAllButton.disabled = !jobs.length;
    printAllButton.textContent = jobs.length ? `打印本轮全部 ${jobs.length} 张` : "当前类别没有待打印条码";
  }
  if (sendToStationButton instanceof HTMLButtonElement) {
    sendToStationButton.disabled = !currentJob;
  }
  if (browserPrintButton instanceof HTMLButtonElement) {
    browserPrintButton.disabled = !currentJob;
  }
  if (completeButton instanceof HTMLButtonElement) {
    completeButton.disabled = completionAction.action !== "complete_group" && !alreadyComplete;
    completeButton.textContent = alreadyComplete ? "这一类已完成，关闭弹窗" : "确认本类已贴完";
  }
  if (closeBalePrintModalButton instanceof HTMLButtonElement) {
    closeBalePrintModalButton.disabled = false;
  }
  if (closeAndRefreshButton instanceof HTMLButtonElement) {
    closeAndRefreshButton.disabled = false;
  }
  renderBaleLocalPrintAgentStatus();
}

async function getBaleModalPrintContext() {
  const printerName = String(document.querySelector("[data-bale-modal-printer-select]")?.value || document.querySelector("#balePrinterConsoleForm [name='printer_name']")?.value || "").trim();
  if (!printerName) {
    throw new Error("请先选择打印机。");
  }
  await loadSystemPrinters();
  const matchedPrinter = findSystemPrinterBySelectedName(printerName);
  const usesTsplMode = isTsplRawPrinter(matchedPrinter);
  setInputValue("#balePrinterConsoleForm [name='printer_name']", printerName);
  const templateScope = getActiveBaleTemplateScope();
  const activeTaskType = getActiveBaleModalTaskType();
  const templateCode = String(document.querySelector("[data-bale-modal-template-select]")?.value || getActiveBaleTemplateCode()).trim();
  if (templateCode) {
    setInputValue("#balePrinterConsoleForm [name='template_code']", templateCode);
  }
  balePrintModalState.preferredTemplateCode = templateCode;
  const selectedTemplate = getSelectedBaleTemplate(templateCode, templateScope, activeTaskType);
  if (!usesTsplMode && !printerSupportsBaleTemplate(matchedPrinter, selectedTemplate)) {
    throw new Error(`当前系统打印队列没有 ${getSelectedBaleTemplateSizeLabel(selectedTemplate)} 标签纸尺寸。请先把 Deli 打印机按标签机纸张重新配置后再打。`);
  }
  return {
    printerName,
    templateCode,
    templateScope,
    usesTsplMode,
  };
}

function buildBaleModalDirectPayload(job, { currentIndex = 0, totalJobs = 0 } = {}) {
  const templateScope = getActiveBaleTemplateScope();
  const activeTaskType = getActiveBaleModalTaskType();
  const helper = balePrintFlow && typeof balePrintFlow.buildBaleDirectPrintPayload === "function"
    ? balePrintFlow.buildBaleDirectPrintPayload
    : null;
  if (helper && templateScope === "bale") {
    return helper(job, {
      printerName: String(document.querySelector("[data-bale-modal-printer-select]")?.value || document.querySelector("#balePrinterConsoleForm [name='printer_name']")?.value || "").trim(),
      templateCode: String(document.querySelector("[data-bale-modal-template-select]")?.value || getPreferredBaleTemplateCode()).trim() || getPreferredBaleTemplateCode(),
      supplierName: balePrintModalState.supplierName,
      categoryDisplay: balePrintModalState.categoryDisplay,
      currentIndex,
      totalJobs,
    });
  }
  return {
    printer_name: String(document.querySelector("[data-bale-modal-printer-select]")?.value || document.querySelector("#balePrinterConsoleForm [name='printer_name']")?.value || "").trim(),
    template_code: String(document.querySelector("[data-bale-modal-template-select]")?.value || getActiveBaleTemplateCode()).trim() || getActiveBaleTemplateCode(),
    copies: Number(job?.copies || 1) || 1,
    barcode_value: String(job?.print_payload?.scan_token || job?.print_payload?.barcode_value || job?.barcode || "").trim(),
    scan_token: String(job?.print_payload?.scan_token || job?.print_payload?.barcode_value || "").trim(),
    bale_barcode: String(job?.barcode || job?.print_payload?.bale_barcode || "").trim(),
    legacy_bale_barcode: String(job?.print_payload?.legacy_bale_barcode || "").trim(),
    supplier_name: String(job?.print_payload?.supplier_name || balePrintModalState.supplierName || "").trim(),
    category_main: String(job?.print_payload?.category_main || "").trim(),
    category_sub: String(job?.print_payload?.category_sub || "").trim(),
    category_display: String(job?.print_payload?.category_display || balePrintModalState.categoryDisplay || job?.product_name || "").trim(),
    package_position_label: String(
      job?.print_payload?.package_position_label
        || job?.print_payload?.package_position
        || `第 ${job?.print_payload?.serial_no || currentIndex + 1} 包 / 共 ${job?.print_payload?.total_packages || totalJobs || 1} 包`,
    ).trim(),
    serial_no: Number(job?.print_payload?.serial_no || currentIndex + 1 || 0),
    total_packages: Number(job?.print_payload?.total_packages || totalJobs || 0),
    shipment_no: String(job?.print_payload?.shipment_no || "").trim(),
    parcel_batch_no: String(job?.print_payload?.parcel_batch_no || "").trim(),
    unload_date: String(job?.print_payload?.unload_date || job?.print_payload?.received_at || "").trim(),
    template_scope: templateScope,
    store_name: String(job?.print_payload?.store_name || "").trim(),
    transfer_order_no: String(job?.print_payload?.transfer_order_no || "").trim(),
    bale_piece_summary: String(job?.print_payload?.bale_piece_summary || "").trim(),
    total_quantity: String(job?.print_payload?.total_quantity || "").trim(),
    packing_list: String(job?.print_payload?.packing_list || "").trim(),
    dispatch_bale_no: String(job?.print_payload?.dispatch_bale_no || job?.print_payload?.scan_token || job?.print_payload?.barcode_value || job?.barcode || "").trim(),
    outbound_time: String(job?.print_payload?.outbound_time || "").trim(),
    status: String(job?.print_payload?.status || (activeTaskType === "sale" ? "wait for sale" : "wait for transtoshop")).trim(),
    cat: String(job?.print_payload?.cat || job?.print_payload?.category_main || "").trim(),
    sub: String(job?.print_payload?.sub || job?.print_payload?.category_sub || "").trim(),
    grade: String(job?.print_payload?.grade || job?.print_payload?.grade_summary || "").trim(),
    qty: String(job?.print_payload?.qty || "").trim(),
    weight: String(job?.print_payload?.weight || "").trim(),
    code: String(job?.print_payload?.code || job?.print_payload?.dispatch_bale_no || job?.print_payload?.scan_token || job?.print_payload?.barcode_value || job?.barcode || "").trim(),
  };
}

async function directPrintBaleModalJob(job, { printerName, templateCode, currentIndex = 0, totalJobs = 0 } = {}) {
  const directPayload = buildBaleModalDirectPayload(job, { currentIndex, totalJobs });
  balePrinterConsoleNotice = {
    type: "success",
    message: `正在发送 ${job.barcode || "当前条码"} 到打印机${isTsplRawPrinter(findSystemPrinterBySelectedName(printerName)) ? "（TSPL 直打）" : ""}...`,
  };
  renderBalePrintModal();
  let result;
  try {
    if (isBaleModalDirectOnlyJob(job)) {
      throw new Error("missing-job-id");
    }
    result = await request(`/print-jobs/${job.id}/direct-print?printer_name=${encodeURIComponent(printerName)}${templateCode ? `&template_code=${encodeURIComponent(templateCode)}` : ""}`, {
      method: "POST",
    });
  } catch (error) {
    const message = String(error?.message || "");
    const shouldFallback = isBaleModalDirectOnlyJob(job)
      || message.includes("Unknown print job")
      || message.includes("404")
      || message.includes("valid integer")
      || message.includes("int_parsing");
    if (!shouldFallback) {
      throw error;
    }
    result = await request("/print-jobs/bale-direct/print", {
      method: "POST",
      body: JSON.stringify(directPayload),
    });
  }
  balePrinterConsoleNotice = {
    type: "success",
    message: String(result?.message || `${job?.barcode || "当前条码"} 已发送到打印机。请看打印机是否开始出纸。`),
  };
  renderBalePrintModal();
}

async function directPrintCurrentBaleModalJob() {
  const jobs = Array.isArray(balePrintModalState.jobs) ? balePrintModalState.jobs : [];
  const currentJob = jobs[balePrintModalState.currentIndex] || null;
  if (!currentJob) {
    return;
  }
  const { printerName, templateCode } = await getBaleModalPrintContext();
  await directPrintBaleModalJob(currentJob, {
    printerName,
    templateCode,
    currentIndex: Number(balePrintModalState.currentIndex || 0),
    totalJobs: jobs.length,
  });
}

async function sendCurrentBaleModalJobToPrintStation() {
  const jobs = Array.isArray(balePrintModalState.jobs) ? balePrintModalState.jobs : [];
  const currentIndex = Number(balePrintModalState.currentIndex || 0);
  const currentJob = jobs[currentIndex] || null;
  if (!currentJob) {
    throw new Error("当前没有可发送到打印站的标签。");
  }
  const payload = balePrintFlow && typeof balePrintFlow.buildBalePrintStationJobPayload === "function"
    ? balePrintFlow.buildBalePrintStationJobPayload(currentJob, {
      currentIndex,
      totalJobs: jobs.length,
      supplierName: balePrintModalState.supplierName,
      shipmentNo: balePrintModalState.shipmentNo,
    })
    : {
      code: String(currentJob?.print_payload?.scan_token || currentJob?.print_payload?.barcode_value || currentJob?.barcode || "").trim(),
      supplier: String(currentJob?.print_payload?.supplier_name || balePrintModalState.supplierName || "").trim(),
      category: String(currentJob?.print_payload?.category_main || "").trim(),
      subcategory: String(currentJob?.print_payload?.category_sub || "").trim(),
      batch: String(currentJob?.print_payload?.parcel_batch_no || "").trim(),
      ship_reference: String(currentJob?.print_payload?.shipment_no || balePrintModalState.shipmentNo || "").trim(),
      total_number: Number(currentJob?.print_payload?.total_packages || jobs.length || 0),
      sequence_number: Number(currentJob?.print_payload?.serial_no || currentIndex + 1),
    };
  const result = await request("/print-jobs/bale-label", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  balePrinterConsoleNotice = {
    type: "success",
    message: `已发送到打印站队列。任务 #${result?.id || "-"} · 状态 ${result?.status || "pending"}。`,
  };
  renderBalePrintModal();
}

function browserPrintCurrentBaleModalJob() {
  const jobs = Array.isArray(balePrintModalState.jobs) ? balePrintModalState.jobs : [];
  const currentJob = jobs[balePrintModalState.currentIndex] || null;
  if (!currentJob) {
    throw new Error("当前没有可打印的标签。");
  }
  const frame = document.querySelector("#balePrintPreviewFrame");
  if (!(frame instanceof HTMLIFrameElement)) {
    throw new Error("当前找不到打印预览窗口。");
  }
  const frameWindow = frame.contentWindow;
  if (!frameWindow) {
    throw new Error("当前预览还没加载完成，请先点“刷新预览”后重试。");
  }
  frameWindow.focus();
  frameWindow.print();
  balePrinterConsoleNotice = {
    type: "success",
    message: "已打开浏览器打印对话框。Cloud staging 不能直接控制本地 USB 打印机，请在 Mac 对话框里选择 Deli_DL_720C。",
  };
  renderBalePrintModal();
}

async function directPrintAllBaleModalJobs() {
  const jobs = Array.isArray(balePrintModalState.jobs) ? [...balePrintModalState.jobs] : [];
  if (!jobs.length) {
    return;
  }
  const { printerName, templateCode, usesTsplMode } = await getBaleModalPrintContext();
  const totalJobs = jobs.length;
  const normalizedGroupKey = String(balePrintModalState.groupKey || "").trim().toUpperCase();
  balePrintModalState.hasSuccessfulBatchPrint = false;
  baleBatchCompletionReadyKeys.delete(normalizedGroupKey);
  if (usesTsplMode) {
    balePrinterConsoleNotice = {
      type: "success",
      message: `正在一次性发送本轮 ${totalJobs} 张到打印机（TSPL 直打）...`,
    };
    renderBalePrintModal();
    const items = jobs.map((job, index) => buildBaleModalDirectPayload(job, { currentIndex: index, totalJobs }));
    const result = await request("/print-jobs/bale-direct/print-batch", {
      method: "POST",
      body: JSON.stringify({
        printer_name: printerName,
        template_code: templateCode || getActiveBaleTemplateCode(),
        items,
      }),
    });
    balePrinterConsoleNotice = {
      type: "success",
      message: String(result?.message || `本轮 ${totalJobs} 张 barcode 已一次性发送到打印机。`),
    };
    renderBalePrintModal();
  } else {
    for (let index = 0; index < totalJobs; index += 1) {
      const job = jobs[index];
      balePrintModalState.currentIndex = index;
      balePrinterConsoleNotice = {
        type: "success",
        message: `正在发送第 ${index + 1}/${totalJobs} 张到打印机...`,
      };
      renderBalePrintModal();
      await directPrintBaleModalJob(job, {
        printerName,
        templateCode,
        currentIndex: index,
        totalJobs,
      });
    }
  }
  balePrintModalState.currentIndex = 0;
  balePrintModalState.hasSuccessfulBatchPrint = true;
  if (normalizedGroupKey) {
    baleBatchCompletionReadyKeys.add(normalizedGroupKey);
  }
  balePrinterConsoleNotice = {
    type: "success",
    message: `本轮 ${totalJobs} 张 barcode 已全部发送到打印机。请核对实体出纸后，再点“确认本类已贴完”。`,
  };
  renderBalePrintModal();
}

function openBalePrintModal(state = {}) {
  if (!(balePrintModal instanceof HTMLElement)) {
    return;
  }
  const normalizedGroupKey = String(state.groupKey || "").trim().toUpperCase();
  balePrintModalState = {
    shipmentNo: state.shipmentNo || "",
    groupKey: normalizedGroupKey,
    jobs: Array.isArray(state.jobs) ? state.jobs : [],
    currentIndex: 0,
    supplierName: state.supplierName || "",
    categoryDisplay: state.categoryDisplay || "",
    hasSuccessfulBatchPrint: normalizedGroupKey ? baleBatchCompletionReadyKeys.has(normalizedGroupKey) : false,
    templateScope: String(state.templateScope || "").trim().toLowerCase() || "bale",
    taskType: String(state.taskType || "").trim().toLowerCase() || "store_dispatch",
    preferredTemplateCode: String(state.preferredTemplateCode || "").trim().toLowerCase(),
  };
  balePrintModal.classList.remove("hidden-screen");
  renderBalePrintModal();
}

async function handleConnectBalePrinter() {
  const printerName = String(document.querySelector("#balePrinterConsoleForm [name='printer_name']")?.value || "Deli DL-720C").trim();
  const shipmentNo = String(document.querySelector("#balePrinterConsoleForm [name='shipment_no']")?.value || "").trim();
  await loadSystemPrinters();
  const matched = findSystemPrinterBySelectedName(printerName);
  balePrinterConsoleNotice = matched
    ? {
        type: "success",
        message: `${isTsplRawPrinter(matched) ? "标签机 TSPL 直打模式已就绪" : `系统里已安装打印机：${printerName}，当前状态：${matched.status_text || "未知"}`}。${shipmentNo ? `当前船单 ${shipmentNo} 的待打任务已经准备好了。` : "现在可以先选择船单并读取待打任务。"} `,
      }
    : {
        type: "error",
        message: systemPrinterState.length
          ? `系统里没有找到名为 ${printerName} 的打印机。请检查名称，或去「系统设置 > 打印机与扫描仪」重新添加。`
          : "这台电脑当前没有安装任何系统打印机。请先去「系统设置 > 打印机与扫描仪」添加 Deli DL-720C。",
      };
  renderBalePrinterConsoleSummary(shipmentNo);
  focusElement("#balePrinterConsoleSummary");
}

async function completeCurrentBalePrintModalJob() {
  const jobs = Array.isArray(balePrintModalState.jobs) ? balePrintModalState.jobs : [];
  const templateScope = getActiveBaleTemplateScope();
  const completionAction = templateScope !== "bale"
    ? {
      action: jobs.length ? "complete_group" : "already_complete",
      pendingCount: jobs.length,
    }
    : (balePrintFlow.getBaleModalCompletionAction
    ? balePrintFlow.getBaleModalCompletionAction({
      pendingCount: jobs.length,
      hasSuccessfulBatchPrint: balePrintModalState.hasSuccessfulBatchPrint,
    })
    : {
      action: jobs.length ? (balePrintModalState.hasSuccessfulBatchPrint ? "complete_group" : "print_first") : "already_complete",
      pendingCount: jobs.length,
    });
  if (completionAction.action === "already_complete") {
    const shipmentNo = balePrintModalState.shipmentNo || "";
    closeBalePrintModal({ force: true });
    if (shipmentNo) {
      renderBaleShipmentPrintProgress(shipmentNo);
      renderBaleBarcodeDirectorySummary(shipmentNo);
    }
    return;
  }
  if (completionAction.action !== "complete_group") {
    throw new Error(`请先点“打印本轮全部 ${completionAction.pendingCount} 张”，确认实体出纸后，再确认本类已贴完。`);
  }
  const jobsToComplete = [...jobs];
  for (const job of jobsToComplete) {
    if (!isBaleModalDirectOnlyJob(job)) {
      try {
        await request(`/print-jobs/${job.id}/complete`, { method: "POST" });
      } catch (error) {
        const message = String(error?.message || "");
        if (!message.includes("Unknown print job") && !message.includes("404") && !message.includes("valid integer") && !message.includes("int_parsing")) {
          throw error;
        }
      }
    }
  }
  balePrintModalState.jobs = [];
  balePrintModalState.currentIndex = 0;
  balePrintModalState.hasSuccessfulBatchPrint = false;
  baleBatchCompletionReadyKeys.delete(String(balePrintModalState.groupKey || "").trim().toUpperCase());
  const completedJobIds = new Set(
    jobsToComplete
      .filter((job) => !isBaleModalDirectOnlyJob(job))
      .map((job) => String(job.id)),
  );
  if (completedJobIds.size) {
    balePrinterJobState = balePrinterJobState.filter((queuedJob) => !completedJobIds.has(String(queuedJob.id)));
  }
  if (templateScope !== "bale") {
    balePrinterConsoleNotice = {
      type: "success",
      message: `${jobsToComplete.length} 张 warehouseout barcode 已确认贴完。`,
    };
    renderBalePrintModal();
    return;
  }
  const shipmentNo = balePrintModalState.shipmentNo;
  if (shipmentNo) {
    const refreshedRows = await reloadBaleShipmentPrintRows(shipmentNo);
    const refreshedGroups = groupBalesByBatch(refreshedRows);
    const nextPendingKey = getNextPendingBaleBatchKey(refreshedGroups);
    activeBaleBatchKey = nextPendingKey;
    if (nextPendingKey) {
      expandedBaleBatchKeys.add(nextPendingKey);
    }
    baleBarcodeDirectoryNotice = {
      type: "success",
      message: `${balePrintModalState.supplierName || ""} ${balePrintModalState.categoryDisplay || ""} 这一类 ${jobsToComplete.length} 包已经全部贴码完成。`,
    };
    renderBaleShipmentPrintProgress(shipmentNo);
  }
  renderBalePrintModal();
}

