function emptyParcelBatchRow() {
  return {
    source_bale_token: "",
    supplier_name: "",
    package_count: "",
    total_weight: "",
    category_main: "",
    category_sub: "",
    note: "",
  };
}

function getChinaSourceLinesForShipment(shipmentNo = "") {
  const normalizedShipmentNo = normalizeShipmentNo(shipmentNo);
  if (!normalizedShipmentNo) {
    return [];
  }
  const shipment = getInboundShipmentRecord(normalizedShipmentNo);
  const customsNoticeNo = String(shipment?.customs_notice_no || "").trim().toUpperCase();
  if (!customsNoticeNo) {
    return [];
  }
  const sourceRecord = getChinaSourceRecordByCustomsNotice(customsNoticeNo);
  return Array.isArray(sourceRecord?.lines) ? sourceRecord.lines : [];
}

function getChinaSourceLineForShipment(shipmentNo = "", sourceBaleToken = "") {
  const normalizedToken = String(sourceBaleToken || "").trim().toUpperCase();
  if (!normalizedToken) {
    return null;
  }
  return getChinaSourceLinesForShipment(shipmentNo).find(
    (row) => String(row?.source_bale_token || "").trim().toUpperCase() === normalizedToken,
  ) || null;
}

function inferChinaSourceTokenForRow(shipmentNo = "", row = {}) {
  const lines = getChinaSourceLinesForShipment(shipmentNo);
  if (!lines.length) {
    return "";
  }
  const matched = lines.find((line) =>
    String(line?.supplier_name || "").trim() === String(row?.supplier_name || "").trim()
    && String(line?.category_main || "").trim() === String(row?.category_main || "").trim()
    && String(line?.category_sub || "").trim() === String(row?.category_sub || "").trim(),
  );
  return matched?.source_bale_token || "";
}

function parcelSourceOptionsHtml(shipmentNo = "", selectedValue = "") {
  const options = ['<option value="">请选择中方预报项</option>'];
  getChinaSourceLinesForShipment(shipmentNo).forEach((row) => {
    const value = String(row?.source_bale_token || "").trim();
    const label = `${row.supplier_name || "-"} · ${row.category_main || "-"} / ${row.category_sub || "-"} · 中方 ${row.package_count || 0} 包 · ${row.total_weight_kg || 0} KG`;
    options.push(`<option value="${escapeHtml(value)}"${value === selectedValue ? " selected" : ""}>${escapeHtml(label)}</option>`);
  });
  return options.join("");
}

function syncParcelBatchRowsFromDom() {
  const container = document.querySelector("#parcelBatchItemsBuilder");
  if (!(container instanceof HTMLElement)) {
    return [];
  }
  const shipmentNo = normalizeShipmentNo(document.querySelector("#parcelBatchForm [name='inbound_shipment_no']")?.value || currentInboundShipmentNo);
  const rows = [...container.querySelectorAll("[data-parcel-batch-row-index]")].map((rowNode) => {
    const sourceBaleToken = rowNode.querySelector("[data-parcel-batch-field='source_bale_token']")?.value?.trim?.() || "";
    const sourceLine = getChinaSourceLineForShipment(shipmentNo, sourceBaleToken);
    return {
      source_bale_token: sourceBaleToken,
      supplier_name: sourceLine?.supplier_name || rowNode.querySelector("[data-parcel-batch-field='supplier_name_hidden']")?.value?.trim?.() || "",
      package_count: Number(rowNode.querySelector("[data-parcel-batch-field='package_count']")?.value || 0),
      total_weight: rowNode.querySelector("[data-parcel-batch-field='total_weight']")?.value || "",
      category_main: sourceLine?.category_main || rowNode.querySelector("[data-parcel-batch-field='category_main_hidden']")?.value?.trim?.() || "",
      category_sub: sourceLine?.category_sub || rowNode.querySelector("[data-parcel-batch-field='category_sub_hidden']")?.value?.trim?.() || "",
      note: rowNode.querySelector("[data-parcel-batch-field='note']")?.value?.trim?.() || "",
    };
  });
  parcelBatchRowState = rows.length ? rows : [emptyParcelBatchRow()];
  return parcelBatchRowState;
}

function supplierOptionsHtml(selectedValue = "", { bilingual = false, includeNew = true } = {}) {
  const options = ['<option value="">请先选择供应商</option>'];
  const names = supplierDirectoryState.map((row) => row.name);
  if (selectedValue && selectedValue !== "__new__" && !names.includes(selectedValue)) {
    options.push(`<option value="${escapeHtml(selectedValue)}" selected>${escapeHtml(selectedValue)}</option>`);
  }
  options.push(
    ...supplierDirectoryState.map((row) => {
      const optionLabel = getSupplierDisplayLabel(row.name, { bilingual, includeCode: true });
      return `<option value="${escapeHtml(row.name)}"${row.name === selectedValue ? " selected" : ""}>${escapeHtml(optionLabel)}</option>`;
    }),
  );
  if (includeNew) {
    options.push(`<option value="__new__"${selectedValue === "__new__" ? " selected" : ""}>+ 当前页新建供应商</option>`);
  }
  return options.join("");
}

function categoryMainOptionsHtml(selectedValue = "", { includeNew = false, supplierName = "", bilingual = false } = {}) {
  const hasSupplierScope = Boolean(String(supplierName || "").trim());
  const categoryTree = hasSupplierScope ? getSupplierScopedCategoryTree(supplierName) : getChinaSourceCategoryTree();
  const categoryMains = Object.keys(categoryTree);
  const options = [`<option value="">${hasSupplierScope ? "请选择当前供应商的大类" : "请选择商品大类"}</option>`];
  if (selectedValue && selectedValue !== "__new__" && !categoryMains.includes(selectedValue)) {
    options.push(`<option value="${escapeHtml(selectedValue)}" selected>${escapeHtml(selectedValue)}</option>`);
  }
  options.push(
    ...categoryMains.map((key) => {
      const optionLabel = getCategoryMainDisplayLabel(key, { supplierName, bilingual });
      return `<option value="${escapeHtml(key)}"${key === selectedValue ? " selected" : ""}>${escapeHtml(optionLabel)}</option>`;
    }),
  );
  if (includeNew) {
    options.push(`<option value="__new__"${selectedValue === "__new__" ? " selected" : ""}>+ 当前页新建品类</option>`);
  }
  return options.join("");
}

function categorySubOptionsHtml(mainCategory = "", selectedValue = "", { supplierName = "", bilingual = false } = {}) {
  const hasSupplierScope = Boolean(String(supplierName || "").trim());
  const categoryTree = hasSupplierScope ? getSupplierScopedCategoryTree(supplierName) : getChinaSourceCategoryTree();
  const placeholder = !mainCategory || mainCategory === "__new__"
    ? (hasSupplierScope ? "请先选择当前供应商的大类" : "请选择商品小类")
    : "请选择商品小类";
  const options = [`<option value="">${placeholder}</option>`];
  const categorySubs = categoryTree[mainCategory] || [];
  if (selectedValue && !categorySubs.includes(selectedValue)) {
    options.push(`<option value="${escapeHtml(selectedValue)}" selected>${escapeHtml(selectedValue)}</option>`);
  }
  categorySubs.forEach((value) => {
    const optionLabel = getCategorySubDisplayLabel(mainCategory, value, { supplierName, bilingual });
    options.push(`<option value="${escapeHtml(value)}"${value === selectedValue ? " selected" : ""}>${escapeHtml(optionLabel)}</option>`);
  });
  return options.join("");
}

function renderParcelBatchRows() {
  const container = document.querySelector("#parcelBatchItemsBuilder");
  if (!(container instanceof HTMLElement)) {
    return;
  }
  const rows = parcelBatchRowState.length ? parcelBatchRowState : [emptyParcelBatchRow()];
  parcelBatchRowState = rows;
  const shipmentNo = normalizeShipmentNo(document.querySelector("#parcelBatchForm [name='inbound_shipment_no']")?.value || currentInboundShipmentNo);
  container.innerHTML = rows
    .map(
      (row, index) => {
        const selectedToken = row.source_bale_token || inferChinaSourceTokenForRow(shipmentNo, row);
        const sourceLine = getChinaSourceLineForShipment(shipmentNo, selectedToken);
        const supplierName = sourceLine?.supplier_name || row.supplier_name || "";
        const categoryMain = sourceLine?.category_main || row.category_main || "";
        const categorySub = sourceLine?.category_sub || row.category_sub || "";
        const sourceMeta = sourceLine
          ? `${sourceLine.supplier_name || "-"} · ${sourceLine.category_main || "-"} / ${sourceLine.category_sub || "-"}`
          : "先从中方预报项里选一条，再录本地实收包数和重量。";
        const expectedMeta = sourceLine
          ? `中方预报 ${sourceLine.package_count || 0} 包 · ${sourceLine.total_weight_kg || 0} KG`
          : "还没有匹配到中方预报";
        return `
        <div class="line-builder-row" data-parcel-batch-row-index="${index}">
          <div class="line-builder-grid">
            <div class="line-builder-field">
              <label>中方预报项</label>
              <select data-parcel-batch-field="source_bale_token">
                ${parcelSourceOptionsHtml(shipmentNo, selectedToken)}
              </select>
            </div>
            <div class="line-builder-field">
              <label>本地实收包数</label>
              <input type="number" min="1" step="1" data-parcel-batch-field="package_count" value="${escapeHtml(row.package_count || "")}" />
            </div>
            <div class="line-builder-field">
              <label>本地单包 KG</label>
              <input type="number" min="0" step="0.01" data-parcel-batch-field="total_weight" value="${escapeHtml(row.total_weight || "")}" />
            </div>
            <div class="line-builder-field" style="grid-column: 1 / -1;">
              <label>已选预报项</label>
              <div class="selected-bale-row">
                <div class="selected-bale-body">
                  <strong>${escapeHtml(sourceMeta)}</strong>
                  <div class="subtle small">${escapeHtml(expectedMeta)}</div>
                </div>
              </div>
            </div>
            <div class="line-builder-field" style="grid-column: 1 / -1;">
              <label>备注</label>
              <input type="text" data-parcel-batch-field="note" value="${escapeHtml(row.note || "")}" placeholder="例如 这一批原始包裹入仓，等待分拣" />
            </div>
            <input type="hidden" data-parcel-batch-field="supplier_name_hidden" value="${escapeHtml(supplierName)}" />
            <input type="hidden" data-parcel-batch-field="category_main_hidden" value="${escapeHtml(categoryMain)}" />
            <input type="hidden" data-parcel-batch-field="category_sub_hidden" value="${escapeHtml(categorySub)}" />
          </div>
          <button type="button" class="ghost-button mini-button line-builder-remove" data-parcel-batch-remove="${index}">删除这一行</button>
        </div>
      `;
      },
    )
    .join("");
}

function applySupplierSelectionToParcelBatchRows(supplierName) {
  syncParcelBatchRowsFromDom();
  const targetRow = parcelBatchRowState.find((row) => !row.supplier_name || row.supplier_name === "__new__");
  if (targetRow) {
    targetRow.supplier_name = supplierName;
  } else {
    parcelBatchRowState[parcelBatchRowState.length - 1].supplier_name = supplierName;
  }
  renderParcelBatchRows();
}

function applyCargoTypeSelectionToParcelBatchRows(cargoTypeName) {
  syncParcelBatchRowsFromDom();
  const targetRow = parcelBatchRowState.find((row) => !row.cargo_type || row.cargo_type === "__new__");
  if (targetRow) {
    targetRow.cargo_type = cargoTypeName;
  } else {
    parcelBatchRowState[parcelBatchRowState.length - 1].cargo_type = cargoTypeName;
  }
  renderParcelBatchRows();
}

function renderStoreResultSummary(kind, data) {
  const target = document.querySelector("#storeResultSummary");
  if (!target) {
    return;
  }
  if (!kind) {
    target.className = "candidate-summary empty-state";
    target.textContent = "这里会显示门店创建结果，以及当前系统里有多少家门店。";
    return;
  }
  const rows = Array.isArray(data) ? data : [data].filter(Boolean);
  if (kind === "list") {
    const activeCount = rows.filter((row) => row.status === "active").length;
    target.className = "report-summary";
    target.innerHTML = `
      <div class="alert-banner">当前门店清单已经读取完成。</div>
      <div class="report-summary-grid">
        <article class="store-metric"><strong>总门店数</strong><span>${rows.length}</span></article>
        <article class="store-metric"><strong>在营门店</strong><span>${activeCount}</span></article>
        <article class="store-metric"><strong>示例门店</strong><span>${escapeHtml(rows[0]?.name || rows[0]?.code || "-")}</span></article>
        <article class="store-metric"><strong>地图链接</strong><span>${rows[0]?.google_maps_url ? "已配置" : "待配置"}</span></article>
      </div>
    `;
    return;
  }
  target.className = "report-summary";
  target.innerHTML = `
    <div class="alert-banner">新门店已经创建成功。</div>
    <div class="report-summary-grid">
      <article class="store-metric"><strong>门店代码</strong><span>${escapeHtml(data.code || "-")}</span></article>
      <article class="store-metric"><strong>门店名称</strong><span>${escapeHtml(data.name || "-")}</span></article>
      <article class="store-metric"><strong>状态</strong><span>${escapeHtml(data.status || "-")}</span></article>
      <article class="store-metric"><strong>地址</strong><span>${escapeHtml(data.address || "-")}</span></article>
      <article class="store-metric"><strong>商圈</strong><span>${escapeHtml(data.catchment_area || "-")}</span></article>
      <article class="store-metric"><strong>地图</strong><span>${data.google_maps_url ? `<a href="${escapeHtml(data.google_maps_url)}" target="_blank" rel="noreferrer">打开地图</a>` : "-"}</span></article>
    </div>
  `;
}

