function renderWarehouseMainflowDemoToolSummary(
  result = safeParse(localStorage.getItem(STORAGE_KEYS.latestWarehouseMainflowDemo), null),
) {
  const target = document.querySelector("#warehouseMainflowDemoSummary");
  if (!(target instanceof HTMLElement)) {
    return;
  }
  const template = warehouseMainflowDemoFlow.DEFAULT_WAREHOUSE_MAINFLOW_DEMO_TEMPLATE || {};
  if (!result || typeof result !== "object") {
    const categoryLabels = Array.isArray(template.categories)
      ? template.categories.map((row) => `${row.sourceCategorySub} ${row.packageCount} 包`).join("，")
      : "";
    target.className = "candidate-summary empty-state";
    target.textContent = `固定模板：Youxun 大船单，${template.perBaleWeightKg || 50} KG / 包，${categoryLabels}；自动推进到“一半已分拣”，但不会真实打印入仓 barcode。`;
    return;
  }
  const summaryBuilder = warehouseMainflowDemoFlow.buildWarehouseMainflowDemoSummary || (() => ({
    metrics: [],
    taskCount: 0,
    categories: [],
  }));
  const summary = summaryBuilder(result);
  target.className = "report-summary";
  target.innerHTML = `
    <div class="alert-banner">${escapeHtml(result.message || "仓库主分拣 demo 已生成。")}</div>
    <div class="report-summary-grid">
      ${summary.metrics
        .map(
          (row) => `
            <article class="store-metric"><strong>${escapeHtml(row.label || "-")}</strong><span>${escapeHtml(row.value ?? "-")}</span></article>
          `,
        )
        .join("")}
      <article class="store-metric"><strong>路费成本</strong><span>${escapeHtml(formatKesAmount(result.route_cost_kes || 0, "KES 0.00"))}</span></article>
      <article class="store-metric"><strong>分拣任务</strong><span>${escapeHtml(summary.taskCount || 0)}</span></article>
    </div>
    <div class="subtle small">来源池：${escapeHtml(result.source_pool_token || "-")} · 关单：${escapeHtml(result.customs_notice_no || "-")} · 本次没有生成真实打印任务。</div>
    <div class="candidate-list">
      ${summary.categories
        .map(
          (row) => `
            <article class="candidate-row">
              <div class="candidate-main">
                <strong>${escapeHtml(row.source_category_sub || "-")}</strong>
                <div class="subtle small">${escapeHtml(`${row.package_count || 0} 包 · 已分拣 ${row.sorted_bales || 0} 包 · 现有 bales ${row.remaining_raw_bales || 0} 包`)}</div>
                <div class="subtle small">${escapeHtml(`分拣去向：${row.sorting_category_name || "-"}`)}</div>
              </div>
            </article>
          `,
        )
        .join("")}
    </div>
  `;
}

function renderStoreReplenishmentDemoSummary(
  result = safeParse(localStorage.getItem(STORAGE_KEYS.latestStoreReplenishmentDemo), null),
) {
  const target = document.querySelector("#storeReplenishmentDemoSummary");
  if (!(target instanceof HTMLElement)) {
    return;
  }
  const template = warehouseMainflowDemoFlow.DEFAULT_STORE_REPLENISHMENT_DEMO_TEMPLATE || {};
  if (!result || typeof result !== "object") {
    target.className = "candidate-summary empty-state";
    target.textContent = `固定模板：1 个船单、${template.categoryCount || 10} 个大类、仓库 ${template.warehouseTargetQty || 20000} 件、门店 ${template.storeSeedQty || 3000} 件、最近 14 天销量 ${template.recent14dSalesQty || 2100} 件；其中 ${Math.round(Number(template.waitingStoreDispatchRatio || 0.3) * 100)}% 会压成 ${template.waitingStoreDispatchBaleQty || 100} 件 / 包的待送店 bale。`;
    return;
  }
  const summaryBuilder = warehouseMainflowDemoFlow.buildStoreReplenishmentDemoSummary || (() => ({
    metrics: [],
    recommendationItemCount: 0,
    waitingStoreDispatchBaleCount: 0,
    categories: [],
  }));
  const summary = summaryBuilder(result);
  target.className = "report-summary";
  target.innerHTML = `
    <div class="alert-banner">${escapeHtml(result.message || "门店补货 demo 已生成。")}</div>
    <div class="report-summary-grid">
      ${summary.metrics
        .map(
          (row) => `
            <article class="store-metric"><strong>${escapeHtml(row.label || "-")}</strong><span>${escapeHtml(row.value ?? "-")}</span></article>
          `,
        )
        .join("")}
      <article class="store-metric"><strong>建议行数</strong><span>${escapeHtml(summary.recommendationItemCount || 0)}</span></article>
      <article class="store-metric"><strong>待送店包</strong><span>${escapeHtml(summary.waitingStoreDispatchBaleCount || 0)} 包</span></article>
    </div>
    <div class="subtle small">同一船单已走完主分拣、待送店压包、门店上架 identity 和 14 天销售；当前停在“补货建议已生成，调拨单未创建”。</div>
    <div class="candidate-list">
      ${summary.categories
        .map(
          (row) => `
            <article class="candidate-row">
              <div class="candidate-main">
                <strong>${escapeHtml([row.category_main, row.category_sub].filter(Boolean).join(" / ") || "-")}</strong>
                <div class="subtle small">${escapeHtml(`生成 ${row.total_generated_qty || 0} 件 · 在店 ${row.store_seed_qty || 0} 件 · 14天销量 ${row.recent_14d_sales_qty || 0} 件`)}</div>
                <div class="subtle small">${escapeHtml(`仓库散货 ${row.warehouse_loose_qty || 0} 件 · 待送店 ${row.waiting_store_dispatch_qty || 0} 件 · ${row.waiting_store_dispatch_bale_count || 0} 包`)}</div>
              </div>
            </article>
          `,
        )
        .join("")}
    </div>
    ${renderSummaryActions([
      { panelKey: getPanelKeyByTitle("warehouse", "4. 门店补货建议"), label: "直接去补货建议" },
      { panelKey: getPanelKeyByTitle("warehouse", "4.1 手动生成配货单"), label: "去手动配货" },
    ])}
  `;
}

async function generateWarehouseMainflowDemo() {
  const result = await request("/system/generate-warehouse-mainflow-demo", { method: "POST" });
  localStorage.setItem(STORAGE_KEYS.latestWarehouseMainflowDemo, JSON.stringify(result));
  writeOutput("#warehouseMainflowDemoOutput", result);
  renderWarehouseMainflowDemoToolSummary(result);
  try {
    await Promise.all([
      request("/warehouse/inbound-shipments").then((rows) => {
        inboundShipmentState = Array.isArray(rows) ? rows : [];
        renderInboundShipmentHistorySummary(inboundShipmentState);
      }),
      syncSortingFlowSnapshot(result.shipment_no || ""),
    ]);
  } catch (error) {
    console.warn("warehouse mainflow demo refresh failed", error);
  }
  focusElement("#warehouseMainflowDemoSummary");
}

async function generateStoreReplenishmentDemo() {
  const result = await request("/system/generate-store-replenishment-demo", { method: "POST" });
  storeReplenishmentDemoState = result;
  localStorage.setItem(STORAGE_KEYS.latestStoreReplenishmentDemo, JSON.stringify(result));
  renderStoreReplenishmentDemoSummary(result);
  writeOutput("#storeReplenishmentDemoOutput", result);
  applyStoreContext(result.store_code || "UTAWALA");
  setInputValue("#recommendationForm [name='to_store_code']", result.store_code || "UTAWALA");
  setInputValue("#transferForm [name='to_store_code']", result.store_code || "UTAWALA");
  setInputValue("#storeRetailSeedForm [name='store_code']", result.store_code || "UTAWALA");
  setInputValue("#storeRecentSalesSimulationForm [name='store_code']", result.store_code || "UTAWALA");
  await loadDashboard();
  focusElement("#storeReplenishmentDemoSummary");
}

