function summarizePreviewFields(row) {
  if (!row || typeof row !== "object") {
    return [];
  }
  const preferred = [
    "product_name",
    "barcode",
    "store_code",
    "warehouse_code",
    "transfer_no",
    "session_no",
    "return_no",
    "order_no",
    "shift_no",
    "status",
    "qty_on_hand",
    "requested_qty",
    "received_qty",
    "total_amount",
    "total_profit",
    "rack_code",
    "store_rack_code",
    "created_at",
  ];
  return preferred
    .filter((key) => row[key] !== undefined && row[key] !== "" && !Array.isArray(row[key]) && typeof row[key] !== "object")
    .slice(0, 5)
    .map((key) => `<div class="meta"><strong>${escapeHtml(key)}</strong>：${escapeHtml(row[key])}</div>`)
    .join("");
}

function renderTableSummary(kind, data) {
  const summaryTarget = document.querySelector("#tableSummary");
  const previewTarget = document.querySelector("#tablePreview");
  if (!summaryTarget || !previewTarget) {
    return;
  }
  if (!kind) {
    summaryTarget.className = "candidate-summary empty-state";
    summaryTarget.textContent = "点上面的按钮后，这里会告诉你当前看的是什么数据，以及一共有多少条。";
    previewTarget.innerHTML = "";
    return;
  }
  const label = LIVE_DATA_LABELS[kind] || kind;
  const rows = Array.isArray(data) ? data : [data].filter(Boolean);
  summaryTarget.className = rows.length ? "report-summary" : "candidate-summary empty-state";
  summaryTarget.innerHTML = rows.length
    ? `
      <div class="alert-banner">当前正在查看：${escapeHtml(label)}。</div>
      <div class="report-summary-grid">
        <article class="store-metric"><strong>记录数</strong><span>${rows.length}</span></article>
        <article class="store-metric"><strong>第一条主键</strong><span>${escapeHtml(rows[0].barcode || rows[0].order_no || rows[0].transfer_no || rows[0].return_no || rows[0].session_no || rows[0].shift_no || rows[0].id || "-")}</span></article>
      </div>
    `
    : `当前没有可显示的 ${label}。`;
  previewTarget.innerHTML = rows.length
    ? rows.slice(0, 6).map((row, index) => `
      <article class="data-preview-card">
        <strong>${escapeHtml(row.product_name || row.order_no || row.transfer_no || row.return_no || row.session_no || row.shift_no || row.barcode || `${label} #${index + 1}`)}</strong>
        ${summarizePreviewFields(row)}
      </article>
    `).join("")
    : "";
}

function getLocalDateKey(isoString) {
  if (!isoString) {
    return "";
  }
  return new Intl.DateTimeFormat("en-CA", {
    timeZone: "Africa/Nairobi",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).format(new Date(isoString));
}

function formatLocalDateTime(isoString) {
  if (!isoString) {
    return "";
  }
  return new Intl.DateTimeFormat("zh-CN", {
    timeZone: "Africa/Nairobi",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
  }).format(new Date(isoString));
}

function priceAlertLabel(eventType) {
  if (eventType === "sale.price_policy_breach") {
    return "超限价成交";
  }
  if (eventType === "sale.price_override_alert") {
    return "改价成交";
  }
  return eventType;
}

function renderPriceAlerts(rows) {
  priceAlertState = Array.isArray(rows) ? rows : [];
  const summaryTarget = document.querySelector("#priceAlertSummary");
  const listTarget = document.querySelector("#priceAlertList");
  const todayKey = getLocalDateKey(new Date().toISOString());
  const todayRows = priceAlertState.filter((row) => getLocalDateKey(row.created_at) === todayKey);
  const breachCount = priceAlertState.filter((row) => row.event_type === "sale.price_policy_breach").length;
  const overrideCount = priceAlertState.filter((row) => row.event_type === "sale.price_override_alert").length;

  if (!priceAlertState.length) {
    summaryTarget.className = "alert-summary empty-state";
    summaryTarget.textContent = "当前还没有红色价格预警。";
    listTarget.innerHTML = "";
    return;
  }

  summaryTarget.className = "alert-summary";
  summaryTarget.innerHTML = `
    <div class="alert-banner">今天如果出现收银改价或超限价成交，这里会第一时间亮红提醒。</div>
    <div class="alert-summary-grid">
      <article class="alert-stat">
        <strong>全部红色预警</strong>
        <span>${priceAlertState.length}</span>
      </article>
      <article class="alert-stat">
        <strong>今日发生</strong>
        <span>${todayRows.length}</span>
      </article>
      <article class="alert-stat">
        <strong>超限价</strong>
        <span>${breachCount}</span>
      </article>
      <article class="alert-stat">
        <strong>人工改价</strong>
        <span>${overrideCount}</span>
      </article>
    </div>
  `;

  listTarget.innerHTML = priceAlertState
    .map((row) => {
      const details = row.details || {};
      const chips = [];
      if (details.barcode) chips.push(`<span class="chip">barcode ${escapeHtml(details.barcode)}</span>`);
      if (details.store_code) chips.push(`<span class="chip">门店 ${escapeHtml(details.store_code)}</span>`);
      if (details.shift_no) chips.push(`<span class="chip">班次 ${escapeHtml(details.shift_no)}</span>`);
      if (details.selling_price != null) chips.push(`<span class="chip">成交 ${escapeHtml(details.selling_price)}</span>`);
      if (details.expected_price != null) chips.push(`<span class="chip">建议 ${escapeHtml(details.expected_price)}</span>`);
      if (details.price_cap != null) chips.push(`<span class="chip">限价 ${escapeHtml(details.price_cap)}</span>`);
      if (details.override_reason) chips.push(`<span class="chip">原因 ${escapeHtml(details.override_reason)}</span>`);
      return `
        <article class="alert-item">
          <div class="alert-item-head">
            <div>
              <div class="alert-item-title">${escapeHtml(priceAlertLabel(row.event_type))}</div>
              <p class="alert-item-summary">${escapeHtml(row.summary)}</p>
            </div>
            <div class="alert-item-time">${escapeHtml(formatLocalDateTime(row.created_at))}</div>
          </div>
          <div class="meta-row">
            <span class="meta-pill">操作人 ${escapeHtml(row.actor || "-")}</span>
            <span class="meta-pill">单据 ${escapeHtml(row.entity_id || "-")}</span>
          </div>
          <div class="chip-row">${chips.join("")}</div>
        </article>
      `;
    })
    .join("");
}

function getReturnSelectionMode() {
  return (
    document.querySelector("input[name='selection_mode']:checked")?.value ||
    "all"
  );
}

function syncReturnSelectionSummary() {
  const summaryTarget = document.querySelector("#returnCandidateSummary");
  if (!returnCandidatesState.length) {
    summaryTarget.className = "candidate-summary empty-state";
    summaryTarget.textContent = "先读取门店可退清单，再勾选要退的商品。";
    return;
  }

  const selectedRows = returnCandidatesState.filter((row) => selectedReturnBarcodes.has(row.barcode));
  const totalQty = returnCandidatesState.reduce((sum, row) => sum + Number(row.qty_on_hand || 0), 0);
  const selectedQty = selectedRows.reduce((sum, row) => sum + Number(row.qty_on_hand || 0), 0);
  const modeLabel = getReturnSelectionMode() === "all" ? "整店退仓模式" : "部分退仓模式";

  summaryTarget.className = "candidate-summary";
  summaryTarget.innerHTML = `
    <div class="candidate-summary-grid">
      <article class="candidate-stat">
        <strong>当前门店 SKU</strong>
        <span>${returnCandidatesState.length}</span>
      </article>
      <article class="candidate-stat">
        <strong>当前门店件数</strong>
        <span>${totalQty}</span>
      </article>
      <article class="candidate-stat">
        <strong>已勾选 SKU</strong>
        <span>${selectedRows.length}</span>
      </article>
      <article class="candidate-stat">
        <strong>已勾选件数</strong>
        <span>${selectedQty}</span>
      </article>
    </div>
    <div class="subtle">${modeLabel}：${
      getReturnSelectionMode() === "all"
        ? "默认全部退回，你只需要取消不想退的商品。"
        : "只勾选这次要退回仓库的商品。"
    }</div>
  `;
}

function renderReturnCandidates(rows) {
  returnCandidatesState = Array.isArray(rows) ? rows : [];
  const listTarget = document.querySelector("#returnCandidateList");
  if (!returnCandidatesState.length) {
    listTarget.innerHTML = "";
    selectedReturnBarcodes = new Set();
    syncReturnSelectionSummary();
    return;
  }

  if (getReturnSelectionMode() === "all" && selectedReturnBarcodes.size === 0) {
    selectedReturnBarcodes = new Set(returnCandidatesState.map((row) => row.barcode));
  } else {
    selectedReturnBarcodes = new Set(
      [...selectedReturnBarcodes].filter((barcode) =>
        returnCandidatesState.some((row) => row.barcode === barcode),
      ),
    );
  }

  listTarget.innerHTML = returnCandidatesState
    .map((row) => {
      const checked = selectedReturnBarcodes.has(row.barcode) ? "checked" : "";
      return `
        <label class="candidate-item">
          <input type="checkbox" data-return-barcode="${escapeHtml(row.barcode)}" ${checked} />
          <div>
            <div class="candidate-head">
              <div class="candidate-title">${escapeHtml(row.product_name)}</div>
              <div class="candidate-qty">${escapeHtml(row.qty_on_hand)} 件</div>
            </div>
            <div class="meta-row">
              <span class="meta-pill">${escapeHtml(row.barcode)}</span>
              <span class="meta-pill">${escapeHtml(row.category_main)} / ${escapeHtml(row.category_sub)}</span>
              <span class="meta-pill">货架 ${escapeHtml(row.store_rack_code || "未记录")}</span>
            </div>
            <div class="button-row" style="margin-top: 8px;">
              <button type="button" class="ghost-button mini-button" data-open-item-identity="${escapeHtml(row.barcode)}">查看身份证台账</button>
            </div>
          </div>
        </label>
      `;
    })
    .join("");

  syncReturnSelectionSummary();
}

function updateReturnSelectionFromDom() {
  const selected = [...document.querySelectorAll("[data-return-barcode]:checked")].map(
    (input) => input.dataset.returnBarcode,
  );
  selectedReturnBarcodes = new Set(selected);
  syncReturnSelectionSummary();
}

function setAllReturnSelections(checked) {
  document.querySelectorAll("[data-return-barcode]").forEach((input) => {
    input.checked = checked;
  });
  updateReturnSelectionFromDom();
}

function parseJsonField(text, fallback) {
  const trimmed = text.trim();
  if (!trimmed) {
    return fallback;
  }
  return JSON.parse(trimmed);
}

function setSession(session) {
  currentSession = {
    token: session.access_token,
    user: session.user,
  };
  localStorage.setItem(STORAGE_KEYS.token, session.access_token);
  localStorage.setItem(STORAGE_KEYS.user, JSON.stringify(session.user));
  renderSessionState();
  applyUserDefaultLanding(session.user, { force: true });
}

function clearSession(message = "Not signed in.") {
  currentSession = { token: "", user: null };
  cashierTerminalPrimedStoreCode = "";
  cashierTerminalState = createCashierTerminalState();
  clearSortingTaskLockedShipment();
  localStorage.removeItem(STORAGE_KEYS.token);
  localStorage.removeItem(STORAGE_KEYS.user);
  document.body.classList.remove("cashier-terminal-mode");
  appShell?.classList.remove("cashier-terminal-mode");
  if (sessionSummary) {
    sessionSummary.textContent = "未登录";
  }
  if (appSessionMeta) {
    appSessionMeta.className = "session-meta-inline";
    appSessionMeta.textContent = "登录后显示角色和默认门店";
  }
  workspacePanels.classList.add("locked");
  logoutButton.disabled = true;
  authPage?.classList.remove("hidden-screen");
  appShell?.classList.add("hidden-screen");
  window.scrollTo({ top: 0, behavior: "auto" });
  renderAuthResultSummary("logout");
  renderCashierTerminal();
}

function renderSessionState() {
  if (!currentSession.user) {
    clearSession();
    return;
  }

  const storeText = currentSession.user.store_code ? ` / ${currentSession.user.store_code}` : "";
  if (sessionSummary) {
    sessionSummary.textContent = `${currentSession.user.full_name} · ${currentSession.user.username}`;
  }
  if (appSessionMeta) {
    appSessionMeta.className = "session-meta-inline";
    appSessionMeta.textContent = `角色：${currentSession.user.role_code || "-"}${storeText || " / 全局账号"}`;
  }
  workspacePanels.classList.remove("locked");
  logoutButton.disabled = false;
  authPage?.classList.add("hidden-screen");
  appShell?.classList.remove("hidden-screen");
  writeOutput("#authOutput", {
    signed_in_as: currentSession.user.username,
    role: currentSession.user.role_code,
    store_code: currentSession.user.store_code || null,
  });
  setActiveWorkspace(activeWorkspace);
  renderAuthResultSummary("login", { user: currentSession.user });
  hydrateStoreDefaults();
  applyUserDefaultLanding(currentSession.user);
  autoLoadRoleHome(currentSession.user);
  syncCashierTerminalMode();
  syncCashierTerminalDraftsFromForms();
  renderCashierTerminal();
  primeCashierTerminalSession().catch(() => {});
  applyPendingTestHomeTarget();
  window.scrollTo({ top: 0, behavior: "auto" });
}

function hydrateStoreDefaults() {
  const storeCode = currentSession.user?.store_code;
  if (!storeCode) {
    return;
  }

  [
    "#transferForm [name='to_store_code']",
    "#priceRuleForm [name='store_code']",
    "#returnCandidateForm [name='store_code']",
    "#returnSelectionForm [name='from_store_code']",
    "#returnForm [name='from_store_code']",
    "#initRackForm [name='store_code']",
    "#assignRackForm [name='store_code']",
    "#lookupForm [name='store_code']",
    "#saleForm [name='store_code']",
    "#openShiftForm [name='store_code']",
    "#userForm [name='store_code']",
  ].forEach((selector) => {
    const input = document.querySelector(selector);
    if (input && !input.value.trim()) {
      input.value = storeCode;
    }
  });
}

function createCashierTerminalPaymentLine(method = "cash") {
  return {
    method,
    amount: "",
    reference: "",
    customer_id: "",
  };
}

function createCashierTerminalState() {
  return {
    currentLookupResult: null,
    cartItems: [],
    activePaymentMode: "cash",
    paymentLines: [createCashierTerminalPaymentLine("cash"), createCashierTerminalPaymentLine("mpesa")],
    latestCompletedSale: null,
    activeDrawer: "",
    locale: "zh",
    networkStatus: navigator.onLine ? "online" : "offline",
    printerStatus: "placeholder",
    shiftNo: "",
    shiftStatus: "not_opened",
    shiftOpen: false,
    currentTime: "",
    note: "正常销售",
    cashReceived: "",
    mpesaAmount: "",
    mpesaReference: "",
    openingFloatCash: "1000",
    openingNote: "早班开始",
    voidOrderNo: "",
    voidReason: "顾客临时不要，撤销本单",
    voidNote: "收银纠错，等待店长审核",
    refundOrderNo: "",
    refundBarcode: "",
    refundQty: "1",
    refundReason: "顾客尺码不合适，申请退款",
    refundMethod: "cash",
    refundNote: "顾客已带商品回店，等待店长审核",
    anomalyNo: "",
    anomalyAction: "collect_balance",
    anomalyAmount: "",
    anomalyOrderNo: "",
    anomalyStoreCode: "",
    anomalyPaymentMethod: "cash",
    anomalyReference: "",
    anomalyCustomerId: "",
    anomalyNote: "已核实并完成处理",
  };
}

function isCashierTerminalRole(user = currentSession.user) {
  return CASHIER_ROLE_CODES.has(getNormalizedRoleCode(user));
}

function getCashierTerminalCopy() {
  return CASHIER_TERMINAL_LOCALE_COPY[cashierTerminalState.locale] || CASHIER_TERMINAL_LOCALE_COPY.zh;
}

function cashierTerminalText(key) {
  const copy = getCashierTerminalCopy();
  return copy[key] ?? key;
}

function getCashierTerminalSalesPanelKey() {
  return getPanelKeyByTitle("store", "9. 收银销售");
}

function isCashierTerminalPanelActive() {
  return Boolean(getCashierTerminalSalesPanelKey()) && activePanelKey === getCashierTerminalSalesPanelKey();
}

function getCashierTerminalStoreCode() {
  return getCurrentStoreCodeFallback();
}

function updateCashierTerminalClock() {
  cashierTerminalState.currentTime = new Date().toLocaleString(
    cashierTerminalState.locale === "en" ? "en-US" : "zh-CN",
    {
      hour12: false,
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
    },
  );
  renderCashierTerminalStatusBar();
}

function ensureCashierTerminalClock() {
  if (cashierTerminalClockTimer !== null) {
    return;
  }
  updateCashierTerminalClock();
  cashierTerminalClockTimer = window.setInterval(updateCashierTerminalClock, 1000);
}

function formatCashierTerminalShiftStatus(status) {
  const normalized = String(status || "").trim().toLowerCase();
  if (!normalized || normalized === "not_opened") {
    return getCashierTerminalCopy().noShift;
  }
  if (["open", "opened", "active", "approved"].includes(normalized)) {
    return getCashierTerminalCopy().openShift;
  }
  if (normalized === "pending_review") {
    return getCashierTerminalCopy().pendingShift;
  }
  if (normalized === "closed") {
    return getCashierTerminalCopy().closedShift;
  }
  return status;
}

function syncCashierTerminalMode() {
  const enabled = Boolean(currentSession.user) && isCashierTerminalRole();
  document.body.classList.toggle("cashier-terminal-mode", enabled);
  appShell?.classList.toggle("cashier-terminal-mode", enabled);
  if (!enabled) {
    return;
  }
  ensureCashierTerminalClock();
  renderCashierTerminal();
}

function focusCashierTerminalScanInput({ select = true } = {}) {
  if (!isCashierTerminalRole() || !isCashierTerminalPanelActive() || !(cashierTerminalBarcodeInput instanceof HTMLInputElement)) {
    return;
  }
  window.setTimeout(() => {
    cashierTerminalBarcodeInput.focus();
    if (select) {
      cashierTerminalBarcodeInput.select();
    }
  }, 0);
}

function normalizeCashierTerminalNumber(value) {
  const numeric = Number(value || 0);
  if (!Number.isFinite(numeric)) {
    return 0;
  }
  return Math.max(numeric, 0);
}

function getCashierTerminalTotals() {
  const rows = Array.isArray(cashierTerminalState.cartItems) ? cashierTerminalState.cartItems : [];
  return rows.reduce(
    (summary, row) => {
      const qty = Math.max(1, Number(row.qty || 1));
      const sellingPrice = normalizeCashierTerminalNumber(row.selling_price);
      summary.totalItems += qty;
      summary.totalAmount += qty * sellingPrice;
      return summary;
    },
    { totalItems: 0, totalAmount: 0 },
  );
}

function isCashierTerminalPriceOverride(row) {
  const sellingPrice = normalizeCashierTerminalNumber(row?.selling_price);
  const expectedPrice = normalizeCashierTerminalNumber(row?.expected_price);
  return Math.abs(sellingPrice - expectedPrice) > 0.0001;
}

function getCashierTerminalNormalizedPaymentLines({ strict = false } = {}) {
  const totalAmount = getCashierTerminalTotals().totalAmount;
  if (!totalAmount) {
    return [];
  }
  if (cashierTerminalState.activePaymentMode === "cash") {
    return [{ method: "cash", amount: totalAmount, reference: "", customer_id: "" }];
  }
  if (cashierTerminalState.activePaymentMode === "mpesa") {
    const amount = normalizeCashierTerminalNumber(cashierTerminalState.mpesaAmount || totalAmount);
    if (strict && amount <= 0) {
      throw new Error("请先填写 M-Pesa 金额。");
    }
    return amount ? [{ method: "mpesa", amount, reference: String(cashierTerminalState.mpesaReference || "").trim(), customer_id: "" }] : [];
  }
  const lines = (cashierTerminalState.paymentLines || [])
    .map((row) => ({
      method: String(row?.method || "cash").trim() || "cash",
      amount: normalizeCashierTerminalNumber(row?.amount),
      reference: String(row?.reference || "").trim(),
      customer_id: String(row?.customer_id || "").trim(),
    }))
    .filter((row) => row.amount > 0);
  if (strict && !lines.length) {
    throw new Error("混合支付至少要有一行付款。");
  }
  return lines;
}

function getCashierTerminalPaymentAssignedTotal() {
  return getCashierTerminalNormalizedPaymentLines().reduce((sum, row) => sum + Number(row.amount || 0), 0);
}

function getCashierTerminalPaymentBalance() {
  return getCashierTerminalTotals().totalAmount - getCashierTerminalPaymentAssignedTotal();
}

function getCashierTerminalChangeDue() {
  if (cashierTerminalState.activePaymentMode !== "cash") {
    return 0;
  }
  const totalAmount = getCashierTerminalTotals().totalAmount;
  return Math.max(normalizeCashierTerminalNumber(cashierTerminalState.cashReceived) - totalAmount, 0);
}

function buildCashierTerminalOrderNo(storeCode = getCashierTerminalStoreCode()) {
  const timestamp = new Date().toISOString().replace(/[-:.TZ]/g, "").slice(0, 14);
  return `POS-${storeCode}-${timestamp}`;
}

function clearCashierTerminalLookupInputs() {
  if (cashierTerminalBarcodeInput) {
    cashierTerminalBarcodeInput.value = "";
  }
  if (cashierTerminalManualInput) {
    cashierTerminalManualInput.value = "";
  }
}

function syncCashierTerminalDraftsFromForms() {
  cashierTerminalState.note = String(document.querySelector("#saleForm [name='note']")?.value || cashierTerminalState.note || "正常销售").trim() || "正常销售";
  cashierTerminalState.openingFloatCash = String(document.querySelector("#openShiftForm [name='opening_float_cash']")?.value || cashierTerminalState.openingFloatCash || "1000").trim() || "1000";
  cashierTerminalState.openingNote = String(document.querySelector("#openShiftForm [name='note']")?.value || cashierTerminalState.openingNote || "早班开始").trim() || "早班开始";
  cashierTerminalState.voidOrderNo = String(document.querySelector("#saleVoidRequestForm [name='order_no']")?.value || cashierTerminalState.voidOrderNo || cashierTerminalState.latestCompletedSale?.order_no || "").trim();
  cashierTerminalState.voidReason = String(document.querySelector("#saleVoidRequestForm [name='reason']")?.value || cashierTerminalState.voidReason || "").trim();
  cashierTerminalState.voidNote = String(document.querySelector("#saleVoidRequestForm [name='note']")?.value || cashierTerminalState.voidNote || "").trim();
  cashierTerminalState.refundOrderNo = String(document.querySelector("#saleRefundRequestForm [name='order_no']")?.value || cashierTerminalState.refundOrderNo || cashierTerminalState.latestCompletedSale?.order_no || "").trim();
  cashierTerminalState.refundReason = String(document.querySelector("#saleRefundRequestForm [name='reason']")?.value || cashierTerminalState.refundReason || "").trim();
  cashierTerminalState.refundMethod = String(document.querySelector("#saleRefundRequestForm [name='refund_method']")?.value || cashierTerminalState.refundMethod || "cash").trim() || "cash";
  cashierTerminalState.refundNote = String(document.querySelector("#saleRefundRequestForm [name='note']")?.value || cashierTerminalState.refundNote || "").trim();
  cashierTerminalState.anomalyNo = String(document.querySelector("#paymentAnomalyResolveForm [name='anomaly_no']")?.value || cashierTerminalState.anomalyNo || "").trim();
  cashierTerminalState.anomalyAction = String(document.querySelector("#paymentAnomalyResolveForm [name='action']")?.value || cashierTerminalState.anomalyAction || "collect_balance").trim() || "collect_balance";
  cashierTerminalState.anomalyAmount = String(document.querySelector("#paymentAnomalyResolveForm [name='amount']")?.value || cashierTerminalState.anomalyAmount || "").trim();
  cashierTerminalState.anomalyOrderNo = String(document.querySelector("#paymentAnomalyResolveForm [name='order_no']")?.value || cashierTerminalState.anomalyOrderNo || "").trim();
  cashierTerminalState.anomalyStoreCode = String(document.querySelector("#paymentAnomalyResolveForm [name='store_code']")?.value || cashierTerminalState.anomalyStoreCode || getCashierTerminalStoreCode()).trim() || getCashierTerminalStoreCode();
  cashierTerminalState.anomalyPaymentMethod = String(document.querySelector("#paymentAnomalyResolveForm [name='payment_method']")?.value || cashierTerminalState.anomalyPaymentMethod || "cash").trim() || "cash";
  cashierTerminalState.anomalyReference = String(document.querySelector("#paymentAnomalyResolveForm [name='reference']")?.value || cashierTerminalState.anomalyReference || "").trim();
  cashierTerminalState.anomalyCustomerId = String(document.querySelector("#paymentAnomalyResolveForm [name='customer_id']")?.value || cashierTerminalState.anomalyCustomerId || "").trim();
  cashierTerminalState.anomalyNote = String(document.querySelector("#paymentAnomalyResolveForm [name='note']")?.value || cashierTerminalState.anomalyNote || "").trim();
  const refundItems = safeParse(document.querySelector("#saleRefundRequestForm [name='items_json']")?.value || "[]", []);
  const refundSeed = Array.isArray(refundItems) ? refundItems[0] || {} : {};
  cashierTerminalState.refundBarcode = String(
    refundSeed.barcode
      || cashierTerminalState.refundBarcode
      || cashierTerminalState.latestCompletedSale?.items?.[0]?.barcode
      || "",
  ).trim();
  cashierTerminalState.refundQty = String(refundSeed.qty || cashierTerminalState.refundQty || "1").trim() || "1";
  if (cashierTerminalSaleNoteInput && !cashierTerminalSaleNoteInput.matches(":focus")) {
    cashierTerminalSaleNoteInput.value = cashierTerminalState.note;
  }
}

function syncCashierTerminalShift(shift = null) {
  const shiftNo = String(
    shift?.shift_no
      || document.querySelector("#saleForm [name='shift_no']")?.value
      || document.querySelector("#shiftReportForm [name='shift_no']")?.value
      || "",
  ).trim();
  const status = String(shift?.status || (shiftNo ? "open" : "not_opened")).trim() || "not_opened";
  cashierTerminalState.shiftNo = shiftNo;
  cashierTerminalState.shiftStatus = status;
  cashierTerminalState.shiftOpen = Boolean(shiftNo) && !["closed", "completed"].includes(status.toLowerCase());
  syncCashierTerminalDraftsFromForms();
  renderCashierTerminal();
}

async function primeCashierTerminalSession(force = false) {
  if (!currentSession.token || !isCashierTerminalRole()) {
    return;
  }
  const storeCode = getCashierTerminalStoreCode();
  if (!force && cashierTerminalPrimedStoreCode === storeCode) {
    return;
  }
  cashierTerminalPrimedStoreCode = storeCode;
  try {
    const shifts = await request("/pos/shifts");
    const rows = Array.isArray(shifts) ? shifts : [];
    const activeShift = rows.find((row) => ["open", "opened", "active", "approved"].includes(String(row?.status || "").trim().toLowerCase())) || null;
    if (activeShift?.shift_no) {
      hydrateShiftForms(activeShift);
      syncCashierTerminalShift(activeShift);
    } else {
      ["#shiftReportForm [name='shift_no']", "#handoverRequestForm [name='shift_no']", "#closeBusinessReportForm [name='shift_no']", "#saleForm [name='shift_no']"].forEach((selector) => setInputValue(selector, ""));
      syncCashierTerminalShift(null);
    }
  } catch (error) {
    renderCashierTerminal();
  }
}

function applyCashierTerminalChromeCopy() {
  if (!(cashierTerminalShell instanceof HTMLElement)) {
    return;
  }
  const copy = getCashierTerminalCopy();
  document.documentElement.lang = cashierTerminalState.locale === "en" ? "en" : "zh-CN";
  cashierTerminalShell.querySelectorAll("[data-terminal-copy]").forEach((node) => {
    const key = node.dataset.terminalCopy;
    if (key) {
      node.textContent = copy[key] ?? node.textContent;
    }
  });
  cashierTerminalShell.querySelectorAll("[data-terminal-locale]").forEach((button) => {
    button.classList.toggle("is-active", button.dataset.terminalLocale === cashierTerminalState.locale);
    const label = copy.localeButtons?.[button.dataset.terminalLocale];
    if (label) {
      button.textContent = label;
    }
  });
  if (cashierTerminalBarcodeInput) {
    cashierTerminalBarcodeInput.placeholder = copy.barcodePlaceholder;
  }
  if (cashierTerminalManualInput) {
    cashierTerminalManualInput.placeholder = copy.manualPlaceholder;
  }
  if (cashierTerminalSaleNoteInput) {
    cashierTerminalSaleNoteInput.placeholder = copy.notePlaceholder;
  }
}

