function jumpToCashierLegacyPanel(panelTitlePrefix) {
  const panelKey = getPanelKeyByTitle("store", panelTitlePrefix);
  if (!panelKey) {
    throw new Error(`没有找到页面：${panelTitlePrefix}`);
  }
  setActivePanel(panelKey);
}

function updateCashierTerminalCartField(index, field, value) {
  const row = cashierTerminalState.cartItems[index];
  if (!row) {
    return;
  }
  if (field === "qty") {
    row.qty = Math.max(1, Number(value || 1));
  } else if (field === "selling_price") {
    row.selling_price = normalizeCashierTerminalNumber(value);
  } else {
    row[field] = String(value || "");
  }
  renderCashierTerminal();
}

function updateCashierTerminalPaymentField(field, value, index = null) {
  if (index != null) {
    const line = cashierTerminalState.paymentLines[index];
    if (!line) {
      return;
    }
    line[field] = field === "amount" ? String(value || "") : String(value || "");
    renderCashierTerminal();
    return;
  }
  cashierTerminalState[field] = String(value || "");
  renderCashierTerminal();
}

function updateCashierTerminalDrawerField(field, value) {
  cashierTerminalState[field] = String(value || "");
}

function handleCashierTerminalNetworkChange() {
  cashierTerminalState.networkStatus = navigator.onLine ? "online" : "offline";
  renderCashierTerminal();
}

async function handleCashierTerminalAction(action, target) {
  switch (action) {
    case "clear-lookup":
      cashierTerminalState.currentLookupResult = null;
      clearCashierTerminalLookupInputs();
      renderCashierTerminal();
      focusCashierTerminalScanInput();
      return;
    case "add-current-lookup":
      if (!cashierTerminalState.currentLookupResult) {
        throw new Error("当前还没有查到商品。");
      }
      upsertCashierTerminalCartItem(cashierTerminalState.currentLookupResult);
      showTransientInlineNotice("#cashierTerminalInlineNotice", "已加入购物篮。", "success", 1400);
      focusCashierTerminalScanInput();
      return;
    case "clear-cart":
      cashierTerminalState.cartItems = [];
      renderCashierTerminal();
      focusCashierTerminalScanInput();
      return;
    case "add-payment-line":
      addCashierTerminalPaymentLine();
      return;
    case "open-drawer":
      cashierTerminalState.activeDrawer = target.dataset.terminalDrawer || "";
      renderCashierTerminal();
      return;
    case "close-drawer":
      cashierTerminalState.activeDrawer = "";
      renderCashierTerminal();
      focusCashierTerminalScanInput({ select: false });
      return;
    case "toggle-locale":
      cashierTerminalState.locale = cashierTerminalState.locale === "zh" ? "en" : "zh";
      updateCashierTerminalClock();
      renderCashierTerminal();
      return;
    case "submit-open-shift":
      await submitCashierTerminalOpenShift();
      return;
    case "load-shifts":
      await loadTable("load-shifts");
      cashierTerminalState.activeDrawer = "shift";
      renderCashierTerminal();
      return;
    case "load-shift-report": {
      if (!cashierTerminalState.shiftNo) {
        throw new Error("请先开班，再读取 T/Z-report。");
      }
      const reportKind = target.dataset.reportKind || "t";
      setInputValue("#shiftReportForm [name='shift_no']", cashierTerminalState.shiftNo);
      const form = document.querySelector("#shiftReportForm");
      if (!(form instanceof HTMLFormElement)) {
        throw new Error("shiftReportForm 不存在。");
      }
      await submitShiftReport({
        preventDefault() {},
        currentTarget: form,
        submitter: { dataset: { reportKind } },
      });
      cashierTerminalState.activeDrawer = "shift";
      renderCashierTerminal();
      return;
    }
    case "complete-sale":
      await submitCashierTerminalSale();
      return;
    case "submit-void-request":
      await submitCashierTerminalVoidRequest();
      return;
    case "submit-refund-request":
      await submitCashierTerminalRefundRequest();
      return;
    case "load-payment-anomalies":
      await loadTable("load-payment-anomalies");
      cashierTerminalState.activeDrawer = "anomaly";
      renderCashierTerminal();
      return;
    case "submit-anomaly-resolve":
      await submitCashierTerminalAnomalyResolve();
      return;
    case "jump-legacy":
      jumpToCashierLegacyPanel(target.dataset.terminalPanel || "");
      return;
    default:
      return;
  }
}

function handleCashierTerminalHotkeys(event) {
  if (!isCashierTerminalRole() || !isCashierTerminalPanelActive() || event.altKey || event.ctrlKey || event.metaKey) {
    return;
  }
  if (event.key === "F2") {
    event.preventDefault();
    setCashierTerminalPaymentMode("cash");
    return;
  }
  if (event.key === "F3") {
    event.preventDefault();
    setCashierTerminalPaymentMode("mpesa");
    return;
  }
  if (event.key === "F4") {
    event.preventDefault();
    setCashierTerminalPaymentMode("mixed");
    return;
  }
  if (event.key === "F7") {
    event.preventDefault();
    cashierTerminalState.activeDrawer = "void";
    renderCashierTerminal();
    return;
  }
  if (event.key === "F8") {
    event.preventDefault();
    submitCashierTerminalSale().catch((error) => {
      showTransientInlineNotice("#cashierTerminalInlineNotice", formatErrorMessage(error), "error", 2200);
    });
    return;
  }
  if (event.key === "F9") {
    event.preventDefault();
    cashierTerminalState.activeDrawer = "refund";
    renderCashierTerminal();
    return;
  }
  if (event.key === "Escape" && cashierTerminalState.activeDrawer) {
    event.preventDefault();
    cashierTerminalState.activeDrawer = "";
    renderCashierTerminal();
    focusCashierTerminalScanInput({ select: false });
  }
}

async function request(path, options = {}) {
  const isFormDataBody = options.body instanceof FormData;
  const headers = {
    ...(isFormDataBody ? {} : { "Content-Type": "application/json" }),
    ...(options.headers || {}),
  };
  if (currentSession.token) {
    headers.Authorization = `Bearer ${currentSession.token}`;
  }

  const response = await fetch(`${getApiBase()}${path}`, {
    ...options,
    headers,
  });

  const contentType = response.headers.get("content-type") || "";
  const data = contentType.includes("application/json")
    ? await response.json()
    : await response.text();

  if (!response.ok) {
    if (response.status === 401) {
      clearSession("Session expired. Please sign in again.");
    }
    throw new Error(extractApiErrorMessage(data) || (typeof data === "string" ? data : pretty(data)));
  }
  return data;
}

function buildQueryString(params = {}) {
  const query = new URLSearchParams();
  Object.entries(params).forEach(([key, value]) => {
    const normalized = String(value ?? "").trim();
    if (normalized) {
      query.set(key, normalized);
    }
  });
  const text = query.toString();
  return text ? `?${text}` : "";
}

async function downloadApiFile(path, fallbackFileName = "download.xlsx") {
  const headers = {};
  if (currentSession.token) {
    headers.Authorization = `Bearer ${currentSession.token}`;
  }
  const response = await fetch(`${getApiBase()}${path}`, { headers });
  if (!response.ok) {
    const contentType = response.headers.get("content-type") || "";
    const data = contentType.includes("application/json")
      ? await response.json()
      : await response.text();
    if (response.status === 401) {
      clearSession("Session expired. Please sign in again.");
    }
    throw new Error(extractApiErrorMessage(data) || (typeof data === "string" ? data : pretty(data)));
  }
  const blob = await response.blob();
  const disposition = response.headers.get("content-disposition") || "";
  const matchedName = disposition.match(/filename\*=UTF-8''([^;]+)|filename=\"?([^\";]+)\"?/i);
  const fileName = decodeURIComponent(matchedName?.[1] || matchedName?.[2] || fallbackFileName);
  const objectUrl = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = objectUrl;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(objectUrl);
}

async function resolveBarcodeForContext(barcode, context, allowedTypes = []) {
  const flow = window.barcodeResolverFlow || {};
  const normalizedBarcode = typeof flow.normalizeBarcode === "function"
    ? flow.normalizeBarcode(barcode)
    : String(barcode || "").trim().toUpperCase();
  if (!normalizedBarcode) {
    throw new Error("请先扫描或输入 barcode。");
  }
  const path = typeof flow.buildBarcodeResolvePath === "function"
    ? flow.buildBarcodeResolvePath(normalizedBarcode, context)
    : `/barcode/resolve/${encodeURIComponent(normalizedBarcode)}?context=${encodeURIComponent(context || "")}`;
  const resolved = await request(path);
  if (typeof flow.assertResolvedBarcodeContext === "function") {
    return flow.assertResolvedBarcodeContext(resolved, { context, allowedTypes });
  }
  if (resolved?.reject_reason) {
    throw new Error(resolved.reject_reason);
  }
  if (allowedTypes.length && !allowedTypes.includes(String(resolved?.barcode_type || "").trim().toUpperCase())) {
    throw new Error(`${context || "当前页面"} 不允许扫描 ${resolved?.barcode_type || "UNKNOWN"}。`);
  }
  return resolved;
}

function renderCards(cards) {
  const target = document.querySelector("#dashboardCards");
  target.innerHTML = cards
    .map(
      (card) => `
        <article class="card">
          <div class="card-label">${DASHBOARD_LABELS[card.label] || card.label}</div>
          <div class="card-value">${card.value}</div>
        </article>
      `,
    )
    .join("");
}

function renderMpesaSummary(collections = mpesaCollectionsState, insights = mpesaCustomerInsightsState) {
  const target = document.querySelector("#mpesaSummary");
  if (!target) {
    return;
  }
  const rows = Array.isArray(collections) ? collections : [];
  const insightRows = Array.isArray(insights) ? insights : [];
  if (!rows.length) {
    target.className = "candidate-summary empty-state";
    target.textContent = "这里会汇总 Safaricom / M-Pesa 的导入金额、未匹配流水和熟客数。";
    return;
  }
  const totalAmount = rows.reduce((sum, row) => sum + Number(row.amount || 0), 0);
  const matchedCount = rows.filter((row) => row.match_status === "matched").length;
  const unmatchedCount = rows.filter((row) => row.match_status === "unmatched").length;
  const duplicateCount = rows.filter((row) => row.match_status === "duplicate").length;
  const customerCount = new Set(
    rows.map((row) => String(row.customer_id || "").trim()).filter(Boolean),
  ).size;
  const topCustomer = insightRows[0];
  target.className = "candidate-summary";
  target.innerHTML = `
    <div class="candidate-summary-grid">
      <article class="candidate-stat">
        <strong>线上收款总额</strong>
        <span>${totalAmount.toFixed(2)}</span>
      </article>
      <article class="candidate-stat">
        <strong>已匹配订单</strong>
        <span>${matchedCount}</span>
      </article>
      <article class="candidate-stat">
        <strong>未匹配流水</strong>
        <span>${unmatchedCount}</span>
      </article>
      <article class="candidate-stat">
        <strong>熟客数量</strong>
        <span>${customerCount}</span>
      </article>
    </div>
    <div class="subtle">
      重复导入：${duplicateCount} 笔
      ${topCustomer ? `；最高消费熟客：${escapeHtml(topCustomer.customer_id)} / ${topCustomer.total_spent}` : ""}
    </div>
  `;
}

function renderOfflineSyncSummary(batches = offlineSyncBatchState) {
  const target = document.querySelector("#offlineSyncSummary");
  if (!target) {
    return;
  }
  const rows = Array.isArray(batches) ? batches : [];
  if (!rows.length) {
    target.className = "candidate-summary empty-state";
    target.textContent = "这里会汇总断网补同步的批次数、成功行、重复行和失败行。";
    return;
  }
  const accepted = rows.reduce((sum, row) => sum + Number(row.accepted_count || 0), 0);
  const duplicates = rows.reduce((sum, row) => sum + Number(row.duplicate_count || 0), 0);
  const failed = rows.reduce((sum, row) => sum + Number(row.failed_count || 0), 0);
  const devices = new Set(rows.map((row) => row.device_id).filter(Boolean)).size;
  target.className = "candidate-summary";
  target.innerHTML = `
    <div class="candidate-summary-grid">
      <article class="candidate-stat">
        <strong>同步批次</strong>
        <span>${rows.length}</span>
      </article>
      <article class="candidate-stat">
        <strong>成功行数</strong>
        <span>${accepted}</span>
      </article>
      <article class="candidate-stat">
        <strong>重复行数</strong>
        <span>${duplicates}</span>
      </article>
      <article class="candidate-stat">
        <strong>失败行数</strong>
        <span>${failed}</span>
      </article>
    </div>
    <div class="subtle">涉及设备：${devices} 台</div>
  `;
}

function renderOpsAlerts() {
  const summaryTarget = document.querySelector("#opsAlertSummary");
  const listTarget = document.querySelector("#opsAlertList");
  if (!summaryTarget || !listTarget) {
    return;
  }
  const unmatchedCollections = mpesaCollectionsState.filter((row) => row.match_status === "unmatched");
  const duplicateCollections = mpesaCollectionsState.filter((row) => row.match_status === "duplicate");
  const failedSyncRows = offlineSyncBatchState.flatMap((batch) =>
    (batch.results || [])
      .filter((row) => row.status === "failed")
      .map((row) => ({ ...row, sync_batch_no: batch.sync_batch_no, device_id: batch.device_id })),
  );
  const duplicateSyncRows = offlineSyncBatchState.flatMap((batch) =>
    (batch.results || [])
      .filter((row) => row.status === "duplicate")
      .map((row) => ({ ...row, sync_batch_no: batch.sync_batch_no, device_id: batch.device_id })),
  );

  if (
    !unmatchedCollections.length &&
    !duplicateCollections.length &&
    !failedSyncRows.length &&
    !duplicateSyncRows.length
  ) {
    summaryTarget.className = "alert-summary empty-state";
    summaryTarget.textContent = "当前没有线上收款或离线同步异常。";
    listTarget.innerHTML = "";
    return;
  }

  summaryTarget.className = "alert-summary";
  summaryTarget.innerHTML = `
    <div class="alert-summary-grid">
      <article class="alert-stat neutral-stat">
        <strong>未匹配 M-Pesa</strong>
        <span>${unmatchedCollections.length}</span>
      </article>
      <article class="alert-stat neutral-stat">
        <strong>重复 M-Pesa</strong>
        <span>${duplicateCollections.length}</span>
      </article>
      <article class="alert-stat neutral-stat">
        <strong>离线失败行</strong>
        <span>${failedSyncRows.length}</span>
      </article>
      <article class="alert-stat neutral-stat">
        <strong>离线重复行</strong>
        <span>${duplicateSyncRows.length}</span>
      </article>
    </div>
  `;

  const entries = [
    ...unmatchedCollections.map((row) => ({
      title: "未匹配 M-Pesa",
      summary: `收据 ${row.receipt_no} 暂时没有匹配到门店销售单。`,
      chips: [
        `门店 ${row.store_code}`,
        `金额 ${row.amount}`,
        row.customer_id ? `客户 ${row.customer_id}` : "",
        row.reference ? `参考 ${row.reference}` : "",
      ].filter(Boolean),
      time: row.collected_at,
      type: "ops",
    })),
    ...duplicateCollections.map((row) => ({
      title: "重复 M-Pesa 导入",
      summary: `收据 ${row.receipt_no} 被重复导入。`,
      chips: [`门店 ${row.store_code}`, `金额 ${row.amount}`],
      time: row.collected_at,
      type: "ops",
    })),
    ...failedSyncRows.map((row) => ({
      title: "离线销售同步失败",
      summary: row.message || `离线销售 ${row.order_no} 同步失败。`,
      chips: [
        `设备 ${row.device_id || "-"}`,
        `批次 ${row.sync_batch_no}`,
        `订单 ${row.order_no}`,
      ],
      time: "",
      type: "ops",
    })),
    ...duplicateSyncRows.map((row) => ({
      title: "离线销售重复同步",
      summary: row.message || `离线销售 ${row.order_no} 已同步过。`,
      chips: [
        `设备 ${row.device_id || "-"}`,
        `批次 ${row.sync_batch_no}`,
        `订单 ${row.order_no}`,
      ],
      time: "",
      type: "ops",
    })),
  ];

  listTarget.innerHTML = entries
    .map(
      (entry) => `
        <article class="alert-item neutral-item">
          <div class="alert-item-head">
            <div>
              <div class="alert-item-title neutral-title">${escapeHtml(entry.title)}</div>
              <p class="alert-item-summary">${escapeHtml(entry.summary)}</p>
            </div>
            <div class="alert-item-time">${escapeHtml(entry.time ? formatLocalDateTime(entry.time) : "")}</div>
          </div>
          <div class="chip-row">
            ${entry.chips.map((chip) => `<span class="chip neutral-chip">${escapeHtml(chip)}</span>`).join("")}
          </div>
        </article>
      `,
    )
    .join("");
}

function formatLocalDateTimeInput(isoString = "") {
  if (!isoString) {
    return "";
  }
  const date = new Date(isoString);
  if (Number.isNaN(date.getTime())) {
    return "";
  }
  const pad = (value) => String(value).padStart(2, "0");
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
}

function parseDateTimeInput(value = "") {
  const trimmed = String(value || "").trim();
  if (!trimmed) {
    return "";
  }
  const date = new Date(trimmed);
  return Number.isNaN(date.getTime()) ? "" : date.toISOString();
}

function buildOpsExceptionNo() {
  const today = getLocalDateKey(new Date().toISOString()).replaceAll("-", "");
  const nextIndex = ensureOpsExceptionTicketState().filter((row) => String(row?.anomaly_no || "").includes(today)).length + 1;
  return `EXC-${today}-${String(nextIndex).padStart(3, "0")}`;
}

