function getOpsExceptionSignals() {
  const paymentOpen = paymentAnomalyState.filter((row) => row.status === "open").length;
  const pendingVoids = saleVoidState.filter((row) => row.status === "pending_review").length;
  const pendingRefunds = saleRefundState.filter((row) => row.status === "pending_review").length;
  const printFailures = itemTokenPrintJobState.filter((row) => row.status === "failed").length + balePrinterJobState.filter((row) => row.status === "failed").length;
  const storeDiscrepancies = storeOperatingSummaryState.reduce((sum, row) => sum + Number(row.pending_discrepancies || 0), 0);
  const unmatchedMpesa = storeOperatingSummaryState.reduce((sum, row) => sum + Number(row.unmatched_mpesa_count || 0), 0);
  return [
    paymentOpen ? `支付异常 ${paymentOpen}` : "",
    pendingVoids ? `待作废 ${pendingVoids}` : "",
    pendingRefunds ? `待退款 ${pendingRefunds}` : "",
    printFailures ? `打印失败 ${printFailures}` : "",
    storeDiscrepancies ? `待批差异 ${storeDiscrepancies}` : "",
    unmatchedMpesa ? `未匹配 M-Pesa ${unmatchedMpesa}` : "",
  ].filter(Boolean);
}

function renderOpsExceptionDeskSummary(message = "") {
  const summaryTarget = document.querySelector("#opsExceptionDeskSummary");
  const listTarget = document.querySelector("#opsExceptionDeskList");
  if (!(summaryTarget instanceof HTMLElement) || !(listTarget instanceof HTMLElement)) {
    return;
  }
  const rows = ensureOpsExceptionTicketState();
  const { status, domain, severity } = getOpsExceptionFilters();
  const filteredRows = rows.filter((row) => (!status || row.status === status) && (!domain || row.domain === domain) && (!severity || row.severity === severity));
  const openCount = rows.filter((row) => row.status === "open").length;
  const activeCount = rows.filter((row) => row.status === "in_progress").length;
  const closedCount = rows.filter((row) => row.status === "closed").length;
  const redCount = rows.filter((row) => row.severity === "red" && row.status !== "closed").length;
  const signals = getOpsExceptionSignals();
  summaryTarget.className = "report-summary";
  summaryTarget.innerHTML = `
    <div class="flow-summary-note">${escapeHtml(message || "统一用异常单去追少件、多件、拒收、打印失败和支付类问题。现场先认领、再处理、最后带证据关闭。")}</div>
    <div class="report-summary-grid">
      <article class="store-metric"><strong>待处理</strong><span>${openCount}</span></article>
      <article class="store-metric"><strong>处理中</strong><span>${activeCount}</span></article>
      <article class="store-metric"><strong>已关闭</strong><span>${closedCount}</span></article>
      <article class="store-metric"><strong>红色未关闭</strong><span>${redCount}</span></article>
    </div>
    <div class="manager-console-flags">
      ${(signals.length ? signals : ["当前系统信号正常"]).map((label) => `<span class="store-flag ${label === "当前系统信号正常" ? "" : "danger"}">${escapeHtml(label)}</span>`).join("")}
    </div>
  `;
  if (!filteredRows.length) {
    listTarget.innerHTML = `<div class="empty-state">当前筛选下还没有异常单。</div>`;
    return;
  }
  listTarget.innerHTML = filteredRows
    .map((row) => `
      <article class="dev-task-card ${row.status === "closed" ? "is-done" : row.status === "in_progress" ? "is-current" : ""}">
        <div class="dev-task-card-head">
          <div>
            <strong>${escapeHtml(row.title || row.anomaly_no)}</strong>
            <div class="chip-row">
              <span class="meta-pill">${escapeHtml(row.anomaly_no)}</span>
              <span class="meta-pill">${escapeHtml(getOpsExceptionDomainLabel(row.domain))}</span>
              <span class="meta-pill">${escapeHtml(getOpsExceptionTypeLabel(row.anomaly_type))}</span>
              <span class="meta-pill">${escapeHtml(getOpsExceptionSeverityLabel(row.severity))}</span>
              <span class="meta-pill">${escapeHtml(getOpsExceptionStatusLabel(row.status))}</span>
            </div>
          </div>
          <div class="button-row">
            <button type="button" class="ghost-button mini-button" data-ops-exception-edit="${escapeHtml(row.anomaly_no)}">编辑</button>
            ${row.status === "open" ? `<button type="button" class="ghost-button mini-button" data-ops-exception-action="claim" data-anomaly-no="${escapeHtml(row.anomaly_no)}">认领</button>` : ""}
            ${row.status !== "closed" ? `<button type="button" class="ghost-button mini-button" data-ops-exception-action="${row.status === "in_progress" ? "close" : "start"}" data-anomaly-no="${escapeHtml(row.anomaly_no)}">${row.status === "in_progress" ? "关闭" : "开始处理"}</button>` : `<button type="button" class="ghost-button mini-button" data-ops-exception-action="reopen" data-anomaly-no="${escapeHtml(row.anomaly_no)}">重新打开</button>`}
          </div>
        </div>
        <p class="dev-task-card-detail">${escapeHtml(row.note || "待补充异常说明。")}</p>
        <div class="meta-row">
          ${row.reference_no ? `<span class="meta-pill">关联 ${escapeHtml(row.reference_no)}</span>` : ""}
          ${row.store_code ? `<span class="meta-pill">位置 ${escapeHtml(row.store_code)}</span>` : ""}
          ${row.owner_role ? `<span class="meta-pill">责任角色 ${escapeHtml(row.owner_role)}</span>` : ""}
          ${row.owner_name ? `<span class="meta-pill">责任人 ${escapeHtml(row.owner_name)}</span>` : ""}
          ${row.due_at ? `<span class="meta-pill">SLA ${escapeHtml(formatLocalDateTime(row.due_at))}</span>` : ""}
        </div>
        <div class="subtle small">创建 ${escapeHtml(formatLocalDateTime(row.created_at))}${row.acknowledged_at ? ` · 开始处理 ${escapeHtml(formatLocalDateTime(row.acknowledged_at))}` : ""}${row.closed_at ? ` · 已关闭 ${escapeHtml(formatLocalDateTime(row.closed_at))}` : ""}</div>
        ${row.resolution_note ? `<div class="subtle small">关闭证据：${escapeHtml(row.resolution_note)}</div>` : ""}
      </article>
    `)
    .join("");
}

