function renderConsignmentBundleWorkbench(message = "") {
  const summaryTarget = document.querySelector("#consignmentBundleSummary");
  const listTarget = document.querySelector("#consignmentBundleList");
  if (!(summaryTarget instanceof HTMLElement) || !(listTarget instanceof HTMLElement)) {
    return;
  }
  const rows = ensureConsignmentBundleOrderState();
  const draftCount = rows.filter((row) => row.status === "draft").length;
  const packedCount = rows.filter((row) => row.status === "packed").length;
  const settledCount = rows.filter((row) => row.status === "settled").length;
  const totalWeight = roundToTwo(rows.reduce((sum, row) => sum + Number(row.target_total_weight_kg || 0), 0));
  summaryTarget.className = "report-summary";
  summaryTarget.innerHTML = `
    <div class="flow-summary-note">${escapeHtml(message || "把 A / B 类货按比例混包、按重量结算，后面生成新的代售 bale 工单和市场售卖口径。")}</div>
    <div class="report-summary-grid">
      <article class="store-metric"><strong>草稿工单</strong><span>${draftCount}</span></article>
      <article class="store-metric"><strong>待出库</strong><span>${packedCount}</span></article>
      <article class="store-metric"><strong>已结算</strong><span>${settledCount}</span></article>
      <article class="store-metric"><strong>目标总重</strong><span>${escapeHtml(`${formatCurrency(totalWeight)} KG`)}</span></article>
    </div>
  `;
  if (!rows.length) {
    listTarget.innerHTML = `<div class="empty-state">先生成一张代售混包草稿，后面再接市场售卖和按 KG 结算。</div>`;
    return;
  }
  listTarget.innerHTML = rows.slice(0, 8).map((row) => `
    <article class="template-card oa-record-item ${row.status === "settled" ? "is-done" : row.status === "packed" ? "is-current" : ""}">
      <div class="template-card-head">
        <div>
          <strong>${escapeHtml(row.title)}</strong>
          <div class="subtle small">${escapeHtml(row.order_no)} · ${escapeHtml(getConsignmentBundleStatusLabel(row.status))}</div>
        </div>
        <div class="button-row">
          <button type="button" class="ghost-button mini-button" data-consignment-edit="${escapeHtml(row.order_no)}">编辑</button>
          ${row.status === "draft" ? `<button type="button" class="ghost-button mini-button" data-consignment-action="pack" data-order-no="${escapeHtml(row.order_no)}">标记已混包</button>` : ""}
          ${row.status === "packed" ? `<button type="button" class="ghost-button mini-button" data-consignment-action="settle" data-order-no="${escapeHtml(row.order_no)}">标记已结算</button>` : ""}
          ${row.status === "settled" ? `<button type="button" class="ghost-button mini-button" data-consignment-action="reopen" data-order-no="${escapeHtml(row.order_no)}">重新打开</button>` : ""}
        </div>
      </div>
      <div class="chip-row">
        ${row.market_channel ? `<span class="meta-pill">${escapeHtml(row.market_channel)}</span>` : ""}
        <span class="meta-pill">${escapeHtml(`${formatCurrency(row.target_total_weight_kg || 0)} KG`)}</span>
        <span class="meta-pill">${escapeHtml(`${row.expected_bale_count || 0} 包`)}</span>
        <span class="meta-pill">${escapeHtml(formatKesAmount((row.market_sell_price_per_kg_kes || 0), "KES 0.00"))}/KG</span>
      </div>
      ${row.source_type_summary ? `<div class="subtle small">来源：${escapeHtml(row.source_type_summary)}</div>` : ""}
      ${row.selected_pool_entry_ids?.length ? `<div class="subtle small">销售池 bale：${escapeHtml(`${row.selected_pool_entry_ids.length} 包`)}</div>` : ""}
      <div class="subtle small">A 类 ${escapeHtml(`${formatCurrency(row.grade_a_weight_kg || 0)} KG (${row.grade_a_ratio || 0}%)`)} · B 类 ${escapeHtml(`${formatCurrency(row.grade_b_weight_kg || 0)} KG (${row.grade_b_ratio || 0}%)`)}</div>
      <div class="subtle small">规则：${escapeHtml(row.source_rule || "待补充")}</div>
    </article>
  `).join("");
}

