function renderOaWorkbenchSummary(message = "") {
  const summaryTarget = document.querySelector("#oaWorkbenchSummary");
  if (!(summaryTarget instanceof HTMLElement)) {
    return;
  }
  const attendanceRows = ensureOaAttendanceRecordState();
  const payrollRows = ensureOaPayrollBatchState();
  const approvalRows = ensureOaFinanceApprovalState();
  const todayKey = getLocalDateKey(new Date().toISOString());
  const todayAttendance = attendanceRows.filter((row) => row.attendance_date === todayKey).length;
  const lateCount = attendanceRows.filter((row) => row.attendance_date === todayKey && row.attendance_status === "late").length;
  const reviewingPayroll = payrollRows.filter((row) => row.status === "under_review").length;
  const pendingApprovals = approvalRows.filter((row) => !["paid", "rejected"].includes(String(row.status || "").trim())).length;
  const pendingApprovalKes = roundToTwo(
    approvalRows
      .filter((row) => !["paid", "rejected"].includes(String(row.status || "").trim()))
      .reduce((sum, row) => sum + convertAmountToKes(row.amount, row.currency), 0),
  );
  summaryTarget.className = "report-summary";
  summaryTarget.innerHTML = `
    <div class="flow-summary-note">${escapeHtml(message || "先把打卡、工资批次和审批单沉到一套工作台里，后面再分别接 Lark、销售提成和真实付款回写。")}</div>
    <div class="report-summary-grid">
      <article class="store-metric"><strong>今日打卡</strong><span>${todayAttendance}</span></article>
      <article class="store-metric"><strong>今日迟到</strong><span>${lateCount}</span></article>
      <article class="store-metric"><strong>工资复核中</strong><span>${reviewingPayroll}</span></article>
      <article class="store-metric"><strong>待付款审批</strong><span>${pendingApprovals}</span></article>
      <article class="store-metric"><strong>待付款金额（KES）</strong><span>${escapeHtml(formatKesAmount(pendingApprovalKes, "KES 0.00"))}</span></article>
    </div>
  `;
  renderOaAttendanceList();
  renderOaPayrollList();
  renderOaFinanceApprovalList();
}

