async function resetTestHistory() {
  const confirmed = window.confirm(
    "这会清空当前系统里的测试历史录入数据，包括关单、包裹、bale、分拣、库存、调拨、销售、打印等记录。账号、门店、供应商和基础主数据会保留。确定继续吗？",
  );
  if (!confirmed) {
    return;
  }
  const result = await request("/system/reset-test-history", { method: "POST" });
  localStorage.removeItem(STORAGE_KEYS.latestWarehouseMainflowDemo);
  localStorage.removeItem(STORAGE_KEYS.latestStoreReplenishmentDemo);
  const firstInboundPanelKey = getPanelKeyByTitle("warehouse", "0. 运输 / 关单主档");
  currentInboundShipmentNo = "";
  renderInboundFlowContext("");
  if (firstInboundPanelKey) {
    localStorage.setItem("retail_ops_active_workspace", "warehouse");
    localStorage.setItem("retail_ops_active_panel_warehouse", firstInboundPanelKey);
    window.history.replaceState(null, "", `#${encodeURIComponent(firstInboundPanelKey)}`);
  } else {
    window.history.replaceState(null, "", window.location.pathname);
  }
  showTransientSummary("#testResetSummary", result.message, 1400);
  window.setTimeout(() => {
    window.location.reload();
  }, 950);
}

async function loadStoreClosingChecklist(storeCode) {
  const normalizedStore = (storeCode || currentSession.user?.store_code || "UTAWALA").trim().toUpperCase();
  applyStoreContext(normalizedStore);
  const [data, anomalies, voids, refunds] = await Promise.all([
    request(`/dashboard/store-closing-checklist/${encodeURIComponent(normalizedStore)}`),
    request(`/payments/anomalies?status=open&store_code=${encodeURIComponent(normalizedStore)}`),
    request(`/sales/void-requests?status=pending_review&store_code=${encodeURIComponent(normalizedStore)}`),
    request(`/sales/refund-requests?status=pending_review&store_code=${encodeURIComponent(normalizedStore)}`),
  ]);
  paymentAnomalyState = anomalies;
  saleVoidState = voids;
  saleRefundState = refunds;
  renderStoreClosingChecklist({
    ...data,
    payment_anomalies: anomalies.slice(0, 5),
    void_requests: voids.slice(0, 5),
    refund_requests: refunds.slice(0, 5),
  });
  focusElement("#storeClosingPanel");
}

