  populateBaleLabelTemplateSelects();
  populateItemTokenTemplateSelects();
  writeOutput("#storesOutput", stores);
  writeOutput("#settingsOutput", { barcode, labels });
  renderConfigSummary(stores, barcodeSettingsState, labelTemplateState, suppliers);
  renderLabelTemplateManagerSummary("list", labelTemplateState);
  renderInboundShipmentHistorySummary(inboundShipments);
  renderBaleBarcodeDirectorySummary();
