async function submitLogin(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const result = await request("/auth/login", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  setSession(result);
  renderAuthResultSummary("login", result);
  await Promise.all([loadDashboard(), loadConfig(), refreshIntegrationSummaries()]);
}

async function submitLogout() {
  try {
    await request("/auth/logout", { method: "POST" });
  } catch (error) {
    // Session may already be invalid; we still want to clear local state.
  }
  clearSession();
  authOutput.textContent = "Logged out.";
  renderAuthResultSummary("logout");
}

async function refreshSession() {
  if (!currentSession.token) {
    clearSession();
    return;
  }

  try {
    const user = await request("/auth/me");
    currentSession.user = user;
    localStorage.setItem(STORAGE_KEYS.user, JSON.stringify(user));
    renderSessionState();
    await Promise.all([loadDashboard(), loadConfig(), refreshIntegrationSummaries()]);
  } catch (error) {
    authOutput.textContent = error.message;
    renderAuthResultSummary("error", error.message);
  }
}

async function submitProduct(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  if (!payload.supplier_name || payload.supplier_name === "__new__") {
    throw new Error("请先从下拉框选择供应商，或者先在当前页新建供应商。");
  }
  payload.category_main = String(payload.category_main || "").trim();
  payload.category_sub = String(payload.category_sub || "").trim();
  if (!payload.category_main || payload.category_main === "__new__") {
    throw new Error("请先选择当前供应商的大类。");
  }
  if (!payload.category_sub) {
    throw new Error("请先选择当前供应商的小类。");
  }
  payload.product_name = String(payload.category_sub || payload.category_main || "").trim();
  addSupplierScopedCategoryPair(payload.supplier_name, payload.category_main, payload.category_sub);
  payload.cost_price = 0;
  payload.launch_price = 0;
  payload.rack_code = "";
  payload.label_template_code = "apparel_60x40";
  const result = await request("/products", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  writeOutput("#productOutput", result);
  renderProductResultSummary(result);
  hydrateProductForms(result);
  refreshProductCategoryControls({
    selectedMain: payload.category_main,
    selectedSub: payload.category_sub,
    notice: `${payload.supplier_name} / ${payload.category_main} / ${payload.category_sub} 已保存，后续切换到其他供应商时不会混看别家的品类。`,
  });
  await loadDashboard();
}

async function submitInboundShipment(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const files = Array.from(event.currentTarget.querySelector("[name='coc_documents_files']")?.files || []);
  payload.coc_documents = await Promise.all(files.map((file) => fileToDataUrl(file)));
  delete payload.coc_documents_files;
  const result = await request("/warehouse/inbound-shipments", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  inboundShipmentState = [result, ...inboundShipmentState.filter((row) => row.shipment_no !== result.shipment_no)];
  writeOutput("#inboundShipmentOutput", result);
  setCurrentInboundShipment(result.shipment_no);
  populateInboundShipmentSelects(inboundShipmentState, result.shipment_no);
  renderInboundShipmentSummary("create", result);
  renderInboundShipmentHistorySummary(inboundShipmentState);
  renderParcelDirectorySummary(parcelBatchState);
  await loadDashboard();
  openInboundFlowStep("packages", result.shipment_no);
}

async function submitParcelBatch(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  if (!payload.inbound_shipment_no) {
    throw new Error("请先从下拉框选择入库主档 / 关单号。");
  }
  const rows = syncParcelBatchRowsFromDom().filter(
    (row) => row.supplier_name || row.package_count || row.total_weight || row.category_main || row.category_sub || row.note,
  );
  if (!rows.length) {
    throw new Error("请至少填写一行包裹入仓明细。");
  }
  rows.forEach((row, index) => {
    if (!row.source_bale_token) {
      throw new Error(`第 ${index + 1} 行请先选择中方预报项。`);
    }
    if (!row.supplier_name) {
      throw new Error(`第 ${index + 1} 行还没有匹配到供应商，请重新选择中方预报项。`);
    }
    if (!Number(row.package_count)) {
      throw new Error(`第 ${index + 1} 行请填写本地实收包数。`);
    }
    if (!row.category_main) {
      throw new Error(`第 ${index + 1} 行还没有匹配到商品大类，请重新选择中方预报项。`);
    }
    if (!row.category_sub) {
      throw new Error(`第 ${index + 1} 行还没有匹配到商品小类，请重新选择中方预报项。`);
    }
  });
  const results = [];
  for (const row of rows) {
    const rowPayload = {
      intake_type: payload.intake_type,
      inbound_shipment_no: payload.inbound_shipment_no,
      source_bale_token: row.source_bale_token,
      supplier_name: row.supplier_name,
      cargo_type: row.category_sub || row.category_main,
      package_count: Number(row.package_count),
      total_weight: row.total_weight === "" ? null : Number(row.total_weight),
      category_main: row.category_main,
      category_sub: row.category_sub,
      note: row.note || "",
    };
    const result = await request("/warehouse/parcel-batches", {
      method: "POST",
      body: JSON.stringify(rowPayload),
    });
    results.push(result);
    parcelBatchState = [result, ...parcelBatchState.filter((existing) => existing.batch_no !== result.batch_no)];
  }
  writeOutput("#parcelBatchOutput", "");
  const totalPackages = results.reduce((sum, row) => sum + Number(row.package_count || 0), 0);
  showTransientSummary("#parcelBatchResultSummary", `包裹入仓成功，已录入 ${results.length} 条，共 ${totalPackages} 包。`, 1200);
  setCurrentInboundShipment(payload.inbound_shipment_no);
  hydrateParcelBatchForms(results[results.length - 1]);
  renderInboundShipmentHistorySummary(inboundShipmentState);
  renderParcelDirectorySummary(parcelBatchState);
  renderParcelBatchStepSummary(payload.inbound_shipment_no, `刚刚新增 ${results.length} 条包裹入仓明细，共 ${totalPackages} 包。现在可以进入总确认。`);
  renderShipmentIntakeStatusSummary(payload.inbound_shipment_no, `刚刚新增 ${results.length} 条包裹入仓明细，共 ${totalPackages} 包。现在可以进入总确认。`);
  openInboundFlowStep("editor", payload.inbound_shipment_no);
  await loadDashboard();
}

async function ensureBaleBarcodesReadyForShipment(shipmentNo = "") {
  const normalizedShipmentNo = String(shipmentNo || "").trim();
  if (!normalizedShipmentNo) {
    return [];
  }
  const existingBales = baleBarcodeState.filter((row) => String(row.shipment_no || "").trim() === normalizedShipmentNo);
  if (existingBales.length) {
    const shipment = getInboundShipmentRecord(normalizedShipmentNo);
    if (shipment) {
      shipment.intake_status = "bales_ready";
    }
    return existingBales;
  }
  try {
    const result = await request(`/warehouse/inbound-shipments/${encodeURIComponent(normalizedShipmentNo)}/generate-bale-barcodes`, {
      method: "POST",
    });
    baleBarcodeState = [
      ...result,
      ...baleBarcodeState.filter((row) => !result.some((created) => created.bale_barcode === row.bale_barcode)),
    ];
    const shipment = getInboundShipmentRecord(normalizedShipmentNo);
    if (shipment) {
      shipment.intake_status = "bales_ready";
    }
    refreshSortingShipmentOptions();
    return result;
  } catch (error) {
    const message = formatErrorMessage(error);
    if (message.includes("这张船单已经生成过 bale barcode")) {
      const refreshedRows = await request(`/warehouse/bale-barcodes?shipment_no=${encodeURIComponent(normalizedShipmentNo)}`);
      baleBarcodeState = [
        ...refreshedRows,
        ...baleBarcodeState.filter((row) => String(row.shipment_no || "").trim().toUpperCase() !== normalizedShipmentNo.toUpperCase()),
      ];
      const shipment = getInboundShipmentRecord(normalizedShipmentNo);
      if (shipment) {
        shipment.intake_status = "bales_ready";
      }
      refreshSortingShipmentOptions();
      return refreshedRows;
    }
    throw error;
  }
}

async function submitShipmentIntakeConfirm(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const shipmentNo = String(payload.shipment_no || "").trim();
  if (!shipmentNo) {
    throw new Error("请先选择要总确认的船单。");
  }
  const recorded = getShipmentRecordedSummary(shipmentNo);
  if (!recorded.totalPackages) {
    throw new Error("这张船单下还没有包裹入仓明细。先把包裹逐条录完，再做下一步。");
  }
  payload.declared_total_packages = Number(recorded.totalPackages || 0);
  try {
    const result = await request(`/warehouse/inbound-shipments/${encodeURIComponent(shipmentNo)}/confirm-intake`, {
      method: "POST",
      body: JSON.stringify(payload),
    });
    inboundShipmentState = [result, ...inboundShipmentState.filter((row) => row.shipment_no !== result.shipment_no)];
    writeOutput("#shipmentIntakeOutput", "");
    renderInboundShipmentSummary("create", result);
    setCurrentInboundShipment(result.shipment_no || shipmentNo);
    renderInboundShipmentHistorySummary(inboundShipmentState);
    renderParcelDirectorySummary(parcelBatchState);
    const normalizedShipmentNo = result.shipment_no || shipmentNo;
    await ensureBaleBarcodesReadyForShipment(normalizedShipmentNo);
    renderShipmentIntakeStatusSummary(
      normalizedShipmentNo,
      `系统累计录入 ${recorded.totalPackages} 包，人工核对后已确认一致，并已生成一包一码。现在进入条码 / 打印。`,
    );
    renderBaleBarcodeDirectorySummary(normalizedShipmentNo);
    openInboundFlowStep("barcodes", normalizedShipmentNo);
  } catch (error) {
    const message = formatErrorMessage(error);
    if (message.includes("这张船单已经确认过包裹入仓")) {
      const existingShipment = getInboundShipmentRecord(shipmentNo);
      if (existingShipment) {
        existingShipment.intake_status = existingShipment.intake_status || "confirmed";
      }
      setCurrentInboundShipment(shipmentNo);
      await ensureBaleBarcodesReadyForShipment(shipmentNo);
      renderShipmentIntakeStatusSummary(shipmentNo, "这张船单已经完成总包裹确认，并已准备好一包一码。现在直接进入条码 / 打印。");
      renderBaleBarcodeDirectorySummary(shipmentNo);
      openInboundFlowStep("barcodes", shipmentNo);
      return;
    }
    throw error;
  }
}

async function submitGenerateBaleBarcodes(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const shipmentNo = String(form.get("shipment_no") || "").trim();
  if (!shipmentNo) {
    throw new Error("请先选择已经完成总确认的船单。");
  }
  try {
    const result = await ensureBaleBarcodesReadyForShipment(shipmentNo);
    writeOutput("#shipmentIntakeOutput", "");
    setCurrentInboundShipment(shipmentNo);
    renderInboundShipmentHistorySummary(inboundShipmentState);
    renderParcelDirectorySummary(parcelBatchState);
    renderBaleBarcodeDirectorySummary(shipmentNo);
    renderShipmentIntakeStatusSummary(shipmentNo, `已按一包一码生成 ${result.length} 个 bale barcode。`);
    openInboundFlowStep("barcodes", shipmentNo);
  } catch (error) {
    const message = formatErrorMessage(error);
    if (message.includes("请先完成这张船单的包裹总确认")) {
      const shipment = getInboundShipmentRecord(shipmentNo);
      if (shipment?.intake_status === "confirmed") {
        setCurrentInboundShipment(shipmentNo);
        renderShipmentIntakeStatusSummary(shipmentNo, "这张船单已经完成总包裹确认了。现在直接进入条码 / 打印。");
        return;
      }
      renderShipmentIntakeStatusSummary(shipmentNo, "还没完成这张船单的总包裹确认。请先点上面的“确认这一船单所有包裹入仓成功”。");
      return;
    }
    throw error;
  }
}

async function confirmBalePrintFlowAndContinue() {
  const shipmentNo =
    String(document.querySelector("#baleBarcodeViewForm [name='shipment_no']")?.value || "").trim()
    || resolveCurrentInboundShipmentNo();
  if (!shipmentNo) {
    throw new Error("请先锁定一张已经完成总确认的船单。");
  }
  const rows = getBalesForShipment(shipmentNo);
  if (!rows.length) {
    throw new Error("这张船单还没有生成一包一码，请先完成总确认。");
  }
  const batchGroups = groupBalesByBatch(rows);
  const continuationAction = balePrintFlow.getBaleShipmentContinuationAction
    ? balePrintFlow.getBaleShipmentContinuationAction(rows, batchGroups)
    : {
      action: rows.some((row) => !row.printed_at) ? "resume_printing" : "proceed_to_sorting",
      pendingCount: rows.filter((row) => !row.printed_at).length,
      nextPendingKey: getNextPendingBaleBatchKey(batchGroups),
    };
  if (continuationAction.action !== "proceed_to_sorting") {
    activeBaleBatchKey = continuationAction.nextPendingKey || getNextPendingBaleBatchKey(batchGroups);
    if (activeBaleBatchKey) {
      expandedBaleBatchKeys.add(activeBaleBatchKey);
    }
    baleBarcodeDirectoryNotice = {
      type: "error",
      message: `还有 ${continuationAction.pendingCount} 个待贴码 bale。请先在打印弹层里逐张确认实体打印，再进入分拣。`,
    };
    renderBaleBarcodeDirectorySummary(shipmentNo);
    return;
  }
  baleBarcodeDirectoryNotice = {
    type: "success",
    message: "这张船单的 bale 标签已经全部贴码完成，现在去原始 bale 总库存页查看当前库存，然后再到 0.1 创建分拣任务扫码加入。",
  };

  setCurrentInboundShipment(shipmentNo);
  renderInboundShipmentHistorySummary(inboundShipmentState);
  renderParcelDirectorySummary(parcelBatchState);
  renderBaleBarcodeDirectorySummary(shipmentNo);
  await loadRawBaleStock(`已定位到船单 ${shipmentNo}。现在先看这批 raw bale 的当前库存；创建分拣任务时不再锁船单，直接按 bale 条码加入。`);
  const rawBalePanelKey = getPanelKeyByTitle("warehouse", "0.1 原始 Bale 总库存");
  if (rawBalePanelKey) {
    setActivePanel(rawBalePanelKey);
    focusElement("#rawBaleStockSummary");
  }
}

async function confirmBalePrintGroup(groupKey = "") {
  const shipmentNo =
    String(document.querySelector("#baleBarcodeViewForm [name='shipment_no']")?.value || "").trim()
    || resolveCurrentInboundShipmentNo();
  if (!shipmentNo) {
    throw new Error("请先选择船单。");
  }
  const rows = getBalesForShipment(shipmentNo);
  const batchGroups = groupBalesByBatch(rows);
  const targetGroup = batchGroups.find((group) => getBaleBatchGroupKey(group) === String(groupKey || "").trim().toUpperCase());
  if (!targetGroup) {
    throw new Error("没有找到这一类待贴码批次。");
  }
  const completionAction = balePrintFlow.getBaleGroupCompletionAction
    ? balePrintFlow.getBaleGroupCompletionAction(targetGroup)
    : {
      action: targetGroup.rows.some((row) => !row.printed_at) ? "resume_printing" : "already_complete",
      pendingCount: targetGroup.rows.filter((row) => !row.printed_at).length,
    };
  if (completionAction.action === "already_complete") {
    baleBarcodeDirectoryNotice = {
      type: "success",
      message: `${targetGroup.supplierName || "当前类别"} ${[targetGroup.categoryMain, targetGroup.categorySub].filter(Boolean).join(" / ") || ""} 已经完成贴码。`,
    };
    activeBaleBatchKey = getNextPendingBaleBatchKey(batchGroups);
    if (activeBaleBatchKey) {
      expandedBaleBatchKeys.add(activeBaleBatchKey);
    }
    renderBaleBarcodeDirectorySummary(shipmentNo);
    return;
  }
  activeBaleBatchKey = getBaleBatchGroupKey(targetGroup);
  if (activeBaleBatchKey) {
    expandedBaleBatchKeys.add(activeBaleBatchKey);
  }
  const remainingOverall = rows.filter((row) => !row.printed_at).length;
  baleBarcodeDirectoryNotice = {
    type: "error",
    message: remainingOverall
      ? `${targetGroup.supplierName || "当前类别"} ${[targetGroup.categoryMain, targetGroup.categorySub].filter(Boolean).join(" / ")} 还剩 ${completionAction.pendingCount} 包待贴码。请先在打印弹层里逐张点击“标记本张已打印”。`
      : "所有类别已经贴码完成，现在可以进入分拣任务。",
  };
  renderBaleBarcodeDirectorySummary(shipmentNo);
  await openBalePrintModalForGroup(groupKey);
}

async function openBalePrintModalForGroup(groupKey = "") {
  const shipmentNo =
    String(document.querySelector("#baleBarcodeViewForm [name='shipment_no']")?.value || "").trim()
    || resolveCurrentInboundShipmentNo();
  if (!shipmentNo) {
    throw new Error("请先选择船单。");
  }
  const printerName = String(document.querySelector("#balePrinterConsoleForm [name='printer_name']")?.value || "Deli DL-720C").trim();
  const rows = getBalesForShipment(shipmentNo);
  const batchGroups = groupBalesByBatch(rows);
  const targetGroup = batchGroups.find((group) => getBaleBatchGroupKey(group) === String(groupKey || "").trim().toUpperCase());
  if (!targetGroup) {
    throw new Error("没有找到这一类待贴码批次。");
  }
  let printPlan = balePrintFlow.buildBaleGroupPrintPlan
    ? balePrintFlow.buildBaleGroupPrintPlan(targetGroup, getQueuedBalePrintJobsForShipment(shipmentNo))
    : {
      pendingRows: targetGroup.rows.filter((row) => !row.printed_at),
      orderedQueuedJobs: [],
      missingRows: targetGroup.rows.filter((row) => !row.printed_at),
    };
  if (!printPlan.pendingRows.length) {
    baleBarcodeDirectoryNotice = {
      type: "success",
      message: `${targetGroup.supplierName || "当前类别"} ${[targetGroup.categoryMain, targetGroup.categorySub].filter(Boolean).join(" / ")} 这一类已经没有待打印包裹。`,
    };
    renderBaleBarcodeDirectorySummary(shipmentNo);
    return;
  }
  const templateCode = getPreferredBaleTemplateCode();
  openBalePrintModal({
    shipmentNo,
    groupKey,
    jobs: printPlan.orderedQueuedJobs,
    supplierName: targetGroup.supplierName || "",
    categoryDisplay: [targetGroup.categoryMain, targetGroup.categorySub].filter(Boolean).join(" / "),
    templateScope: "bale",
    taskType: "warehouse_inbound",
    preferredTemplateCode: "warehouse_in",
  });
  try {
    await loadSystemPrinters();
  } catch (error) {
    balePrinterConsoleNotice = {
      type: "error",
      message: formatErrorMessage(error),
    };
    renderBalePrintModal();
  }
  if (printPlan.missingRows.length) {
    const createResult = await request("/warehouse/bale-barcodes/print-jobs", {
      method: "POST",
      body: JSON.stringify({
        shipment_no: shipmentNo,
        printer_name: printerName,
        template_code: templateCode,
        items: printPlan.missingRows.map((row) => ({ bale_barcode: row.bale_barcode, copies: 1 })),
      }),
    });
    const createdJobs = createResult.print_jobs || [];
    balePrinterJobState = [
      ...createdJobs,
      ...balePrinterJobState.filter((job) => !createdJobs.some((row) => row.id === job.id)),
    ];
    printPlan = balePrintFlow.buildBaleGroupPrintPlan
      ? balePrintFlow.buildBaleGroupPrintPlan(targetGroup, getQueuedBalePrintJobsForShipment(shipmentNo))
      : {
        pendingRows: printPlan.pendingRows,
        orderedQueuedJobs: [...printPlan.orderedQueuedJobs, ...createdJobs],
        missingRows: [],
      };
  }
  balePrinterConsoleNotice = {
    type: "success",
    message: `已为 ${targetGroup.supplierName || ""} ${[targetGroup.categoryMain, targetGroup.categorySub].filter(Boolean).join(" / ")} 准备 ${printPlan.orderedQueuedJobs.length} 包待打印任务。`,
  };
  renderBalePrinterConsoleSummary(shipmentNo);
  openBalePrintModal({
    shipmentNo,
    groupKey,
    jobs: printPlan.orderedQueuedJobs,
    supplierName: targetGroup.supplierName || "",
    categoryDisplay: [targetGroup.categoryMain, targetGroup.categorySub].filter(Boolean).join(" / "),
    templateScope: "bale",
    taskType: "warehouse_inbound",
    preferredTemplateCode: "warehouse_in",
  });
}

async function submitSelectedBalePrintJobs() {
  const shipmentNo = String(document.querySelector("#baleBarcodeViewForm [name='shipment_no']")?.value || "").trim();
  if (!shipmentNo) {
    throw new Error("请先选择船单，再确认打印。");
  }
  setCurrentInboundShipment(shipmentNo);
  const items = [...selectedBalePrintMap.entries()].map(([bale_barcode, copies]) => ({ bale_barcode, copies }));
  if (!items.length) {
    throw new Error("请先从左侧加入至少一个包裹，再确认打印。");
  }
  const result = await request("/warehouse/bale-barcodes/print-jobs", {
    method: "POST",
    body: JSON.stringify({
      shipment_no: shipmentNo,
      printer_name: "Deli DL-720C",
      template_code: getPreferredBaleTemplateCode(),
      items,
    }),
  });
  const refreshedRows = await request(`/warehouse/bale-barcodes?shipment_no=${encodeURIComponent(shipmentNo)}`);
  baleBarcodeState = [
    ...refreshedRows,
    ...baleBarcodeState.filter((row) => String(row.shipment_no || "").trim().toUpperCase() !== shipmentNo.toUpperCase()),
  ];
  baleBarcodeDirectoryNotice = {
    type: "success",
    message: `已把 ${result.total_selected_bales} 个包裹加入贴码打印任务，总共 ${result.total_print_copies} 份。它们会进入待打印队列，逐张确认实体打印后才会回写为“已贴码”。`,
  };
  balePrinterJobState = [
    ...(result.print_jobs || []),
    ...balePrinterJobState.filter((job) => !(result.print_jobs || []).some((row) => row.id === job.id)),
  ];
  balePrinterConsoleNotice = {
    type: "success",
    message: `待打任务已经创建好了。现在请连接条码打印机，再逐条预览并点击“已打印”。`,
  };
  selectedBalePrintMap = new Map();
  writeOutput("#baleBarcodeDirectoryOutput", result.print_jobs || []);
  renderBaleBarcodeDirectorySummary(shipmentNo);
  renderInboundShipmentHistorySummary(inboundShipmentState);
  jumpToBalePrinterConsole(shipmentNo);
  await loadBalePrinterConsole(shipmentNo);
}

async function submitRawBaleStockFilter(event) {
  event.preventDefault();
  await loadRawBaleStock();
  focusElement("#rawBaleStockSummary");
}

async function addSortingLookupBaleToSelection() {
  const baleLookupInput = document.querySelector("#sortingTaskForm [name='bale_lookup']");
  const baleCode = String(baleLookupInput?.value || "").trim();
  await resolveBarcodeForContext(baleCode, "warehouse_sorting_create", ["RAW_BALE"]);
  await syncSortingFlowSnapshot();
  const resolver = sortingTaskFlow.addBaleToSortingTaskSelection || ((options = {}) => {
    const allBales = Array.isArray(options.allBales) ? options.allBales : [];
    const selectedBaleCodes = Array.isArray(options.selectedBaleCodes) ? options.selectedBaleCodes : [];
    const normalizedCode = String(options.baleCode || "").trim().toUpperCase();
    const matchedRow = allBales.find((row) => (
      String(row?.bale_barcode || "").trim().toUpperCase() === normalizedCode
      || String(row?.legacy_bale_barcode || "").trim().toUpperCase() === normalizedCode
      || String(row?.scan_token || "").trim().toUpperCase() === normalizedCode
    ));
    if (!matchedRow) {
      return { ok: false, error: "没有找到这个 bale barcode。", selectedBaleCodes };
    }
    if (!isRawBaleEligibleForSortingTask(matchedRow)) {
      return { ok: false, error: `${options.baleCode} 当前不能加入分拣任务。`, selectedBaleCodes };
    }
    const canonicalBaleBarcode = String(matchedRow?.bale_barcode || "").trim().toUpperCase();
    return {
      ok: true,
      duplicate: selectedBaleCodes.includes(canonicalBaleBarcode),
      selectedBaleCodes: selectedBaleCodes.includes(canonicalBaleBarcode) ? selectedBaleCodes : [...selectedBaleCodes, canonicalBaleBarcode],
      matchedRow,
    };
  });
  const result = resolver({
    allBales: baleBarcodeState,
    selectedBaleCodes: [...selectedSortingBales],
    baleCode,
  });
  if (!result.ok) {
    throw new Error(result.error || "当前 bale 不能加入分拣任务。");
  }
  selectedSortingBales = new Set(Array.isArray(result.selectedBaleCodes) ? result.selectedBaleCodes : []);
  const lastScan = sortingScannerHealthState.lastCompletedScan;
  if (
    baleCode
    && (!lastScan
      || String(lastScan.value || "").trim().toUpperCase() !== baleCode.toUpperCase()
      || Math.abs(Date.now() - Number(lastScan.capturedAtMs || 0)) > 2000)
  ) {
    recordSortingScannerCompletedScan({
      value: baleCode,
      terminator: "none",
      target: "bale_lookup",
    });
  }
  setInputValue("#sortingTaskForm [name='bale_lookup']", "");
  refreshSortingShipmentOptions();
  showTransientInlineNotice(
    "#sortingTaskNotice",
    result.duplicate
      ? `${result.matchedRow?.bale_barcode || baleCode} 已经在当前任务里。`
      : result.approximate
        ? `${baleCode} 疑似扫码丢字，已按 ${result.matchedRow?.bale_barcode || baleCode} 加入当前任务。`
        : `${result.matchedRow?.bale_barcode || baleCode} 已加入当前任务。`,
    result.duplicate ? "info" : "success",
    1600,
  );
}

async function routeRawBaleFromWorkbench(baleBarcode, destination) {
  const normalizedBale = String(baleBarcode || "").trim().toUpperCase();
  const normalizedDestination = String(destination || "").trim().toLowerCase();
  if (!normalizedBale || !normalizedDestination) {
    return;
  }
  const endpoint = normalizedDestination === "sorting"
    ? `/warehouse/raw-bales/${encodeURIComponent(normalizedBale)}/route-to-sorting`
    : `/warehouse/raw-bales/${encodeURIComponent(normalizedBale)}/route-to-bale-sales-pool`;
  const result = await request(endpoint, {
    method: "POST",
    body: JSON.stringify({
      note: normalizedDestination === "sorting" ? "仓库主管判定进入分拣" : "仓库主管移交整包销售池",
    }),
  });
  upsertRawBaleState([result]);
  renderRawBaleStockSummary(
    rawBaleStockState,
    normalizedDestination === "sorting"
      ? `${normalizedBale} 已判定进入分拣，现在可以去 0.1 创建分拣任务继续做任务占用。`
      : `${normalizedBale} 已移交整包销售池，不再属于主分拣流可分拣池。`,
  );
  renderBaleSalesWorkbench(
    normalizedDestination === "bale_sales_pool" ? `${normalizedBale} 已进入整包销售池工作台。` : "",
  );
  writeOutput("#rawBaleStockOutput", result);
  if (normalizedDestination === "sorting") {
    setInputValue("#sortingTaskForm [name='shipment_no']", result.shipment_no || "");
    refreshSortingShipmentOptions();
  }
}

async function submitSortingTask(event) {
  event.preventDefault();
  syncJsonBuilderToField("sorting-handler-names");
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  payload.category_filters = [];
  payload.handler_names = parseJsonField(payload.handler_names_json, []);
  delete payload.bale_lookup;
  delete payload.bale_search;
  delete payload.handler_names_json;
  await syncSortingFlowSnapshot();
  const selectedRows = baleBarcodeState.filter(
    (row) => selectedSortingBales.has(row.bale_barcode) && isRawBaleEligibleForSortingTask(row),
  );
  payload.bale_barcodes = selectedRows.map((row) => row.bale_barcode).filter(Boolean);
  if (!payload.bale_barcodes.length) {
    throw new Error("请先通过扫码或检索，把至少一个当前可分拣的 bale 加入右侧任务清单。");
  }
  if (!payload.handler_names.length) {
    throw new Error("请至少填写一个分拣处理人。");
  }
  const result = await request("/warehouse/sorting-tasks", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  sortingTaskState = [result, ...sortingTaskState.filter((row) => row.task_no !== result.task_no)];
  writeOutput("#sortingTaskOutput", result);
  await syncSortingFlowSnapshot();
  renderSortingTaskResultSummary("create", result);
  renderSortingTaskManagerSummary("list", sortingTaskState);
  selectedSortingBales = new Set();
  selectedSortingBatchNos = new Set();
  setInputValue("#sortingTaskForm [name='bale_lookup']", "");
  setInputValue("#sortingTaskForm [name='bale_search']", "");
  setJsonBuilderRows("sorting-handler-names", []);
  syncJsonBuilderToField("sorting-handler-names");
  setInputValue("#sortingResultForm [name='task_no']", result.task_no || "");
  refreshSortingShipmentOptions();
  showTransientInlineNotice("#sortingTaskNotice", `分拣任务 ${result.task_no || ""} 已创建成功。`, "success", 1800);
}

async function submitSortingResults(event) {
  event.preventDefault();
  syncJsonBuilderToField("sorting-result-items");
  const formElement = event.currentTarget;
  const form = new FormData(formElement);
  const payload = Object.fromEntries(form.entries());
  const taskNo = payload.task_no?.trim();
  if (!taskNo) {
    throw new Error("请先创建或读取一张分拣任务。");
  }
  let task = getSortingTaskByNo(taskNo);
  await syncSortingFlowSnapshot(task?.shipment_no || "");
  task = getSortingTaskByNo(taskNo);
  payload.result_items = parseJsonField(payload.result_items_json, []);
  payload.loss_record = await buildSortingLossRecordPayload(formElement);
  payload.mark_task_completed = payload.mark_task_completed === "true";
  payload.result_items.forEach((row, index) => {
    if (!(Number(row?.actual_weight_kg || 0) > 0)) {
      throw new Error(`第 ${index + 1} 行请先录入实际分拣重量 KG。`);
    }
    if (String(row?.confirm_to_inventory) === "false" || row?.confirm_to_inventory === false) {
      return;
    }
    if (!(Number(row?.default_cost_kes || 0) > 0)) {
      throw new Error(`第 ${index + 1} 行还没有绑定默认成本价，请先去 4.7 配置。`);
    }
    if (!String(row?.rack_code || "").trim()) {
      throw new Error(`第 ${index + 1} 行还没有绑定分拣库位，请先去 4.8 配置。`);
    }
  });
  const costMeta = getSortingTaskFormalCostPayload(task, payload.result_items, payload.loss_record);
  if (costMeta.cost_status !== "cost_locked") {
    throw new Error(costMeta.detail || "当前分拣重量还不能正式锁成本。");
  }
  delete payload.task_no;
  delete payload.result_items_json;
  const result = await request(`/warehouse/sorting-tasks/${encodeURIComponent(taskNo)}/results`, {
    method: "POST",
    body: JSON.stringify(payload),
  });
  sortingTaskState = [result, ...sortingTaskState.filter((row) => row.task_no !== result.task_no)];
  await syncSortingFlowSnapshot(result.shipment_no || task?.shipment_no || "");
  writeOutput("#sortingResultOutput", result);
  renderSortingResultSubmitSummary(result);
  renderSortingTaskManagerSummary("list", sortingTaskState);
  hydrateSortingTaskForms(result);
  hydrateSortingLossRecord(result.loss_record || null);
  populateStoreFlowFormsFromContext({
    task_no: result.task_no || "",
    shipment_no: result.shipment_no || "",
    store_code: getCurrentStoreCodeFallback(),
  });
  await refreshStoreDispatchBaleDirectoryFromForm({
    lastTaskNo: result.task_no || "",
    lastShipmentNo: result.shipment_no || "",
  });
  await loadTable("load-sorting-stock");
}

async function submitStorePrepBaleTask(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  payload.task_type = String(payload.task_type || "store_dispatch").trim().toLowerCase() || "store_dispatch";
  if (payload.task_type === "sale") {
    payload.target_weight_kg = Number(payload.target_weight_kg || 0);
    const ratioPreset = getSaleBaleRatioPreset(payload.ratio_label || "");
    payload.grade_ratios = Array.isArray(ratioPreset?.gradeRatios) ? ratioPreset.gradeRatios : [];
    delete payload.target_qty;
    delete payload.pieces_per_bale;
    delete payload.bale_count;
  } else {
    const piecesPerBale = Number(payload.pieces_per_bale || 0);
    const baleCount = Number(payload.bale_count || 0);
    if (!(piecesPerBale > 0) || !(baleCount > 0)) {
      throw new Error("请先填写每包多少件和本次压缩多少包。");
    }
    if (![100, 200].includes(piecesPerBale)) {
      throw new Error("每包件数只能选择 100 或 200 件。");
    }
    if (baleCount < 1 || baleCount > 5) {
      throw new Error("本次压缩包数只能选择 1-5 包。");
    }
    const ratioEstimate = buildStoreDispatchCompressionGradeRequirements({
      piecesPerBale,
      baleCount,
      ratioLabel: payload.store_dispatch_ratio_label || "",
    });
    const gradeRequirements = ratioEstimate.totalRequirements;
    const targetQty = piecesPerBale * baleCount;
    const gradeTotalQty = gradeRequirements.reduce((sum, row) => sum + Number(row.qty || 0), 0);
    if (gradeTotalQty !== targetQty) {
      throw new Error(`P/S 等级总件数必须等于每包件数 × 包数：${targetQty} 件。`);
    }
    payload.grade_requirements = gradeRequirements;
    payload.pieces_per_bale = piecesPerBale;
    payload.bale_count = baleCount;
    payload.target_qty = targetQty;
  }
  delete payload.grade_p_qty;
  delete payload.grade_s_qty;
  delete payload.store_dispatch_ratio_label;
  if (!String(payload.assigned_employee || "").trim()) {
    throw new Error("请先选择负责压缩 bale 的员工。");
  }
  const result = await request("/warehouse/store-prep-bale-tasks", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  storePrepBaleTaskState = [
    result,
    ...storePrepBaleTaskState.filter((row) => String(row?.task_no || "").trim().toUpperCase() !== String(result.task_no || "").trim().toUpperCase()),
  ];
  writeOutput("#compressionTaskOutput", result);
  closeSortingCompressionCreator();
  renderStorePrepBaleTaskSummary(`${getCompressionTaskTypeLabel(result.task_type || "")}任务 ${result.task_no || ""} 已创建。下一步去 0.1.2 压缩工单管理里做验收和打印。`);
  await loadStorePrepBaleWorkbench({ force: true, focus: false });
  await loadTable("load-sorting-stock");
}

async function queueCompressionTaskPrintJob(resultRow = {}) {
  const baleNo = String(resultRow?.prepared_bale_no || "").trim().toUpperCase();
  if (!baleNo) {
    throw new Error("当前压缩任务还没有生成 bale 编号，不能准备打印任务。");
  }
  const taskType = String(resultRow?.task_type || "store_dispatch").trim().toLowerCase() || "store_dispatch";
  const templateCode = getPreferredWarehouseoutTemplateCode("", taskType);
  return request(`/warehouse/store-prep-bales/${encodeURIComponent(baleNo)}/print-jobs`, {
    method: "POST",
    body: JSON.stringify({
      printer_name: String(document.querySelector("#balePrinterConsoleForm [name='printer_name']")?.value || "Deli DL-720C").trim() || "Deli DL-720C",
      template_code: templateCode,
      copies: 1,
    }),
  });
}

async function queueCompressionTaskPrintJobs(resultRow = {}) {
  const baleNos = Array.isArray(resultRow?.prepared_bale_nos) && resultRow.prepared_bale_nos.length
    ? resultRow.prepared_bale_nos
    : [resultRow?.prepared_bale_no];
  const normalizedBaleNos = baleNos
    .map((value) => String(value || "").trim().toUpperCase())
    .filter(Boolean);
  if (!normalizedBaleNos.length) {
    throw new Error("当前压缩任务还没有生成 bale 编号，不能准备打印任务。");
  }
  const jobs = [];
  for (const baleNo of normalizedBaleNos) {
    jobs.push(await queueCompressionTaskPrintJob({ ...resultRow, prepared_bale_no: baleNo }));
  }
  return jobs;
}

async function directPrintStorePrepBaleHistoricalBarcode(row = {}) {
  const baleNo = String(row?.bale_no || "").trim().toUpperCase();
  const barcodeValue = String(row?.scan_token || row?.bale_barcode || "").trim().toUpperCase();
  if (!baleNo || !barcodeValue) {
    throw new Error("当前这张压缩 bale 还没有历史 barcode，不能直接补打。");
  }
  await loadSystemPrinters();
  const taskType = String(row?.task_type || "store_dispatch").trim().toLowerCase() || "store_dispatch";
  const templateCode = String(
    storePrepBaleFlow.getStorePrepTemplateDefaultCode
      ? storePrepBaleFlow.getStorePrepTemplateDefaultCode(taskType)
      : (taskType === "sale" ? "wait_for_sale" : "wait_for_transtoshop")
  ).trim().toLowerCase() || "wait_for_transtoshop";
  const printerName = String(document.querySelector("#balePrinterConsoleForm [name='printer_name']")?.value || "Deli DL-720C").trim() || "Deli DL-720C";
  const payload = storePrepBaleFlow.buildStorePrepBaleDirectPrintPayload
    ? storePrepBaleFlow.buildStorePrepBaleDirectPrintPayload(row, { printerName, templateCode })
    : {
      printer_name: printerName,
      template_code: templateCode,
      copies: 1,
      barcode_value: barcodeValue,
      scan_token: barcodeValue,
      bale_barcode: String(row?.bale_barcode || "").trim().toUpperCase(),
      legacy_bale_barcode: "",
      supplier_name: "SORTED STOCK",
      category_main: String(row?.category_main || "").trim(),
      category_sub: String(row?.category_sub || "").trim(),
      category_display: [String(row?.category_main || "").trim(), String(row?.category_sub || "").trim()].filter(Boolean).join(" / "),
      package_position_label: `${Number(row?.qty || 0)} 件`,
      serial_no: 1,
      total_packages: 1,
      shipment_no: String(row?.task_no || "").trim().toUpperCase(),
      parcel_batch_no: baleNo,
      unload_date: String(row?.updated_at || row?.created_at || "").trim(),
      template_scope: "warehouseout_bale",
      dispatch_bale_no: barcodeValue,
      status: taskType === "sale" ? "wait for sale" : "wait for transtoshop",
      cat: String(row?.category_main || "").trim(),
      sub: String(row?.category_sub || "").trim(),
      grade: String(row?.grade_summary || "").trim(),
      qty: String(Number(row?.qty || 0)),
      weight: row?.actual_weight_kg ? `${row.actual_weight_kg} KG` : "",
      code: barcodeValue,
    };
  const result = await request("/print-jobs/bale-direct/print", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  writeOutput("#compressionTaskOutput", {
    action: "reprint_store_prep_bale_barcode",
    bale_no: baleNo,
    barcode: barcodeValue,
    printer_name: printerName,
    template_code: templateCode,
    result,
  });
  showTransientInlineNotice(
    "#sortingStockNotice",
    `${baleNo} 的历史 barcode ${barcodeValue} 已发送补打。请确认标签机是否开始出纸。`,
    "success",
    2200,
  );
  return result;
}

function openCompressionTaskPrintModal(resultRow = {}, printJobs = []) {
  const jobs = Array.isArray(printJobs) ? printJobs.filter(Boolean) : [printJobs].filter(Boolean);
  if (!jobs.length) {
    return;
  }
  const taskType = String(resultRow?.task_type || "store_dispatch").trim().toLowerCase() || "store_dispatch";
  const templateCode = getPreferredWarehouseoutTemplateCode(
    String(jobs[0]?.template_code || "").trim().toLowerCase(),
    taskType,
  );
  const categoryDisplay = [String(resultRow?.category_main || "").trim(), String(resultRow?.category_sub || "").trim()]
    .filter(Boolean)
    .join(" / ");
  balePrinterConsoleNotice = {
    type: "success",
    message: `已为 ${jobs.length} 个压缩 bale 准备模板打印任务。先选模板，再确认实体出纸。`,
  };
  openBalePrintModal({
    shipmentNo: String(resultRow?.task_no || "").trim().toUpperCase(),
    groupKey: String(resultRow?.task_no || resultRow?.prepared_bale_no || "").trim().toUpperCase(),
    jobs,
    supplierName: "SORTED STOCK",
    categoryDisplay: categoryDisplay || String(resultRow?.prepared_bale_no || "").trim().toUpperCase(),
    templateScope: "warehouseout_bale",
    taskType,
    preferredTemplateCode: templateCode,
  });
}

async function completeStorePrepBaleTask(taskNo = "", payload = {}) {
  const normalizedTaskNo = String(taskNo || "").trim().toUpperCase();
  if (!normalizedTaskNo) {
    return;
  }
  const result = await request(`/warehouse/store-prep-bale-tasks/${encodeURIComponent(normalizedTaskNo)}/complete`, {
    method: "POST",
    body: JSON.stringify(payload),
  });
  storePrepBaleTaskState = [
    result,
    ...storePrepBaleTaskState.filter((row) => String(row?.task_no || "").trim().toUpperCase() !== normalizedTaskNo),
  ];
  activeCompressionTaskNo = normalizedTaskNo;
  activeCompressionTaskResult = result;
  writeOutput("#compressionTaskOutput", result);
  await loadStorePrepBaleWorkbench({ force: true, focus: false });
  await loadTable("load-sorting-stock");
  const completedTaskTypeLabel = getCompressionTaskTypeLabel(result.task_type || "");
  const generatedBaleCount = Array.isArray(result.prepared_bale_nos) && result.prepared_bale_nos.length
    ? result.prepared_bale_nos.length
    : (result.prepared_bale_no ? 1 : 0);
  const completedMessage = String(result.task_type || "").trim().toLowerCase() === "sale"
    ? `任务 ${normalizedTaskNo} 已完成验收并生成 barcode，已进入待售卖 bale 区，原散件库存口径保持不扣减。`
    : `任务 ${normalizedTaskNo} 已完成验收并生成 ${generatedBaleCount || 1} 个 barcode，散件已转成待送店 bale，仍留在仓库已分拣服装库存口径里。`;
  renderCompressionTaskAcceptanceWindow(completedMessage);
  renderStorePrepBaleTaskSummary(`${completedTaskTypeLabel}任务已完成：${completedMessage}`);
  try {
    await loadSystemPrinters();
    const printJobs = await queueCompressionTaskPrintJobs(result);
    closeCompressionTaskAcceptanceModal();
    openCompressionTaskPrintModal(result, printJobs);
  } catch (error) {
    const printMessage = formatErrorMessage(error);
    renderErrorSummary("#compressionTaskAcceptanceSummary", `${completedMessage} 已完成验收，但没有自动拉起打印窗：${printMessage}`);
  }
}

function openCompressionTaskForAcceptance(taskNo = "") {
  activeCompressionTaskNo = String(taskNo || "").trim().toUpperCase();
  activeCompressionTaskResult = null;
  renderCompressionTaskAcceptanceWindow();
  openCompressionTaskAcceptanceModal();
  renderStorePrepBaleTaskSummary();
  focusElement("#compressionTaskAcceptanceSummary");
}

