async function submitItemTokenDirectory(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const baleNo = String(payload.bale_no || "").trim().toUpperCase();
  if (!baleNo) {
    throw new Error("请先读取当前店员负责的门店配货 bale。");
  }
  let rows = await request(`/stores/dispatch-bales/${encodeURIComponent(baleNo)}/tokens`);
  rows = Array.isArray(rows) ? rows : [];
  const assignedEmployee = String(payload.assigned_employee || "").trim();
  if (assignedEmployee) {
    rows = rows.filter((row) => String(row.assigned_employee || "").trim() === assignedEmployee);
  }
  itemBarcodeTokenState = rows;
  filteredItemBarcodeTokenState = rows;
  await loadItemTokenPrintJobs();
  populateStoreFlowFormsFromContext({
    bale_no: baleNo,
    assigned_employee: assignedEmployee || rows[0]?.assigned_employee || "",
    task_no: rows[0]?.task_no || "",
    shipment_no: rows[0]?.shipment_no || "",
    store_code: rows[0]?.store_code || getCurrentStoreCodeFallback(),
  });
  if (String(payload.template_code || "").trim()) {
    setInputValue("#itemTokenPrintQueueForm [name='template_code']", String(payload.template_code || "").trim());
  }
  if (String(payload.printer_name || "").trim()) {
    setInputValue("#itemTokenPrintQueueForm [name='printer_name']", String(payload.printer_name || "").trim());
  }
  writeOutput("#itemTokenDirectoryOutput", rows.length ? rows : "当前 bale 下没有待贴码 token。");
  renderItemTokenDirectorySummary(filteredItemBarcodeTokenState);
}

async function submitItemTokenPrintQueue(event) {
  event.preventDefault();
  if (!filteredItemBarcodeTokenState.length) {
    throw new Error("请先筛出一批待贴码 token。");
  }
  const printableTokenNos = filteredItemBarcodeTokenState
    .filter((row) => ["pending_store_print", "print_failed"].includes(String(row.status || "").trim()))
    .filter((row) => row.selling_price_kes !== null && row.selling_price_kes !== undefined)
    .filter((row) => String(row.store_rack_code || "").trim())
    .map((row) => String(row.token_no || "").trim())
    .filter(Boolean);
  if (!printableTokenNos.length) {
    throw new Error("当前 bale 里还没有完成售价和货架位编辑的 token，不能加入打印队列。");
  }
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  payload.token_nos = printableTokenNos;
  payload.copies = Number(payload.copies || 1);
  await loadSystemPrinters();
  const matchedPrinter = findSystemPrinterBySelectedName(String(payload.printer_name || "").trim());
  if (!matchedPrinter) {
    throw new Error(systemPrinterState.length
      ? `系统里没有找到名为 ${payload.printer_name || "当前选择"} 的打印机，请先检查设备名称。`
      : "当前电脑没有识别到任何系统打印机，请先连接并安装蓝牙打印机。");
  }
  payload.printer_name = String(matchedPrinter.name || payload.printer_name || "").trim();
  const result = await request("/print-jobs/item-tokens", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  writeOutput("#itemTokenDirectoryOutput", Array.isArray(result) ? result : []);
  showTransientInlineNotice("#itemTokenDirectoryNotice", `已把 ${printableTokenNos.length} 个商品 token 加入打印队列。`, "success", 1800);
  const directoryForm = document.querySelector("#storeBluetoothPrinterForm");
  if (directoryForm instanceof HTMLFormElement) {
    await submitItemTokenDirectory({ preventDefault() {}, currentTarget: directoryForm });
  } else {
    await loadItemTokenPrintJobs();
  }
  renderItemTokenDirectorySummary(filteredItemBarcodeTokenState, { lastQueuedCount: printableTokenNos.length });
  await loadTable("load-print-jobs");
}

