async function submitLabelTemplate(event) {
  event.preventDefault();
  const formElement = event.currentTarget;
  const form = new FormData(formElement);
  const payload = Object.fromEntries(form.entries());
  const draft = ensureLabelTemplateEditorDraft();
  payload.template_code = String(payload.template_code || "").trim().toLowerCase();
  payload.name = String(payload.name || "").trim();
  payload.template_scope = "bale";
  payload.barcode_type = "Code128";
  payload.paper_preset = String(payload.paper_preset || draft.paper_preset || "60x40").trim().toLowerCase();
  payload.width_mm = Number(payload.width_mm || draft.width_mm || 60);
  payload.height_mm = Number(payload.height_mm || draft.height_mm || 40);
  const normalizeLayout = labelTemplateFlow.normalizeBaleTemplateLayout || ((layout) => layout || {});
  payload.layout = normalizeLayout(draft.layout || {}, payload.width_mm, payload.height_mm);
  payload.fields = labelTemplateFlow.getEnabledTemplateFields
    ? labelTemplateFlow.getEnabledTemplateFields(payload.layout)
    : ["barcode_value"];
  const barcodeComponent = (Array.isArray(payload.layout?.components) ? payload.layout.components : []).find((component) => component.id === "barcode");
  if (!barcodeComponent?.enabled) {
    throw new Error("bale 模版的中间条码必须保留，不能关闭。");
  }
  if (!payload.fields.length) {
    throw new Error("请至少保留一个可显示字段。");
  }
  const currentExists = Boolean(getLabelTemplateByCode(payload.template_code));
  const result = await request(
    currentExists ? `/settings/label-templates/${encodeURIComponent(payload.template_code)}` : "/settings/label-templates",
    {
      method: currentExists ? "PUT" : "POST",
      body: JSON.stringify(payload),
    },
  );
  labelTemplateState = [
    result,
    ...labelTemplateState.filter((row) => String(row?.template_code || "").trim().toLowerCase() !== payload.template_code),
  ].sort((left, right) => String(left.template_code || "").localeCompare(String(right.template_code || ""), "zh-CN"));
  writeOutput("#labelTemplateOutput", labelTemplateState);
  populateBaleLabelTemplateSelects(payload.template_code);
  populateItemTokenTemplateSelects();
  hydrateLabelTemplateForm(result);
  renderLabelTemplateManagerSummary("save", result);
  renderConfigSummary(storeDirectoryState, barcodeSettingsState, labelTemplateState, supplierDirectoryState);
  renderBaleBarcodeDirectorySummary(document.querySelector("#baleBarcodeViewForm [name='shipment_no']")?.value || "");
  renderBalePrintModal();
}

async function submitChinaSourceBale(event) {
  event.preventDefault();
  const pendingImportFileInput = document.querySelector("#chinaSourceImportFile");
  if ((pendingImportFileInput instanceof HTMLInputElement) && pendingImportFileInput.files?.length) {
    const currentRows = syncChinaSourceContainerRowsFromDom();
    if (!hasMeaningfulChinaSourceContainerRows(currentRows)) {
      await loadChinaSourceImportPreviewFromFile(pendingImportFileInput.files[0]);
    }
  }
  const preview = getChinaSourceBalePreviewData();
  if (!preview) {
    throw new Error("中方来源整柜页面还没有准备好，请刷新后再试。");
  }
  if (!preview.container_type) {
    throw new Error("请先选择整柜类型。");
  }
  if (!preview.customs_notice_no) {
    throw new Error("请先填写船单。");
  }
  if (!preview.lines.length) {
    throw new Error("请至少录入一条柜内内容明细。");
  }
  preview.lines.forEach((row, index) => {
    if (!row.package_code) {
      throw new Error(`第 ${index + 1} 行缺少包裹编码。请先在识别框里补全，或重新填写 Excel 模版后再上传。`);
    }
    if (!row.supplier_name || row.supplier_name === "__new__") {
      throw new Error(`第 ${index + 1} 行缺少供应商。请先在识别框里补全供应商，或重新填写 Excel 模版后再上传。`);
    }
    if (!row.category_main) {
      throw new Error(`第 ${index + 1} 行缺少商品大类。请先在识别框里补全，或重新填写 Excel 模版后再上传。`);
    }
    if (!row.category_sub) {
      throw new Error(`第 ${index + 1} 行缺少商品小类。请先在识别框里补全，或重新填写 Excel 模版后再上传。`);
    }
    if (!(Number(row.package_count || 0) > 0)) {
      throw new Error(`第 ${index + 1} 行请填写包数。`);
    }
    if (!(Number(row.unit_weight_kg || 0) > 0)) {
      throw new Error(`第 ${index + 1} 行请填写单包重量。`);
    }
    addSupplierScopedCategoryPair(row.supplier_name, row.category_main, row.category_sub);
  });
  const now = new Date().toISOString();
  const previewResult = {
    ...preview,
    created_at: now,
    updated_at: now,
  };
  const result = await request("/warehouse/china-sources", {
    method: "POST",
    body: JSON.stringify(previewResult),
  });
  chinaSourceBaleState = [
    result,
    ...ensureChinaSourceBaleState().filter((row) => row.source_pool_token !== result.source_pool_token),
  ];
  persistChinaSourceBaleState();
  writeOutput("#chinaSourceBaleOutput", result);
  renderChinaSourceBalePreview(result);
  populateChinaSourceShipmentSelects(result.customs_notice_no);
  populateChinaSourceCostRecordSelect(result.source_pool_token);
  populateDirectHangSourceSelect();
  renderDirectHangUnpackSummary();
  renderChinaSourceCostSummary(result.source_pool_token);
  showTransientInlineNotice("#chinaSourceBaleNotice", `船单 ${result.customs_notice_no} 已完成录入。`, "success", 1800);
  chinaSourceImportPreviewState = [];
  const importFileInput = document.querySelector("#chinaSourceImportFile");
  if (importFileInput instanceof HTMLInputElement) {
    importFileInput.value = "";
  }
  renderChinaSourceImportPreviewSummary();
}

async function submitChinaSourceCost(event) {
  event.preventDefault();
  const formElement = event.currentTarget;
  const form = new FormData(formElement);
  const payload = Object.fromEntries(form.entries());
  const sourcePoolToken = String(payload.source_pool_token || "").trim();
  if (!sourcePoolToken) {
    throw new Error("请先选择一条中方来源记录。");
  }
  const current = getChinaSourceRecordByPoolToken(sourcePoolToken);
  if (!current) {
    throw new Error("当前选中的中方来源记录不存在，请重新选择。");
  }
  const buildStageEntry = async (stageKey) => {
    const files = Array.from(formElement.querySelector(`[name='${stageKey}_files']`)?.files || []);
    const previousDocs = Array.isArray(current.cost_entries?.[stageKey]?.documents) ? current.cost_entries[stageKey].documents : [];
    return {
      currency: String(payload[`${stageKey}_currency`] || "").trim(),
      amount: Number(payload[`${stageKey}_amount`] || 0) || 0,
      payment_method: String(payload[`${stageKey}_payment_method`] || "").trim(),
      payer: String(payload[`${stageKey}_payer`] || "").trim(),
      payment_reference: String(payload[`${stageKey}_reference`] || "").trim(),
      documents: files.length ? await Promise.all(files.map((file) => fileToDataUrl(file))) : previousDocs,
    };
  };
  const costEntries = {
    head_transport: await buildStageEntry("head_transport"),
    customs_clearance: await buildStageEntry("customs_clearance"),
    tail_transport: await buildStageEntry("tail_transport"),
  };
  const result = await request(`/warehouse/china-sources/${encodeURIComponent(sourcePoolToken)}/cost`, {
    method: "PUT",
    body: JSON.stringify({
      cost_entries: costEntries,
    }),
  });
  chinaSourceBaleState = [
    result,
    ...ensureChinaSourceBaleState().filter((row) => String(row?.source_pool_token || "").trim() !== sourcePoolToken),
  ];
  persistChinaSourceBaleState();
  populateChinaSourceCostRecordSelect(sourcePoolToken);
  hydrateChinaSourceCostForm(result);
  renderChinaSourceCostSummary(sourcePoolToken);
  writeOutput("#chinaSourceCostOutput", result);
  showTransientInlineNotice("#chinaSourceCostNotice", `船单 ${result.customs_notice_no} 的成本补填已保存。`, "success", 1800);
}

