async function submitApparelDefaultCost(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const previousRecord = getApparelDefaultCostByCategoryGrade(payload.category_main, payload.category_sub, payload.grade);
  const draftRecord = {
    category_main: String(payload.category_main || "").trim(),
    category_sub: String(payload.category_sub || "").trim(),
    grade: String(payload.grade || "").trim().toUpperCase(),
    default_cost_kes: roundToTwo(Number(payload.default_cost_kes || 0)),
    note: String(payload.note || "").trim(),
  };
  if (!draftRecord.category_main) {
    throw new Error("请先选择商品大类。");
  }
  if (!draftRecord.category_sub) {
    throw new Error("请先选择商品小类。");
  }
  if (!["P", "S"].includes(draftRecord.grade)) {
    throw new Error("等级只支持 P 或 S。");
  }
  if (!(draftRecord.default_cost_kes > 0)) {
    throw new Error("请先填写默认成本价。");
  }
  const record = await request("/warehouse/apparel-default-costs", {
    method: "POST",
    body: JSON.stringify(draftRecord),
  });
  const nextRows = [
    record,
    ...ensureApparelDefaultCostState().filter(
      (row) =>
        !(
          String(row?.category_main || "").trim().toLowerCase() === record.category_main.toLowerCase()
          && String(row?.category_sub || "").trim().toLowerCase() === record.category_sub.toLowerCase()
          && String(row?.grade || "").trim().toUpperCase() === record.grade.toUpperCase()
        ),
    ),
  ];
  apparelDefaultCostState = normalizeApparelDefaultCostRows(nextRows);
  if (previousRecord && roundToTwo(previousRecord.default_cost_kes) !== roundToTwo(record.default_cost_kes)) {
    apparelSortingRackState = normalizeApparelSortingRackRows(
      ensureApparelSortingRackState().filter(
        (row) =>
          !(
            String(row?.category_main || "").trim().toLowerCase() === record.category_main.toLowerCase()
            && String(row?.category_sub || "").trim().toLowerCase() === record.category_sub.toLowerCase()
            && String(row?.grade || "").trim().toUpperCase() === record.grade.toUpperCase()
            && roundToTwo(Number(row?.default_cost_kes || 0)) === roundToTwo(previousRecord.default_cost_kes)
          ),
      ),
    );
    persistApparelSortingRackState();
    hydrateApparelSortingRackForm(null);
    renderApparelSortingRackSummary();
  }
  persistApparelDefaultCostState();
  hydrateApparelDefaultCostForm(record);
  renderApparelDefaultCostSummary(record);
  renderJsonBuilder("sorting-result-items");
  syncJsonBuilderToField("sorting-result-items");
  writeOutput("#apparelDefaultCostOutput", record);
}

