async function submitItemIdentityLedger(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const identityNo = String(form.get("identity_no") || "").trim().toUpperCase();
  if (!identityNo) {
    throw new Error("请先输入商品身份证 ID、token 号或商品 barcode。");
  }
  const directHangLedger = buildDirectHangIdentityLedger(identityNo);
  if (directHangLedger) {
    writeOutput("#itemIdentityLedgerOutput", directHangLedger);
    renderItemIdentityLedgerSummary(directHangLedger);
    return;
  }
  let ledgerLookupValue = identityNo;
  try {
    const resolved = await resolveBarcodeForContext(identityNo, "identity_ledger", ["RAW_BALE", "DISPATCH_BALE", "STORE_ITEM"]);
    if (window.barcodeResolverFlow && typeof window.barcodeResolverFlow.getIdentityLedgerLookupValue === "function") {
      ledgerLookupValue = window.barcodeResolverFlow.getIdentityLedgerLookupValue(identityNo, resolved);
    } else {
      ledgerLookupValue = String(resolved?.identity_id || identityNo).trim().toUpperCase();
    }
  } catch (_error) {
    ledgerLookupValue = identityNo;
  }
  const result = await request(`/warehouse/item-identity-ledger/${encodeURIComponent(ledgerLookupValue)}`);
  writeOutput("#itemIdentityLedgerOutput", result);
  renderItemIdentityLedgerSummary(result);
}

async function submitDirectHangUnpack(event) {
  event.preventDefault();
  const preview = getDirectHangPreviewData();
  if (!preview) {
    throw new Error("请先选择一个中方来源 bale。");
  }
  if (!(preview.unpacked_package_count > 0)) {
    throw new Error("请先填写本次拆包包数。");
  }
  if (preview.unpacked_package_count > preview.remaining_package_count) {
    throw new Error(`本次最多还能拆 ${preview.remaining_package_count} 包，请先检查已确认记录。`);
  }
  if (!(preview.counted_piece_qty > 0)) {
    throw new Error("请先填写实际点数。");
  }
  if (!(preview.unit_cost_amount > 0)) {
    throw new Error("当前单件成本还没算出来，请检查包裹单价和点数。");
  }
  const result = {
    ...preview,
    created_at: new Date().toISOString(),
    status: "cost_locked",
  };
  directHangUnpackState = [
    result,
    ...ensureDirectHangUnpackState().filter((row) => row.direct_hang_unwrap_no !== result.direct_hang_unwrap_no),
  ];
  persistDirectHangUnpackState();
  populateDirectHangSourceSelect();
  renderDirectHangUnpackSummary(result);
  writeOutput("#directHangUnpackOutput", result);
  showTransientInlineNotice("#directHangUnpackNotice", `来源 bale ${result.source_bale_token} 的单件成本已锁定。`, "success", 1800);
}

async function submitDirectHangTransfer(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const unpackNo = String(payload.direct_hang_unwrap_no || "").trim().toUpperCase();
  const unpack = getDirectHangUnpackByNo(unpackNo);
  if (!unpack) {
    throw new Error("请先选择一条已锁单件成本的直挂拆包记录。");
  }
  const allocatedQty = Number(payload.allocated_qty || 0);
  if (!(allocatedQty > 0)) {
    throw new Error("请先填写要发去门店的件数。");
  }
  const remainingQty = getRemainingDirectHangQty(unpackNo);
  if (allocatedQty > remainingQty) {
    throw new Error(`当前最多还能分配 ${remainingQty} 件，请检查已生成的直挂调拨草稿。`);
  }
  const result = {
    transfer_no: buildDirectHangTransferNo(),
    flow_type: "direct_hang",
    direct_hang_unwrap_no: unpack.direct_hang_unwrap_no || "",
    source_pool_token: unpack.source_pool_token || "",
    source_bale_token: unpack.source_bale_token || "",
    customs_notice_no: unpack.customs_notice_no || "",
    supplier_name: unpack.supplier_name || "",
    category_main: unpack.category_main || "",
    category_sub: unpack.category_sub || "",
    unit_cost_amount: unpack.unit_cost_amount || 0,
    unit_cost_kes: unpack.unit_cost_kes || 0,
    unit_cost_currency: unpack.source_unit_cost_currency || "",
    allocated_qty: allocatedQty,
    from_warehouse_code: "WH1",
    to_store_code: String(payload.to_store_code || "").trim().toUpperCase(),
    note: String(payload.note || "").trim(),
    approval_status: "not_required",
    status: "approved",
    dispatch_bale_count: 0,
    accepted_dispatch_bale_count: 0,
    completed_dispatch_bale_count: 0,
    dispatch_grouping_mode: "by_category",
    dispatch_max_items_per_bale: 30,
    created_at: new Date().toISOString(),
    items: [
      {
        source_bale_token: unpack.source_bale_token || "",
        requested_qty: allocatedQty,
        category_main: unpack.category_main || "",
        category_sub: unpack.category_sub || "",
        supplier_name: unpack.supplier_name || "",
      },
    ],
  };
  directHangDispatchOrderState = [result, ...ensureDirectHangDispatchOrderState()];
  persistDirectHangDispatchOrderState();
  populateDirectHangTransferSelect();
  renderDirectHangTransferSummary(result);
  writeOutput("#directHangTransferOutput", result);
  renderTransferDispatchSummary(transferOrderState);
}

async function submitDirectHangBundle(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const transferNo = String(payload.transfer_no || "").trim().toUpperCase();
  const order = ensureDirectHangDispatchOrderState().find(
    (row) => String(row?.transfer_no || "").trim().toUpperCase() === transferNo,
  );
  if (!order) {
    throw new Error("这张直挂门店调拨号不存在，请先回上一步生成草稿。");
  }
  const maxItemsPerBale = Math.max(1, Number(payload.max_items_per_bale || 30));
  const baleCount = Math.ceil(Number(order.allocated_qty || 0) / maxItemsPerBale);
  if (!(baleCount > 0)) {
    throw new Error("当前调拨草稿没有可拆分的件数。");
  }
  const generated = [];
  let remaining = Number(order.allocated_qty || 0);
  for (let index = 0; index < baleCount; index += 1) {
    const itemCount = Math.min(maxItemsPerBale, remaining);
    remaining -= itemCount;
    generated.push({
      bale_no: buildDirectHangDispatchBaleNo(order.to_store_code || "STORE"),
      flow_type: "direct_hang",
      transfer_no: order.transfer_no || "",
      store_code: order.to_store_code || "",
      shipment_no: order.customs_notice_no || "",
      task_no: "",
      source_bale_token: order.source_bale_token || "",
      direct_hang_unwrap_no: order.direct_hang_unwrap_no || "",
      supplier_name: order.supplier_name || "",
      category_name: `${order.category_main || "-"} / ${order.category_sub || "-"}`,
      category_summary: `${order.category_main || "-"} / ${order.category_sub || "-"}`,
      item_count: itemCount,
      unit_cost_kes: order.unit_cost_kes || 0,
      status: "pending_acceptance",
      assigned_employee: "",
      created_at: new Date().toISOString(),
    });
  }
  directHangDispatchBaleState = [
    ...generated,
    ...ensureDirectHangDispatchBaleState(),
  ];
  persistDirectHangDispatchBaleState();
  directHangDispatchOrderState = ensureDirectHangDispatchOrderState().map((row) => (
    String(row?.transfer_no || "").trim().toUpperCase() === transferNo
      ? {
          ...row,
          dispatch_bale_count: generated.length,
          dispatch_max_items_per_bale: maxItemsPerBale,
          status: "dispatched",
          dispatched_at: new Date().toISOString(),
        }
      : row
  ));
  persistDirectHangDispatchOrderState();
  writeOutput("#transferActionOutput", { transfer_no: transferNo, generated_bale_count: generated.length, store_dispatch_bales: generated });
  renderTransferActionResultSummary({
    transfer_no: transferNo,
    flow_type: "direct_hang",
    generated_bale_count: generated.length,
    store_dispatch_bales: generated,
  });
  renderTransferDispatchSummary(transferOrderState);
}

async function submitDevTask(event) {
  event.preventDefault();
  ensureDevTrackerState();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const taskId = String(payload.task_id || "").trim();
  const title = String(payload.title || "").trim();
  if (!title) {
    throw new Error("请先填写事项标题。");
  }
  const existing = devTrackerState.items.find((row) => row.id === taskId);
  const track = String(payload.track || "backlog").trim();
  const bucket = String(payload.bucket || "current").trim();
  const nextGroupKey = getDevGroupKey({ track, bucket });
  const previousGroupKey = existing ? getDevGroupKey(existing) : "";
  const nextOrderBase = Math.max(0, ...getDevGroupRows(nextGroupKey).map((row) => row.order || 0)) + 10;
  const row = {
    id: existing?.id || createDevTaskId(),
    track,
    bucket,
    order: existing && previousGroupKey === nextGroupKey ? existing.order : nextOrderBase,
    title,
    detail: String(payload.detail || "").trim(),
    status: String(payload.status || "todo").trim(),
    priority: String(payload.priority || "medium").trim(),
    module: String(payload.module || "general").trim(),
    next_action: String(payload.next_action || "").trim(),
  };
  devTrackerState.items = [
    row,
    ...devTrackerState.items.filter((item) => item.id !== row.id),
  ];
  resequenceAllDevTrackerGroups();
  persistDevTrackerState();
  renderDevTrackerSummary();
  hydrateDevTaskForm(row);
  showTransientSummary("#devTrackerSummary", `开发事项已保存：${row.title}`, 1200);
}

