async function submitReturnSelection(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const mode = getReturnSelectionMode();
  const allBarcodes = returnCandidatesState.map((row) => row.barcode);
  const selectedBarcodes = [...selectedReturnBarcodes];
  if (!allBarcodes.length) {
    throw new Error("请先读取门店可退清单。");
  }
  if (mode === "partial" && !selectedBarcodes.length) {
    throw new Error("部分退仓模式下，至少勾选一个商品。");
  }
  payload.select_all = mode === "all";
  payload.selected_barcodes = mode === "partial" ? selectedBarcodes : [];
  payload.excluded_barcodes =
    mode === "all" ? allBarcodes.filter((barcode) => !selectedReturnBarcodes.has(barcode)) : [];
  const result = await request("/returns/from-selection", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  writeOutput("#returnOutput", result);
  renderReturnResultSummary(result);
  hydrateReturnForms(result);
  await loadDashboard();
}

