async function submitLoosePackingTaskPlan(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const transferNo = String(form.get("transfer_no") || "").trim().toUpperCase();
  if (!transferNo) {
    throw new Error("请先填写调拨单号。");
  }
  const transfer = getTransferPreparationOrder(transferNo);
  if (!transfer?.transfer_no) {
    throw new Error("系统里还没有这张调拨单，请先从 5 页创建或读取调拨单。");
  }
  const packageLimitQty = getLoosePackingPackageLimitQty(Number(form.get("package_limit_qty") || 200));
  const plan = buildTransferPreparationPlan(getTransferPreparationPlanRows(transfer));
  const existingRecord = getTransferExecutionRecord(transferNo, { create: false, plan });
  const tasks = buildLoosePackingTasksForTransfer(transferNo, plan, { packageLimitQty });
  setTransferPrepExecutionRecord(transferNo, {
    transferNo,
    demandLines: getTransferPreparationPlanRows(transfer),
    packageLimitQty,
    foundPreparedBarcodes: existingRecord.foundPreparedBarcodes,
    looseTasks: tasks,
  });
  activeTransferPreparationNo = transferNo;
  writeOutput("#loosePackingTaskOutput", tasks);
  renderReplenishmentFlowSummary(transfer);
  renderLoosePackingTaskWorkbench(transfer);
  renderTransferExecutionWorkbench(transfer);
  showTransientInlineNotice(
    "#loosePackingTaskPlanNotice",
    tasks.length ? `已为 ${transferNo} 生成 1 张补差拣货单 barcode。` : `这张调拨单没有散货补差，不需要生成工单。`,
    "success",
    2200,
  );
}

async function submitPreparedBaleRegistration(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const transferNo = String(form.get("transfer_no") || "").trim().toUpperCase();
  const barcode = String(form.get("prepared_bale_barcode") || "").trim().toUpperCase();
  if (!transferNo) {
    throw new Error("请先填写调拨单号。");
  }
  const transfer = getTransferPreparationOrder(transferNo);
  if (!transfer?.transfer_no) {
    throw new Error("系统里还没有这张调拨单，请先从 5 页创建或读取调拨单。");
  }
  const plan = buildTransferPreparationPlan(getTransferPreparationPlanRows(transfer));
  const executionRecord = getTransferExecutionRecord(transferNo, { create: true, plan });
  const scanResult = typeof operationsFulfillmentFlow.registerPreparedBaleScan === "function"
    ? operationsFulfillmentFlow.registerPreparedBaleScan({
      plan,
      foundPreparedBarcodes: executionRecord.foundPreparedBarcodes,
      barcode,
    })
    : { ok: false, error: "现成包扫码登记能力还没加载。", foundPreparedBarcodes: executionRecord.foundPreparedBarcodes };
  if (!scanResult.ok) {
    throw new Error(scanResult.error || "现成包扫码登记失败。");
  }
  setTransferPrepExecutionRecord(transferNo, {
    transferNo,
    demandLines: getTransferPreparationPlanRows(transfer),
    packageLimitQty: executionRecord.packageLimitQty,
    foundPreparedBarcodes: scanResult.foundPreparedBarcodes,
    looseTasks: executionRecord.looseTasks,
  });
  activeTransferPreparationNo = transferNo;
  writeOutput("#preparedBaleRegistrationOutput", {
    transfer_no: transferNo,
    barcode,
    duplicate: scanResult.duplicate,
    matched_row: scanResult.matchedRow || null,
  });
  renderReplenishmentFlowSummary(transfer);
  renderLoosePackingTaskWorkbench(transfer);
  renderTransferExecutionWorkbench(transfer);
  const barcodeInput = event.currentTarget.querySelector("[name='prepared_bale_barcode']");
  if (barcodeInput instanceof HTMLInputElement) {
    barcodeInput.value = "";
    barcodeInput.focus();
  }
  showTransientInlineNotice(
    "#preparedBaleRegistrationNotice",
    scanResult.duplicate
      ? `${barcode} 之前已经登记过，保留当前状态。`
      : `已登记 ${barcode}，可以继续找下一包现成包。`,
    "success",
    2200,
  );
}

async function loadTransferPlanningContext({ force = false } = {}) {
  if (!currentSession?.token) {
    renderReplenishmentFlowSummary();
    renderLoosePackingTaskWorkbench();
    renderTransferPreparationPlanSummary();
    renderTransferExecutionWorkbench();
    return [];
  }
  await loadStorePrepBaleWorkbench({ force, focus: false });
  await loadTransferOrders();
  renderReplenishmentFlowSummary();
  renderLoosePackingTaskWorkbench();
  renderTransferPreparationPlanSummary();
  renderTransferExecutionWorkbench();
  return transferOrderState;
}

async function loadTransferOrders() {
  transferOrderState = await request("/transfers");
  try {
    storeDispatchBaleState = await request("/stores/dispatch-bales");
    filteredStoreDispatchBaleState = storeDispatchBaleState;
  } catch (error) {
    storeDispatchBaleState = [];
    filteredStoreDispatchBaleState = [];
  }
  renderTransferDispatchSummary(transferOrderState);
  renderStoreManagerConsoleSummary({ store_code: getCurrentStoreCodeFallback() });
  renderStoreClerkHomeSummary({
    store_code: getCurrentStoreCodeFallback(),
    assigned_employee: getCurrentStoreWorkerFallback(),
  });
  renderReplenishmentFlowSummary();
  renderLoosePackingTaskWorkbench();
  renderTransferExecutionWorkbench();
  return transferOrderState;
}

async function submitStartReceivingSession(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  if (!String(payload.store_code || "").trim()) {
    payload.store_code = getCurrentStoreCodeFallback();
    setInputValue("#startReceivingSessionForm [name='store_code']", payload.store_code);
  }
  if (!String(payload.bale_no || "").trim()) {
    payload.bale_no = String(document.querySelector("#storeBluetoothPrinterForm [name='bale_no']")?.value || "").trim().toUpperCase();
    if (payload.bale_no) {
      setInputValue("#startReceivingSessionForm [name='bale_no']", payload.bale_no);
    }
  }
  if (String(payload.bale_no || "").trim()) {
    const resolvedBale = await resolveBarcodeForContext(payload.bale_no, "store_pda", ["DISPATCH_BALE"]);
    payload.bale_no = window.barcodeResolverFlow && typeof window.barcodeResolverFlow.getCanonicalBarcodeForContext === "function"
      ? window.barcodeResolverFlow.getCanonicalBarcodeForContext({
        inputBarcode: payload.bale_no,
        resolved: resolvedBale,
        context: "store_pda",
      })
      : String(resolvedBale.object_id || payload.bale_no).trim().toUpperCase();
    setInputValue("#startReceivingSessionForm [name='bale_no']", payload.bale_no);
  }
  const result = await request("/store-token-receiving-sessions/start", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  writeOutput("#receivingOutput", result);
  renderReceivingResultSummary(result);
  hydrateReceivingSessionForms(result);
  await loadDashboard();
}

