async function submitTransferBundle(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const transferNo = String(payload.transfer_no || "").trim().toUpperCase();
  const transfer = getTransferPreparationOrder(transferNo);
  const plan = buildTransferPreparationPlan(getTransferPreparationPlanRows(transfer || transferNo));
  const readiness = summarizeTransferExecutionState(transferNo, plan);
  if (!readiness.canPrint) {
    const pendingNotes = [];
    if (readiness.pendingPreparedCount > 0) {
      pendingNotes.push(`现成包还有 ${readiness.pendingPreparedCount} 包未登记`);
    }
    if (readiness.pendingLooseTaskCount > 0) {
      pendingNotes.push(`补差拣货单还有 ${readiness.pendingLooseTaskCount} 张未完成`);
    }
    throw new Error(`还不能打印最终送店 bale：${pendingNotes.join("，")}。`);
  }
  delete payload.transfer_no;
  payload.copies = Number(payload.copies);
  payload.max_items_per_bale = Number(payload.max_items_per_bale);
  payload.printer_name = "Deli DL-720C";
  const result = await request(`/print-jobs/transfers/${transferNo}/dispatch-bundle`, {
    method: "POST",
    body: JSON.stringify(payload),
  });
  activeTransferPreparationNo = String(transferNo || "").trim().toUpperCase();
  const executionRecord = getTransferExecutionRecord(transferNo, { create: false, plan });
  const displayStoreDispatchBales = typeof operationsFulfillmentFlow.buildTransferDispatchResultDisplayRows === "function"
    ? operationsFulfillmentFlow.buildTransferDispatchResultDisplayRows({
      result,
      plan,
      looseTasks: executionRecord.looseTasks,
    })
    : result.store_dispatch_bales;
  const displayResult = {
    ...result,
    display_store_dispatch_bales: displayStoreDispatchBales,
    display_generated_bale_count: Array.isArray(displayStoreDispatchBales) ? displayStoreDispatchBales.length : result.generated_bale_count,
  };
  writeOutput("#transferActionOutput", displayResult);
  renderTransferActionResultSummary(displayResult);
  hydratePrintJobForms([result.transfer_print_job, ...(result.label_print_jobs || [])]);
  writeOutput("#labelPrintOutput", result.label_print_jobs || []);
  renderLabelPrintResultSummary(result.label_print_jobs || []);
  renderReplenishmentFlowSummary(transferNo);
  renderLoosePackingTaskWorkbench(transferNo);
  openTransferDispatchPrintTemplateModal({
    transferNo,
    transfer: transfer || getTransferPreparationOrder(transferNo) || {},
    displayRows: displayStoreDispatchBales,
  });
  await loadTransferOrders();
}

