async function submitSale(event) {
  event.preventDefault();
  syncJsonBuilderToField("sale-items");
  syncJsonBuilderToField("sale-payments");
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  payload.items = parseJsonField(payload.items_json, []);
  delete payload.items_json;
  payload.payments = parseJsonField(payload.payments_json, []);
  delete payload.payments_json;
  const result = await request("/sales", {
    method: "POST",
    body: JSON.stringify(payload),
  });
  writeOutput("#saleOutput", result);
  renderSaleResultSummary(result);
  if (result.shift_no) {
    setInputValue("#shiftReportForm [name='shift_no']", result.shift_no);
    setInputValue("#handoverRequestForm [name='shift_no']", result.shift_no);
    setInputValue("#closeBusinessReportForm [name='shift_no']", result.shift_no);
  }
  if (result.order_no) {
    setInputValue("#saleVoidRequestForm [name='order_no']", result.order_no);
    setInputValue("#saleRefundRequestForm [name='order_no']", result.order_no);
    setJsonField(
      "#saleRefundRequestForm [name='items_json']",
      (result.items || []).map((item) => ({
        barcode: item.barcode,
        qty: 1,
        note: "customer return",
      })),
    );
  }
  if (result.shift_no) {
    setInputValue("#saleRefundRequestForm [name='shift_no']", result.shift_no);
  }
  if (Array.isArray(result.payment_anomaly_nos) && result.payment_anomaly_nos.length) {
    setInputValue("#paymentAnomalyResolveForm [name='anomaly_no']", result.payment_anomaly_nos[0]);
    await loadTable("load-payment-anomalies");
  }
  await loadDashboard();
  cashierTerminalState.latestCompletedSale = result;
  syncCashierTerminalShift(result);
  renderCashierTerminal();
  return result;
}

