async function submitPaymentAnomalyResolve(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const anomalyNo = payload.anomaly_no?.trim();
  if (!anomalyNo) {
    throw new Error("请先读取支付异常单，或先完成一笔带异常的销售。");
  }
  if (!payload.action?.trim()) {
    throw new Error("请先选择处理动作。");
  }
  if (!String(payload.amount || "").trim()) {
    delete payload.amount;
  } else {
    payload.amount = Number(payload.amount);
  }
  delete payload.anomaly_no;
  const result = await request(`/payments/anomalies/${encodeURIComponent(anomalyNo)}/resolve`, {
    method: "POST",
    body: JSON.stringify(payload),
  });
  writeOutput("#paymentAnomalyOutput", result);
  renderPaymentAnomalyResultSummary(result);
  await loadTable("load-payment-anomalies");
  await loadDashboard();
  syncCashierTerminalDraftsFromForms();
  renderCashierTerminal();
  return result;
}

