async function submitLookup(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const payload = Object.fromEntries(form.entries());
  const resolved = await resolveBarcodeForContext(payload.barcode, "pos", ["STORE_ITEM"]);
  const result = await request(`/stores/${payload.store_code}/stock/${payload.barcode}`);
  if (window.barcodeResolverFlow && typeof window.barcodeResolverFlow.getCanonicalBarcodeForContext === "function") {
    result.barcode = window.barcodeResolverFlow.getCanonicalBarcodeForContext({
      inputBarcode: payload.barcode,
      resolved,
      stockResult: result,
      context: "pos",
    });
  }
  writeOutput("#lookupOutput", result);
  renderLookupResultSummary(result);
  cashierTerminalState.currentLookupResult = result;
  renderCashierTerminal();
  return result;
}

