function bindForm(id, handler, outputSelector = "#authOutput") {
  const form = document.querySelector(id);
  if (form) {
    form.addEventListener("submit", async (event) => {
      try {
        await handler(event);
      } catch (error) {
        const message = formatErrorMessage(error);
        if (id === "#sortingTaskForm") {
          writeOutput(outputSelector, "");
          showTransientInlineNotice("#sortingTaskNotice", message, "error", 2200);
          return;
        }
        const summarySelector = FORM_SUMMARY_SELECTORS[id];
        if (summarySelector) {
          writeOutput(outputSelector, "");
          if (["#transferForm", "#approveTransferForm", "#transferBundleForm"].includes(id)) {
            renderTransferExecutionErrorSummary(summarySelector, message);
          } else {
            renderErrorSummary(summarySelector, message);
          }
        } else {
          writeOutput(outputSelector, message);
        }
      }
    });
  }
}

