cashierTerminalScanForm?.addEventListener("submit", async (event) => {
  event.preventDefault();
  try {
    const action = event.submitter?.dataset?.terminalSubmit || "add";
    await submitCashierTerminalLookup({ addToCart: action !== "lookup" });
  } catch (error) {
    showTransientInlineNotice("#cashierTerminalInlineNotice", formatErrorMessage(error), "error", 2200);
  }
});

cashierTerminalShell?.addEventListener("click", async (event) => {
  const target = event.target instanceof HTMLElement
    ? event.target.closest("[data-terminal-action], [data-terminal-payment-mode], [data-terminal-cart-remove], [data-terminal-payment-remove], [data-terminal-locale]")
    : null;
  if (!(target instanceof HTMLElement)) {
    return;
  }
  try {
    if (target.dataset.terminalLocale) {
      cashierTerminalState.locale = target.dataset.terminalLocale;
      updateCashierTerminalClock();
      renderCashierTerminal();
      return;
    }
    if (target.dataset.terminalPaymentMode) {
      setCashierTerminalPaymentMode(target.dataset.terminalPaymentMode);
      return;
    }
    if (target.dataset.terminalCartRemove) {
      cashierTerminalState.cartItems = cashierTerminalState.cartItems.filter((_, index) => index !== Number(target.dataset.terminalCartRemove));
      renderCashierTerminal();
      focusCashierTerminalScanInput({ select: false });
      return;
    }
    if (target.dataset.terminalPaymentRemove) {
      removeCashierTerminalPaymentLine(Number(target.dataset.terminalPaymentRemove));
      return;
    }
    await handleCashierTerminalAction(target.dataset.terminalAction || "", target);
  } catch (error) {
    showTransientInlineNotice("#cashierTerminalInlineNotice", formatErrorMessage(error), "error", 2200);
  }
});

cashierTerminalShell?.addEventListener("input", (event) => {
  const target = event.target instanceof HTMLElement ? event.target : null;
  if (!(target instanceof HTMLElement)) {
    return;
  }
  if (target === cashierTerminalSaleNoteInput) {
    cashierTerminalState.note = String(target.value || "");
    return;
  }
  if (target.dataset.terminalCartField) {
    updateCashierTerminalCartField(Number(target.dataset.terminalCartIndex || -1), target.dataset.terminalCartField, target.value);
    return;
  }
  if (target.dataset.terminalPaymentField) {
    updateCashierTerminalPaymentField(
      target.dataset.terminalPaymentField,
      target.value,
      target.dataset.terminalPaymentIndex ? Number(target.dataset.terminalPaymentIndex) : null,
    );
    return;
  }
  if (target.dataset.terminalDrawerField) {
    updateCashierTerminalDrawerField(target.dataset.terminalDrawerField, target.value);
  }
});

cashierTerminalShell?.addEventListener("change", (event) => {
  const target = event.target instanceof HTMLElement ? event.target : null;
  if (!(target instanceof HTMLElement)) {
    return;
  }
  if (target.dataset.terminalPaymentField) {
    updateCashierTerminalPaymentField(
      target.dataset.terminalPaymentField,
      target.value,
      target.dataset.terminalPaymentIndex ? Number(target.dataset.terminalPaymentIndex) : null,
    );
    return;
  }
  if (target.dataset.terminalDrawerField) {
    updateCashierTerminalDrawerField(target.dataset.terminalDrawerField, target.value);
    renderCashierTerminal();
  }
});

