async function handlePanelJumpEvent(event) {
  const toggle = event.target instanceof HTMLElement ? event.target.closest("[data-section-toggle]") : null;
  if (toggle instanceof HTMLElement) {
    const sectionId = toggle.dataset.sectionToggle;
    if (sectionId) {
      expandOnlyWorkspaceSection(activeWorkspace, sectionId);
      renderWorkspacePageNav();
    }
    return;
  }
  const inboundStepButton = event.target instanceof HTMLElement ? event.target.closest("[data-open-inbound-step]") : null;
  if (inboundStepButton instanceof HTMLElement) {
    const step = inboundStepButton.dataset.openInboundStep || "";
    const shipmentNo = inboundStepButton.dataset.shipmentNo || "";
    if (step) {
      openInboundFlowStep(step, shipmentNo);
    }
    return;
  }
  const inboundEditorButton = event.target instanceof HTMLElement ? event.target.closest("[data-open-inbound-editor]") : null;
  if (inboundEditorButton instanceof HTMLElement) {
    const shipmentNo = inboundEditorButton.dataset.openInboundEditor || "";
    openInboundShipmentEditor(shipmentNo);
    return;
  }
  const intakeActionButton = event.target instanceof HTMLElement ? event.target.closest("[data-intake-action]") : null;
  if (intakeActionButton instanceof HTMLElement) {
    const action = intakeActionButton.dataset.intakeAction || "";
    const shipmentNo = intakeActionButton.dataset.shipmentNo || "";
    setCurrentInboundShipment(shipmentNo);
    if (action === "confirm") {
      document.querySelector("#shipmentIntakeConfirmForm")?.requestSubmit();
      return;
    }
    if (action === "generate") {
      document.querySelector("#generateBaleBarcodesForm")?.requestSubmit();
      return;
    }
    if (action === "barcodes") {
      openInboundFlowStep("barcodes", shipmentNo);
      return;
    }
    if (action === "printer") {
      openInboundFlowStep("printer", shipmentNo);
      return;
    }
  }
  const warehouseHubJumpButton = event.target instanceof HTMLElement ? event.target.closest("[data-warehouse-hub-jump]") : null;
  if (warehouseHubJumpButton instanceof HTMLElement) {
    const targetKey = String(warehouseHubJumpButton.dataset.warehouseHubJump || "").trim();
    const action = getWarehouseHubPageTargets().find((row) => row.key === targetKey);
    if (!action) {
      return;
    }
    setActivePanel(action.panelKey);
    if (action.loadAction) {
      try {
        await loadTable(action.loadAction);
      } catch (error) {
        if (targetKey === "dispatch_history") {
          writeOutput("#warehouseDispatchHistoryOutput", formatErrorMessage(error));
          renderErrorSummary("#warehouseDispatchHistorySummary", formatErrorMessage(error));
        } else if (targetKey === "sold_history") {
          writeOutput("#warehouseSoldPackagesOutput", formatErrorMessage(error));
          renderErrorSummary("#warehouseSoldPackagesSummary", formatErrorMessage(error));
        } else if (targetKey === "sorted_inventory") {
          writeOutput("#sortingStockOutput", formatErrorMessage(error));
          renderErrorSummary("#sortingStockNotice", formatErrorMessage(error));
        }
      }
    } else if (action.focusSelector) {
      focusElement(action.focusSelector);
    }
    return;
  }
  const button = event.target instanceof HTMLElement ? event.target.closest("[data-panel-jump]") : null;
  if (!(button instanceof HTMLElement)) {
    return;
  }
  const panelKey = button.dataset.panelJump;
  if (panelKey) {
    setActivePanel(panelKey);
  }
}

