function handleJsonBuilderInputEvent(event) {
  const target = event.target instanceof HTMLElement ? event.target.closest("[data-builder-input]") : null;
  if (!(target instanceof HTMLInputElement || target instanceof HTMLSelectElement)) {
    return;
  }
  const builderId = target.dataset.builderInput;
  if (!builderId) {
    return;
  }
  jsonBuilderState[builderId] = getBuilderRowsFromDom(builderId);
  const fieldKey = String(target.dataset.fieldKey || "").trim();
  const rowIndex = Number(target.dataset.rowIndex || -1);
  if (builderId === "sorting-result-items") {
    const rows = jsonBuilderState[builderId] || [];
    if (fieldKey === "category_main") {
      resetBuilderCategorySubIfNeeded(rows, rowIndex);
    }
    if (["category_main", "category_sub", "grade"].includes(fieldKey)) {
      setJsonBuilderRows(builderId, rows);
      syncJsonBuilderToField(builderId);
      return;
    }
    if (["actual_weight_kg", "qty"].includes(fieldKey)) {
      syncJsonBuilderToField(builderId);
      refreshSortingResultCostDisplays();
      renderSortingResultTaskSummary();
      return;
    }
  }
  syncJsonBuilderToField(builderId);
  if (builderId === "sorting-handler-names") {
    refreshSortingShipmentOptions();
    return;
  }
  if (builderId === "transfer-items") {
    if (fieldKey === "category_main") {
      const rows = jsonBuilderState[builderId] || [];
      autoFillTransferCategorySub(rows, rowIndex);
      setJsonBuilderRows(builderId, rows);
      syncJsonBuilderToField(builderId);
    }
    renderTransferDraftSummary();
    return;
  }
}

document.addEventListener("input", handleJsonBuilderInputEvent);
document.addEventListener("change", handleJsonBuilderInputEvent);

document.addEventListener("click", async (event) => {
  const target = event.target instanceof HTMLElement ? event.target.closest("[data-builder-add], [data-builder-remove]") : null;
  if (!(target instanceof HTMLElement)) {
    return;
  }
  if (target.dataset.builderAdd) {
    const builderId = target.dataset.builderAdd;
    const config = getBuilderConfig(builderId);
    const rows = getBuilderRowsFromDom(builderId);
    const nextRow = config.emptyRow();
    if (builderId === "transfer-items") {
      const lastRowWithCategory = [...rows].reverse().find((row) => String(row?.category_main || "").trim());
      if (lastRowWithCategory) {
        nextRow.category_main = String(lastRowWithCategory.category_main || "").trim();
      }
      rows.push(nextRow);
      autoFillTransferCategorySub(rows, rows.length - 1);
    } else {
      rows.push(nextRow);
    }
    setJsonBuilderRows(builderId, rows);
    syncJsonBuilderToField(builderId);
    if (builderId === "sorting-handler-names") {
      refreshSortingShipmentOptions();
      return;
    }
    if (builderId === "transfer-items") {
      renderTransferDraftSummary();
      return;
    }
    return;
  }
  if (target.dataset.builderRemove) {
    const builderId = target.dataset.builderRemove;
    const rowIndex = Number(target.dataset.rowIndex);
    const config = getBuilderConfig(builderId);
    const rows = getBuilderRowsFromDom(builderId).filter((_, index) => index !== rowIndex);
    setJsonBuilderRows(builderId, rows.length ? rows : [config.emptyRow()]);
    syncJsonBuilderToField(builderId);
    if (builderId === "sorting-handler-names") {
      refreshSortingShipmentOptions();
      return;
    }
    if (builderId === "transfer-items") {
      renderTransferDraftSummary();
      return;
    }
  }
});

