document.querySelector("#loosePackingTaskList")?.addEventListener("click", async (event) => {
  const button = event.target instanceof HTMLElement ? event.target.closest("[data-loose-task-action]") : null;
  if (!(button instanceof HTMLElement)) {
    return;
  }
  const transferNo = String(button.dataset.transferNo || activeTransferPreparationNo || "").trim().toUpperCase();
  const taskNo = String(button.dataset.looseTaskNo || "").trim().toUpperCase();
  const action = String(button.dataset.looseTaskAction || "").trim();
  if (!transferNo || !taskNo) {
    return;
  }
  const transfer = getTransferPreparationOrder(transferNo);
  const plan = buildTransferPreparationPlan(getTransferPreparationPlanRows(transfer || transferNo));
  const executionRecord = getTransferExecutionRecord(transferNo, { create: true, plan });
  if (action === "print-label") {
    try {
      const task = executionRecord.looseTasks.find((row) => String(row?.taskNo || "").trim().toUpperCase() === taskNo);
      if (!task) {
        throw new Error("系统里没有找到这张补差拣货单。");
      }
      const job = openLoosePickSheetPrintTemplateModal(task, transfer || {});
      writeOutput("#loosePackingTaskOutput", {
        action: "open_loose_pick_sheet_template_selector",
        task_no: taskNo,
        template_code: job.template_code,
        template_scope: job.print_payload?.template_scope || "warehouseout_bale",
        print_job: job,
      });
      showTransientInlineNotice(
        "#loosePackingTaskPlanNotice",
        `${taskNo} 已打开模板选择页，请在弹层里选择模板并打印。`,
        "success",
        2200,
      );
    } catch (error) {
      showTransientInlineNotice(
        "#loosePackingTaskPlanNotice",
        error?.message || "补差拣货单发送标签机失败。",
        "error",
        3200,
      );
    }
    return;
  }
  const nextStatus = action === "pack" ? "packed" : "picking";
  const nextTasks = typeof operationsFulfillmentFlow.updateLoosePackingTaskStatus === "function"
    ? operationsFulfillmentFlow.updateLoosePackingTaskStatus({
      tasks: executionRecord.looseTasks,
      taskNo,
      nextStatus,
    })
    : executionRecord.looseTasks;
  setTransferPrepExecutionRecord(transferNo, {
    transferNo,
    demandLines: getTransferPreparationPlanRows(transfer || transferNo),
    packageLimitQty: executionRecord.packageLimitQty,
    foundPreparedBarcodes: executionRecord.foundPreparedBarcodes,
    looseTasks: nextTasks,
  });
  activeTransferPreparationNo = transferNo;
  renderReplenishmentFlowSummary(transfer || transferNo);
  renderLoosePackingTaskWorkbench(transfer || transferNo);
  renderTransferExecutionWorkbench(transfer || transferNo);
  showTransientInlineNotice(
    "#loosePackingTaskPlanNotice",
    nextStatus === "packed" ? `${taskNo} 已确认拣货并封包。` : `${taskNo} 已进入拣货中。`,
    "success",
    1800,
  );
});

