document.addEventListener("click", async (event) => {
  const costLoadButton = event.target instanceof HTMLElement ? event.target.closest("[data-china-source-cost-load]") : null;
  if (costLoadButton instanceof HTMLElement) {
    const sourcePoolToken = String(costLoadButton.dataset.chinaSourceCostLoad || "").trim();
    const record = getChinaSourceRecordByPoolToken(sourcePoolToken);
    if (!record) {
      return;
    }
    populateChinaSourceCostRecordSelect(sourcePoolToken);
    hydrateChinaSourceCostForm(record);
    renderChinaSourceCostSummary(sourcePoolToken);
    const panelKey = getPanelKeyByTitle("warehouse", "4.3 中方来源列表 / 补填成本");
    if (panelKey) {
      setActivePanel(panelKey);
    }
    focusElement("#chinaSourceCostForm");
    return;
  }
  const chinaActionButton = event.target instanceof HTMLElement
    ? event.target.closest("[data-china-source-row-add], [data-china-source-row-remove], [data-china-source-category-save]")
    : null;
  if (chinaActionButton instanceof HTMLElement) {
    if (chinaActionButton.dataset.chinaSourceRowAdd !== undefined) {
      syncChinaSourceContainerRowsFromDom();
      chinaSourceContainerRowState.push(emptyChinaSourceContainerRow());
      renderChinaSourceContainerRows();
      renderChinaSourceBalePreview();
      renderChinaSourceImportPreviewSummary();
      return;
    }
    if (chinaActionButton.dataset.chinaSourceRowRemove) {
      const rowIndex = Number(chinaActionButton.dataset.chinaSourceRowRemove || -1);
      syncChinaSourceContainerRowsFromDom();
      chinaSourceContainerRowState = chinaSourceContainerRowState.filter((_, index) => index !== rowIndex);
      if (!chinaSourceContainerRowState.length) {
        chinaSourceContainerRowState = [emptyChinaSourceContainerRow()];
      }
      renderChinaSourceContainerRows();
      renderChinaSourceBalePreview();
      renderChinaSourceImportPreviewSummary();
      return;
    }
    if (chinaActionButton.dataset.chinaSourceCategorySave !== undefined) {
      const form = document.querySelector("#chinaSourceBaleForm");
      if (!(form instanceof HTMLFormElement)) {
        return;
      }
      const inlinePanel = document.querySelector("#chinaSourceCategoryInline");
      const rowIndex = Number(inlinePanel?.dataset.activeRowIndex || -1);
      const currentRow = rowIndex >= 0 ? chinaSourceContainerRowState[rowIndex] : null;
      const supplierName = String(currentRow?.supplier_name || "").trim();
      if (!supplierName || supplierName === "__new__") {
        showTransientInlineNotice("#chinaSourceBaleNotice", "请先在这一行锁定供应商，再给这个供应商新增品类。", "error", 1800);
        return;
      }
      const mainCategory = String(form.querySelector("[name='category_main_new']")?.value || "").trim();
      const subCategory = String(form.querySelector("[name='category_sub_new']")?.value || "").trim();
      const mainCategoryZh = String(form.querySelector("[name='category_main_zh_new']")?.value || "").trim();
      const subCategoryZh = String(form.querySelector("[name='category_sub_zh_new']")?.value || "").trim();
      if (!mainCategory || !subCategory) {
        showTransientInlineNotice("#chinaSourceBaleNotice", "请先填写商品大类和商品小类。", "error", 1800);
        return;
      }
      addSupplierScopedCategoryPair(supplierName, mainCategory, subCategory, {
        categoryMainZh: mainCategoryZh,
        categorySubZh: subCategoryZh,
      });
      resetChinaSourceCategoryInlineEditor();
      applyChinaSourceCategorySelection(mainCategory, subCategory);
      document.querySelector("#chinaSourceCategoryInline")?.classList.add("hidden-screen");
      showTransientInlineNotice(
        "#chinaSourceBaleNotice",
        `${getSupplierDisplayLabel(supplierName, { bilingual: true })} 的品类 ${formatBilingualLabel(mainCategory, mainCategoryZh)} / ${formatBilingualLabel(subCategory, subCategoryZh)} 已加入下拉。`,
        "success",
        1800,
      );
      return;
    }
  }
  const toggle = event.target instanceof HTMLElement ? event.target.closest("[data-sorting-category-toggle]") : null;
  if (toggle instanceof HTMLElement) {
    const categoryMain = String(toggle.dataset.sortingCategoryToggle || "").trim();
    if (!categoryMain) {
      return;
    }
    if (expandedSortingCategoryMains.has(categoryMain)) {
      expandedSortingCategoryMains.delete(categoryMain);
    } else {
      expandedSortingCategoryMains.add(categoryMain);
    }
    refreshSortingShipmentOptions();
    return;
  }
  const rawBaleRouteButton = event.target instanceof HTMLElement ? event.target.closest("[data-raw-bale-route]") : null;
  if (rawBaleRouteButton instanceof HTMLElement) {
    const baleBarcode = String(rawBaleRouteButton.dataset.rawBaleCode || "").trim().toUpperCase();
    const destination = String(rawBaleRouteButton.dataset.rawBaleRoute || "").trim().toLowerCase();
    if (!baleBarcode || !destination) {
      return;
    }
    try {
      await routeRawBaleFromWorkbench(baleBarcode, destination);
    } catch (error) {
      writeOutput("#rawBaleStockOutput", formatErrorMessage(error));
      renderErrorSummary("#rawBaleStockSummary", formatErrorMessage(error));
    }
    return;
  }
  const sortingLookupButton = event.target instanceof HTMLElement ? event.target.closest("[data-sorting-lookup-add]") : null;
  if (sortingLookupButton instanceof HTMLElement) {
    try {
      await addSortingLookupBaleToSelection();
    } catch (error) {
      showTransientInlineNotice("#sortingTaskNotice", formatErrorMessage(error), "error", 2200);
      setSortingScannerError(formatErrorMessage(error));
    }
    return;
  }
  const sortingScannerButton = event.target instanceof HTMLElement
    ? event.target.closest("[data-sorting-scanner-detect], [data-sorting-scanner-refresh], [data-sorting-scanner-authorize], [data-sorting-scanner-focus], [data-sorting-scanner-clear]")
    : null;
  if (sortingScannerButton instanceof HTMLElement) {
    try {
      if (sortingScannerButton.dataset.sortingScannerDetect !== undefined) {
        await startSortingScannerDetection();
        return;
      }
      if (sortingScannerButton.dataset.sortingScannerRefresh !== undefined) {
        await refreshSortingScannerDeviceState();
        return;
      }
      if (sortingScannerButton.dataset.sortingScannerAuthorize !== undefined) {
        await requestSortingScannerHidAccess();
        return;
      }
      if (sortingScannerButton.dataset.sortingScannerFocus !== undefined) {
        const input = document.querySelector("#sortingTaskForm [name='bale_lookup']");
        if (input instanceof HTMLInputElement) {
          input.focus();
          input.select();
        }
        renderSortingScannerHealthSummary();
        return;
      }
      if (sortingScannerButton.dataset.sortingScannerClear !== undefined) {
        const input = document.querySelector("#sortingTaskForm [name='bale_lookup']");
        if (input instanceof HTMLInputElement) {
          input.value = "";
          input.focus();
        }
        if (sortingScannerHealthState.detectionTimerId) {
          clearTimeout(sortingScannerHealthState.detectionTimerId);
          sortingScannerHealthState.detectionTimerId = null;
        }
        sortingScannerHealthState.detectionArmedAtMs = 0;
        sortingScannerHealthState.lastCompletedScan = null;
        sortingScannerHealthState.burstStartedAtMs = 0;
        sortingScannerHealthState.burstLastInputAtMs = 0;
        sortingScannerHealthState.errorMessage = "";
        clearSortingScannerInactivityTimer();
        renderSortingScannerHealthSummary();
        return;
      }
    } catch (error) {
      setSortingScannerError(formatErrorMessage(error));
      showTransientInlineNotice("#sortingTaskNotice", formatErrorMessage(error), "error", 2200);
      return;
    }
  }
  const button = event.target instanceof HTMLElement ? event.target.closest("[data-sorting-add-bale], [data-sorting-remove-bale]") : null;
  if (!(button instanceof HTMLElement)) {
    return;
  }
  if (button.dataset.sortingAddBale) {
    selectedSortingBales = new Set([...selectedSortingBales, button.dataset.sortingAddBale]);
    refreshSortingShipmentOptions();
    return;
  }
  if (button.dataset.sortingRemoveBale) {
    selectedSortingBales = new Set([...selectedSortingBales].filter((code) => code !== button.dataset.sortingRemoveBale));
    refreshSortingShipmentOptions();
  }
});

document.addEventListener("click", (event) => {
  const saveButton = event.target instanceof HTMLElement ? event.target.closest("[data-product-category-save]") : null;
  if (saveButton instanceof HTMLElement) {
    const form = document.querySelector("#productForm");
    if (!(form instanceof HTMLFormElement)) {
      return;
    }
    const supplierName = String(form.querySelector("[name='supplier_name']")?.value || "").trim();
    if (!supplierName || supplierName === "__new__") {
      renderProductCategoryScopeSummary("请先锁定供应商，再维护这个供应商自己的品类。");
      return;
    }
    const categoryMain = String(form.querySelector("[name='product_category_main_new']")?.value || "").trim();
    const categorySub = String(form.querySelector("[name='product_category_sub_new']")?.value || "").trim();
    const categoryMainZh = String(form.querySelector("[name='product_category_main_zh_new']")?.value || "").trim();
    const categorySubZh = String(form.querySelector("[name='product_category_sub_zh_new']")?.value || "").trim();
    const editingKey = String(form.querySelector("[name='product_category_editing_key']")?.value || "").trim();
    if (!categoryMain || !categorySub) {
      renderProductCategoryScopeSummary("请先填写要保存的大类和小类。");
      return;
    }
    const existingRows = getSupplierScopedCategoryRows(supplierName);
    const duplicate = existingRows.find(
      (row) =>
        row.key.toLowerCase() === `${supplierName}|||${categoryMain}|||${categorySub}`.toLowerCase()
        && (!editingKey || row.key.toLowerCase() !== editingKey.toLowerCase()),
    );
    if (duplicate) {
      renderProductCategoryScopeSummary(`${supplierName} 下已经有 ${categoryMain} / ${categorySub}。`);
      return;
    }
    if (editingKey) {
      const [, originalMain = "", originalSub = ""] = editingKey.split("|||");
      removeSupplierScopedCategoryPair(supplierName, originalMain, originalSub);
    }
    addSupplierScopedCategoryPair(supplierName, categoryMain, categorySub, {
      categoryMainZh,
      categorySubZh,
    });
    resetProductCategoryInlineEditor();
    refreshProductCategoryControls({
      selectedMain: categoryMain,
      selectedSub: categorySub,
      notice: `${getSupplierDisplayLabel(supplierName, { bilingual: true })} 的 ${formatBilingualLabel(categoryMain, categoryMainZh)} / ${formatBilingualLabel(categorySub, categorySubZh)} 已保存并自动选中。`,
    });
    return;
  }

  const editButton = event.target instanceof HTMLElement ? event.target.closest("[data-product-category-edit]") : null;
  if (editButton instanceof HTMLElement) {
    const form = document.querySelector("#productForm");
    if (!(form instanceof HTMLFormElement)) {
      return;
    }
    const supplierName = String(form.querySelector("[name='supplier_name']")?.value || "").trim();
    const [currentSupplier = "", categoryMain = "", categorySub = ""] = String(editButton.dataset.productCategoryEdit || "").split("|||");
    if (!supplierName || supplierName !== currentSupplier) {
      return;
    }
    prefillProductCategoryInlineEditor({
      supplierName,
      categoryMain,
      categorySub,
      categoryMainZh: getSupplierScopedCategoryMainZh(supplierName, categoryMain),
      categorySubZh: getSupplierScopedCategorySubZh(supplierName, categoryMain, categorySub),
      editingKey: `${supplierName}|||${categoryMain}|||${categorySub}`,
    });
    renderProductCategoryScopeSummary(`正在编辑 ${getSupplierDisplayLabel(supplierName, { bilingual: true })} 的 ${getCategoryMainDisplayLabel(categoryMain, { supplierName, bilingual: true })} / ${getCategorySubDisplayLabel(categoryMain, categorySub, { supplierName, bilingual: true })}。`);
    return;
  }

  const removeButton = event.target instanceof HTMLElement ? event.target.closest("[data-product-category-remove]") : null;
  if (removeButton instanceof HTMLElement) {
    const form = document.querySelector("#productForm");
    if (!(form instanceof HTMLFormElement)) {
      return;
    }
    const supplierName = String(form.querySelector("[name='supplier_name']")?.value || "").trim();
    const [currentSupplier = "", categoryMain = "", categorySub = ""] = String(removeButton.dataset.productCategoryRemove || "").split("|||");
    if (!supplierName || supplierName !== currentSupplier) {
      return;
    }
    removeSupplierScopedCategoryPair(supplierName, categoryMain, categorySub);
    const mainSelect = form.querySelector("[data-product-category-main]");
    const subSelect = form.querySelector("[data-product-category-sub]");
    const selectedMain = String(mainSelect?.value || "").trim();
    const selectedSub = String(subSelect?.value || "").trim();
    const keepCurrent = !(selectedMain === categoryMain && selectedSub === categorySub);
    resetProductCategoryInlineEditor();
    refreshProductCategoryControls({
      selectedMain: keepCurrent ? selectedMain : "",
      selectedSub: keepCurrent ? selectedSub : "",
      notice: `${getSupplierDisplayLabel(supplierName, { bilingual: true })} 的 ${getCategoryMainDisplayLabel(categoryMain, { supplierName, bilingual: true })} / ${getCategorySubDisplayLabel(categoryMain, categorySub, { supplierName, bilingual: true })} 已删除。`,
    });
    return;
  }
});

