document.addEventListener("click", async (event) => {
  const button = event.target instanceof HTMLElement
    ? event.target.closest("[data-store-dispatch-fill], [data-store-dispatch-accept], [data-store-receipt-bale-fill], [data-store-dispatch-edit], [data-direct-hang-edit], [data-token-edit-save], [data-store-dispatch-assignment-fill], [data-store-dispatch-progress-fill], [data-clerk-bale-open]")
    : null;
  if (!(button instanceof HTMLElement)) {
    return;
  }
  try {
    if (button.dataset.clerkBaleOpen) {
      const baleNo = String(button.dataset.clerkBaleOpen || "").trim().toUpperCase();
      const assignedEmployee = String(button.dataset.clerkBaleEmployee || "").trim();
      const flowType = String(button.dataset.clerkBaleFlow || "sorting").trim();
      const row = getStoreClerkAssignedBales(getCurrentStoreCodeFallback(), assignedEmployee).find(
        (item) => String(item?.bale_no || "").trim().toUpperCase() === baleNo,
      );
      populateStoreFlowFormsFromContext(row || {
        bale_no: baleNo,
        assigned_employee: assignedEmployee,
        store_code: getCurrentStoreCodeFallback(),
      });
      if (flowType === "direct_hang") {
        const form = document.querySelector("#directHangStoreWorkbenchForm");
        if (form instanceof HTMLFormElement) {
          await submitDirectHangStoreWorkbenchDirectory({ preventDefault() {}, currentTarget: form });
        }
        const panelKey = getPanelKeyByTitle("store", "7.2 直挂店员工作台");
        if (panelKey) {
          setActivePanel(panelKey);
          focusElement("#directHangStoreWorkbenchForm");
        }
      } else {
        const form = document.querySelector("#storeTokenEditDirectoryForm");
        if (form instanceof HTMLFormElement) {
          await submitStoreTokenEditDirectory({ preventDefault() {}, currentTarget: form });
        }
        const panelKey = getPanelKeyByTitle("store", "7. 店员 PDA 上架工作台");
        if (panelKey) {
          setActivePanel(panelKey);
          focusElement("#storeTokenEditDirectoryForm");
        }
      }
      return;
    }
    if (button.dataset.storeDispatchFill) {
      const baleNo = String(button.dataset.storeDispatchFill || "").trim().toUpperCase();
      const row = storeDispatchBaleState.find((item) => String(item?.bale_no || "").trim().toUpperCase() === baleNo);
      populateStoreFlowFormsFromContext(row || { bale_no: baleNo });
      showTransientInlineNotice("#storeDispatchBaleNotice", `已把 ${baleNo} 填入当前门店流程。`, "success", 1200);
      return;
    }
    if (button.dataset.storeDispatchAccept) {
      const baleNo = String(button.dataset.storeDispatchAccept || "").trim().toUpperCase();
      const storeCode = getCurrentStoreCodeFallback();
      const row = storeDispatchBaleState.find((item) => String(item?.bale_no || "").trim().toUpperCase() === baleNo);
      const result = await request(`/stores/dispatch-bales/${encodeURIComponent(baleNo)}/accept`, {
        method: "POST",
        body: JSON.stringify({
          store_code: storeCode,
          transfer_no: String(row?.transfer_no || "").trim().toUpperCase(),
          note: "门店已验收配货 bale",
        }),
      });
      populateStoreFlowFormsFromContext(result);
      await refreshStoreDispatchBaleDirectoryFromForm({ lastAccepted: baleNo });
      showTransientInlineNotice("#storeDispatchBaleNotice", `门店配货 bale ${baleNo} 已验收。`, "success", 1800);
      const panelKey = getPanelKeyByTitle("store", "6.1 门店分配店员");
      if (panelKey) {
        setActivePanel(panelKey);
        focusElement("#storeDispatchAssignmentForm");
      }
      return;
    }
    if (button.dataset.storeReceiptBaleFill) {
      const baleNo = String(button.dataset.storeReceiptBaleFill || "").trim().toUpperCase();
      const transferNo = String(button.dataset.storeReceiptTransfer || "").trim().toUpperCase();
      setInputValue("#storeDispatchBaleAcceptForm [name='transfer_no']", transferNo);
      const currentText = String(document.querySelector("#storeDispatchBaleAcceptForm [name='bale_no']")?.value || "").trim();
      setInputValue("#storeDispatchBaleAcceptForm [name='bale_no']", [currentText, baleNo].filter(Boolean).join("\n"));
      renderStoreReceiptTransferBaleList(transferNo);
      focusElement("#storeDispatchBaleAcceptForm");
      return;
    }
    if (button.dataset.storeReceiptTransferFill) {
      const transferNo = String(button.dataset.storeReceiptTransferFill || "").trim().toUpperCase();
      setInputValue("#storeDispatchBaleAcceptForm [name='transfer_no']", transferNo);
      setInputValue("#storeDispatchBaleAcceptForm [name='bale_no']", "");
      renderStoreReceiptTransferBaleList(transferNo);
      const panelKey = getPanelKeyByTitle("store", "6. 门店验收配货 bale");
      if (panelKey) {
        setActivePanel(panelKey);
        focusElement("#storeDispatchBaleAcceptForm");
      }
      return;
    }
    if (button.dataset.storeDispatchAssignmentFill) {
      const baleNo = String(button.dataset.storeDispatchAssignmentFill || "").trim().toUpperCase();
      const row = getStoreManagerConsoleRows(getCurrentStoreCodeFallback()).find((item) => String(item?.bale_no || "").trim().toUpperCase() === baleNo);
      populateStoreFlowFormsFromContext(row || { bale_no: baleNo });
      const panelKey = getPanelKeyByTitle("store", "6.1 门店分配店员");
      if (panelKey) {
        setActivePanel(panelKey);
        focusElement("#storeDispatchAssignmentForm");
      }
      return;
    }
    if (button.dataset.storeAssignmentTransferFill) {
      const transferNo = String(button.dataset.storeAssignmentTransferFill || "").trim().toUpperCase();
      const bales = String(button.dataset.storeAssignmentBales || "").trim();
      setInputValue("#storeDispatchAssignmentForm [name='transfer_no']", transferNo);
      setInputValue("#storeDispatchAssignmentForm [name='bale_no']", bales);
      const panelKey = getPanelKeyByTitle("store", "6.1 门店分配店员");
      if (panelKey) {
        setActivePanel(panelKey);
        focusElement("#storeDispatchAssignmentForm");
      }
      return;
    }
    if (button.dataset.storeDispatchProgressFill) {
      const baleNo = String(button.dataset.storeDispatchProgressFill || "").trim().toUpperCase();
      const assignedEmployee = String(button.dataset.storeDispatchEmployee || "").trim();
      const progressPlan = getStoreManagerProgressNavigationPlan();
      const row = getStoreManagerConsoleRows(getCurrentStoreCodeFallback()).find((item) => String(item?.bale_no || "").trim().toUpperCase() === baleNo);
      populateStoreFlowFormsFromContext(row || { bale_no: baleNo, assigned_employee: assignedEmployee });
      if (row) {
        renderStoreDispatchAssignmentResultSummary(row);
      }
      const panelKey = getPanelKeyByTitle("store", progressPlan.panelTitle);
      if (panelKey) {
        setActivePanel(panelKey);
        focusElement("#storeDispatchAssignmentForm");
      }
      return;
    }
    if (button.dataset.storeDispatchEdit) {
      const baleNo = String(button.dataset.storeDispatchEdit || "").trim().toUpperCase();
      const assignedEmployee = String(button.dataset.storeDispatchEmployee || "").trim();
      const row = storeDispatchBaleState.find((item) => String(item?.bale_no || "").trim().toUpperCase() === baleNo);
      populateStoreFlowFormsFromContext(row || { bale_no: baleNo, assigned_employee: assignedEmployee });
      const form = document.querySelector("#storeTokenEditDirectoryForm");
      if (form instanceof HTMLFormElement) {
        await submitStoreTokenEditDirectory({ preventDefault() {}, currentTarget: form });
      }
      const panelKey = getPanelKeyByTitle("store", "7. 店员 PDA 上架工作台");
      if (panelKey) {
        setActivePanel(panelKey);
        focusElement("#storeTokenEditDirectoryForm");
      }
      return;
    }
    if (button.dataset.directHangEdit) {
      const baleNo = String(button.dataset.directHangEdit || "").trim().toUpperCase();
      const assignedEmployee = String(button.dataset.storeDispatchEmployee || "").trim();
      const row = ensureDirectHangDispatchBaleState().find((item) => String(item?.bale_no || "").trim().toUpperCase() === baleNo);
      populateStoreFlowFormsFromContext(row || { bale_no: baleNo, assigned_employee: assignedEmployee });
      const form = document.querySelector("#directHangStoreWorkbenchForm");
      if (form instanceof HTMLFormElement) {
        await submitDirectHangStoreWorkbenchDirectory({ preventDefault() {}, currentTarget: form });
      }
      const panelKey = getPanelKeyByTitle("store", "7.2 直挂店员工作台");
      if (panelKey) {
        setActivePanel(panelKey);
        focusElement("#directHangStoreWorkbenchForm");
      }
      return;
    }
    if (button.dataset.tokenEditSave) {
      const tokenNo = String(button.dataset.tokenEditSave || "").trim().toUpperCase();
      const sellingInput = document.querySelector(`[data-token-edit-field="selling_price_kes"][data-token-no="${CSS.escape(tokenNo)}"]`);
      const rackInput = document.querySelector(`[data-token-edit-field="store_rack_code"][data-token-no="${CSS.escape(tokenNo)}"]`);
      const sellingPriceKes = Number(String(sellingInput?.value || "").trim());
      const storeRackCode = String(rackInput?.value || "").trim().toUpperCase();
      if (!Number.isFinite(sellingPriceKes) || sellingPriceKes <= 0) {
        throw new Error("请先填写有效的售价。");
      }
      if (!storeRackCode) {
        throw new Error("请先填写货架位。");
      }
      const storeCode = getCurrentStoreCodeFallback();
      const result = await request(`/stores/item-barcode-tokens/${encodeURIComponent(tokenNo)}/edit`, {
        method: "PATCH",
        body: JSON.stringify({
          store_code: storeCode,
          selling_price_kes: sellingPriceKes,
          store_rack_code: storeRackCode,
          note: "店员已在 PDA 完成售价和货架位编辑",
        }),
      });
      itemBarcodeTokenState = itemBarcodeTokenState.map((row) => (
        String(row?.token_no || "").trim().toUpperCase() === tokenNo ? result : row
      ));
      filteredItemBarcodeTokenState = filteredItemBarcodeTokenState.map((row) => (
        String(row?.token_no || "").trim().toUpperCase() === tokenNo ? result : row
      ));
      populateStoreFlowFormsFromContext({
        bale_no: result.store_dispatch_bale_no || "",
        assigned_employee: result.assigned_employee || "",
        store_code: result.store_code || storeCode,
      });
      renderStoreTokenEditSummary(filteredItemBarcodeTokenState, { lastSavedToken: tokenNo });
      writeOutput("#storeTokenEditOutput", result);
    }
  } catch (error) {
    const message = formatErrorMessage(error);
    const outputTarget = button.dataset.tokenEditSave ? "#storeTokenEditOutput" : "#storeDispatchBaleOutput";
    writeOutput(outputTarget, message);
    const summaryTarget = button.dataset.tokenEditSave ? "#storeTokenEditSummary" : "#storeDispatchBaleSummary";
    renderErrorSummary(summaryTarget, message);
  }
});

document.addEventListener("click", async (event) => {
  const button = event.target instanceof HTMLElement
    ? event.target.closest("[data-pda-category-select], [data-pda-start-session], [data-pda-apply-default], [data-pda-apply-premium], [data-pda-queue-group], [data-pda-complete-group], [data-pda-finalize-bale]")
    : null;
  if (!(button instanceof HTMLElement)) {
    return;
  }
  try {
    if (button.dataset.pdaCategorySelect) {
      syncStorePdaWorkbenchStateFromDom();
      storePdaWorkbenchState.selectedCategoryKey = String(button.dataset.pdaCategorySelect || "").trim().toLowerCase();
      renderStoreTokenEditSummary(filteredItemBarcodeTokenState);
      return;
    }

    syncStorePdaWorkbenchStateFromDom();
    const { group, rows } = getCurrentStorePdaCategoryState();
    const baleNo = String(document.querySelector("#storeTokenEditDirectoryForm [name='bale_no']")?.value || "").trim().toUpperCase();
    const storeCode = String(document.querySelector("#storeTokenEditDirectoryForm [name='store_code']")?.value || getCurrentStoreCodeFallback()).trim().toUpperCase();
    if (!group || !rows.length) {
      throw new Error("请先读取一个已分配的门店配货 bale。");
    }

    if (button.dataset.pdaStartSession !== undefined) {
      await ensureStorePdaReceivingSession({ baleNo, storeCode });
      await refreshStorePdaWorkbench({ lastSavedToken: "上架会话已开始" });
      showTransientInlineNotice("#storeTokenEditNotice", `已为 ${baleNo} 开始门店上架会话。`, "success", 1500);
      return;
    }

    if (button.dataset.pdaApplyDefault !== undefined) {
      const sellingPriceKes = Number(storePdaWorkbenchState.defaultPriceKes || 0);
      const storeRackCode = String(storePdaWorkbenchState.defaultRackCode || "").trim().toUpperCase();
      if (!(sellingPriceKes > 0)) {
        throw new Error("请先填写当前分组的默认售价。");
      }
      if (!storeRackCode) {
        throw new Error("请先填写当前分组的默认货架位。");
      }
      const editableRows = rows.filter((row) => !["print_queued", "printed_in_store", "shelved_in_store"].includes(String(row.status || "").trim()))
        .filter((row) => row.selling_price_kes == null || !String(row.store_rack_code || "").trim());
      if (!editableRows.length) {
        throw new Error("当前分组没有待应用默认值的 token。");
      }
      for (const row of editableRows) {
        await request(`/stores/item-barcode-tokens/${encodeURIComponent(row.token_no)}/edit`, {
          method: "PATCH",
          body: JSON.stringify({
            store_code: storeCode,
            selling_price_kes: sellingPriceKes,
            store_rack_code: storeRackCode,
            note: "PDA 工作台批量应用默认售价和货架位",
          }),
        });
      }
      await refreshStorePdaWorkbench({ lastSavedToken: `${group.main} / ${group.sub}` });
      showTransientInlineNotice("#storeTokenEditNotice", `已把默认售价和货架位应用到 ${editableRows.length} 件 ${group.main} / ${group.sub}。`, "success", 1800);
      return;
    }

    if (button.dataset.pdaApplyPremium !== undefined) {
      const premiumCount = Number(storePdaWorkbenchState.premiumCount || 0);
      const premiumPriceKes = Number(storePdaWorkbenchState.premiumPriceKes || 0);
      const fallbackRackCode = String(storePdaWorkbenchState.defaultRackCode || "").trim().toUpperCase();
      if (!(premiumCount > 0)) {
        throw new Error("请先填写高价值件数。");
      }
      if (!(premiumPriceKes > 0)) {
        throw new Error("请先填写高价值售价。");
      }
      const premiumRows = rows
        .filter((row) => !["print_queued", "printed_in_store", "shelved_in_store"].includes(String(row.status || "").trim()))
        .slice(0, premiumCount);
      if (!premiumRows.length) {
        throw new Error("当前分组没有可设置高价值例外的 token。");
      }
      for (const row of premiumRows) {
        await request(`/stores/item-barcode-tokens/${encodeURIComponent(row.token_no)}/edit`, {
          method: "PATCH",
          body: JSON.stringify({
            store_code: storeCode,
            selling_price_kes: premiumPriceKes,
            store_rack_code: String(row.store_rack_code || fallbackRackCode || row.suggested_rack_code || "").trim().toUpperCase(),
            note: "PDA 工作台标记高价值例外售价",
          }),
        });
      }
      await refreshStorePdaWorkbench({ lastSavedToken: `${group.main} / ${group.sub}` });
      showTransientInlineNotice("#storeTokenEditNotice", `已把 ${premiumRows.length} 件 ${group.main} / ${group.sub} 记为高价值例外。`, "success", 1800);
      return;
    }

    if (button.dataset.pdaQueueGroup !== undefined) {
      const printerName = String(storePdaWorkbenchState.printerName || "").trim() || "Deli DL-720C";
      const templateCode = String(storePdaWorkbenchState.templateCode || getPreferredItemTokenTemplateCode()).trim().toLowerCase();
      const printableTokenNos = rows
        .filter((row) => ["pending_store_print", "print_failed"].includes(String(row.status || "").trim()))
        .filter((row) => row.selling_price_kes !== null && row.selling_price_kes !== undefined)
        .filter((row) => String(row.store_rack_code || "").trim())
        .map((row) => String(row.token_no || "").trim())
        .filter(Boolean);
      if (!printableTokenNos.length) {
        throw new Error("当前分组还没有可打印的 token，请先补售价和货架位。");
      }
      await loadSystemPrinters();
      const matchedPrinter = findSystemPrinterBySelectedName(printerName);
      if (!matchedPrinter) {
        throw new Error(systemPrinterState.length
          ? `系统里没有找到名为 ${printerName} 的打印机，请先检查蓝牙打印机名称。`
          : "当前电脑没有识别到任何系统打印机，请先连接蓝牙打印机。");
      }
      await request("/print-jobs/item-tokens", {
        method: "POST",
        body: JSON.stringify({
          bale_no: baleNo,
          assigned_employee: String(document.querySelector("#storeTokenEditDirectoryForm [name='assigned_employee']")?.value || "").trim(),
          printer_name: String(matchedPrinter.name || printerName).trim(),
          template_code: templateCode,
          copies: 1,
          token_nos: printableTokenNos,
        }),
      });
      if (document.querySelector("#storeBluetoothPrinterForm [name='bale_no']")) {
        setInputValue("#storeBluetoothPrinterForm [name='bale_no']", baleNo);
        setInputValue("#storeBluetoothPrinterForm [name='assigned_employee']", String(document.querySelector("#storeTokenEditDirectoryForm [name='assigned_employee']")?.value || "").trim());
        setInputValue("#storeBluetoothPrinterForm [name='printer_name']", printerName);
        setInputValue("#itemTokenPrintQueueForm [name='template_code']", templateCode);
      }
      await loadItemTokenPrintJobs();
      await refreshStorePdaWorkbench({ lastQueuedCount: printableTokenNos.length });
      showTransientInlineNotice("#storeTokenEditNotice", `当前分组已加入 ${printableTokenNos.length} 张标签到打印队列。`, "success", 1800);
      return;
    }

    if (button.dataset.pdaCompleteGroup !== undefined) {
      const rackFallback = String(storePdaWorkbenchState.defaultRackCode || "").trim().toUpperCase();
      const printedRows = rows.filter((row) => String(row.status || "").trim() === "printed_in_store");
      if (!printedRows.length) {
        throw new Error("当前分组还没有已打印待上架的 token。");
      }
      const session = await ensureStorePdaReceivingSession({ baleNo, storeCode });
      let lastResult = null;
      for (const row of printedRows) {
        const rackCode = String(row.store_rack_code || rackFallback || row.suggested_rack_code || "").trim().toUpperCase();
        if (!rackCode) {
          throw new Error(`商品 ${row.token_no} 还没有货架位，不能完成本组上架。`);
        }
        lastResult = await request(`/store-token-receiving-sessions/${session.session_no}/batches`, {
          method: "POST",
          body: JSON.stringify({
            token_no: row.token_no,
            rack_code: rackCode,
            note: `PDA 工作台完成 ${group.main} / ${group.sub} 分组上架`,
          }),
        });
      }
      if (lastResult) {
        writeOutput("#receivingOutput", lastResult);
        renderReceivingResultSummary(lastResult);
        hydrateReceivingSessionForms(lastResult);
      }
      await refreshStorePdaWorkbench({ lastCompletedGroup: `${group.main} / ${group.sub}` });
      showTransientInlineNotice("#storeTokenEditNotice", `已完成 ${printedRows.length} 件 ${group.main} / ${group.sub} 的上架。`, "success", 1800);
      return;
    }

    if (button.dataset.pdaFinalizeBale !== undefined) {
      const session = await ensureStorePdaReceivingSession({ baleNo, storeCode });
      const result = await request(`/store-token-receiving-sessions/${session.session_no}/finalize`, {
        method: "POST",
        body: JSON.stringify({
          note: "PDA 工作台已完成当前门店配货 bale 的贴码上架",
        }),
      });
      writeOutput("#receivingOutput", result);
      renderReceivingResultSummary(result);
      hydrateReceivingSessionForms(result);
      await refreshStoreDispatchBaleDirectoryFromForm();
      const completionPlan = getStoreClerkCompletionNavigationPlan(baleNo);
      refreshStoreClerkHomeWithContext({
        store_code: storeCode,
        assigned_employee: String(document.querySelector("#storeTokenEditDirectoryForm [name='assigned_employee']")?.value || "").trim(),
        last_action_message: completionPlan.completionMessage,
      });
      await refreshStorePdaWorkbench({ lastCompletedGroup: "本 bale" });
      showTransientInlineNotice("#storeTokenEditNotice", `当前 bale ${baleNo} 已完成并核对未上架 token。`, "success", 1800);
      const panelKey = getPanelKeyByTitle("store", completionPlan.panelTitle);
      if (panelKey) {
        setActivePanel(panelKey);
        focusElement("#storeClerkHomeForm");
      }
    }
  } catch (error) {
    const message = formatErrorMessage(error);
    writeOutput("#storeTokenEditOutput", message);
    renderErrorSummary("#storeTokenEditSummary", message);
  }
});

document.addEventListener("click", async (event) => {
  const button = event.target instanceof HTMLElement ? event.target.closest("[data-direct-hang-action]") : null;
  if (!(button instanceof HTMLElement)) {
    return;
  }
  try {
    syncDirectHangWorkbenchStateFromDom();
    const baleNo = String(document.querySelector("#directHangStoreWorkbenchForm [name='bale_no']")?.value || "").trim().toUpperCase();
    const storeCode = String(document.querySelector("#directHangStoreWorkbenchForm [name='store_code']")?.value || getCurrentStoreCodeFallback()).trim().toUpperCase();
    const assignedEmployee = String(document.querySelector("#directHangStoreWorkbenchForm [name='assigned_employee']")?.value || "").trim();
    const bale = ensureDirectHangDispatchBaleState().find(
      (row) => String(row?.bale_no || "").trim().toUpperCase() === baleNo,
    );
    if (!bale || String(bale.flow_type || "").trim() !== "direct_hang") {
      throw new Error("请先读取一个已分配店员的直挂门店配货 bale。");
    }
    const rows = getDirectHangItemsByBale(baleNo, assignedEmployee);
    if (!rows.length) {
      throw new Error("当前 bale 下没有待处理商品。");
    }

    if (button.dataset.directHangAction === "apply-default") {
      const sellingPriceKes = Number(directHangWorkbenchState.defaultPriceKes || 0);
      const storeRackCode = String(directHangWorkbenchState.defaultRackCode || "").trim().toUpperCase();
      if (!(sellingPriceKes > 0)) {
        throw new Error("请先填写默认售价。");
      }
      if (!storeRackCode) {
        throw new Error("请先填写默认货架位。");
      }
      directHangStoreItemState = ensureDirectHangStoreItemState().map((row) => (
        String(row?.bale_no || "").trim().toUpperCase() === baleNo && String(row?.assigned_employee || "").trim() === assignedEmployee
          ? {
              ...row,
              store_code: storeCode,
              selling_price_kes: row.selling_price_kes != null ? row.selling_price_kes : sellingPriceKes,
              store_rack_code: String(row.store_rack_code || "").trim() || storeRackCode,
              edited_at: row.edited_at || new Date().toISOString(),
            }
          : row
      ));
      persistDirectHangStoreItemState();
      await refreshDirectHangWorkbench();
      showTransientInlineNotice("#directHangStoreWorkbenchNotice", `已把默认售价和货架位应用到当前直挂 bale。`, "success", 1600);
      return;
    }

    if (button.dataset.directHangAction === "apply-premium") {
      const premiumCount = Number(directHangWorkbenchState.premiumCount || 0);
      const premiumPriceKes = Number(directHangWorkbenchState.premiumPriceKes || 0);
      if (!(premiumCount > 0)) {
        throw new Error("请先填写高价值件数。");
      }
      if (!(premiumPriceKes > 0)) {
        throw new Error("请先填写高价值售价。");
      }
      let applied = 0;
      directHangStoreItemState = ensureDirectHangStoreItemState().map((row) => {
        if (
          String(row?.bale_no || "").trim().toUpperCase() === baleNo
          && String(row?.assigned_employee || "").trim() === assignedEmployee
          && applied < premiumCount
        ) {
          applied += 1;
          return {
            ...row,
            store_code: storeCode,
            selling_price_kes: premiumPriceKes,
            store_rack_code: String(row.store_rack_code || "").trim() || String(directHangWorkbenchState.defaultRackCode || "").trim().toUpperCase(),
            edited_at: new Date().toISOString(),
          };
        }
        return row;
      });
      persistDirectHangStoreItemState();
      await refreshDirectHangWorkbench();
      showTransientInlineNotice("#directHangStoreWorkbenchNotice", `已记录 ${premiumCount} 件高价值例外。`, "success", 1600);
      return;
    }

    if (button.dataset.directHangAction === "print-all") {
      const printableRows = rows.filter((row) => row.selling_price_kes != null && String(row.store_rack_code || "").trim());
      if (printableRows.length !== rows.length) {
        throw new Error("请先给本包全部商品补齐售价和货架位，再统一生成商品码。");
      }
      await loadSystemPrinters();
      const printerName = String(directHangWorkbenchState.printerName || "").trim() || "Deli DL-720C";
      const matchedPrinter = findSystemPrinterBySelectedName(printerName);
      if (!matchedPrinter) {
        throw new Error(systemPrinterState.length
          ? `系统里没有找到名为 ${printerName} 的打印机，请先检查蓝牙打印机名称。`
          : "当前电脑没有识别到任何系统打印机，请先连接蓝牙打印机。");
      }
      directHangStoreItemState = ensureDirectHangStoreItemState().map((row) => {
        if (String(row?.bale_no || "").trim().toUpperCase() !== baleNo || String(row?.assigned_employee || "").trim() !== assignedEmployee) {
          return row;
        }
        const identityNo = row.identity_no || buildDirectHangIdentityNo(baleNo, Number(row.qty_index || 0));
        return {
          ...row,
          store_code: storeCode,
          identity_no: identityNo,
          barcode_value: row.barcode_value || buildDirectHangBarcodeValue(identityNo),
          status: "printed_in_store",
          edited_at: row.edited_at || new Date().toISOString(),
          printed_at: row.printed_at || new Date().toISOString(),
        };
      });
      directHangDispatchBaleState = ensureDirectHangDispatchBaleState().map((row) => (
        String(row?.bale_no || "").trim().toUpperCase() === baleNo
          ? { ...row, status: "printing_in_progress", assigned_employee: assignedEmployee }
          : row
      ));
      persistDirectHangStoreItemState();
      persistDirectHangDispatchBaleState();
      await refreshStoreDispatchBaleDirectoryFromForm();
      await refreshDirectHangWorkbench({ printed: true });
      showTransientInlineNotice("#directHangStoreWorkbenchNotice", `当前 bale 已生成商品码并回写打印状态。`, "success", 1800);
      return;
    }

    if (button.dataset.directHangAction === "finalize") {
      const printableRows = rows.filter((row) => String(row.status || "").trim() === "printed_in_store" || String(row.status || "").trim() === "shelved_in_store");
      if (printableRows.length !== rows.length) {
        throw new Error("请先把当前直挂 bale 全部生成商品码后，再完成上架。");
      }
      directHangStoreItemState = ensureDirectHangStoreItemState().map((row) => (
        String(row?.bale_no || "").trim().toUpperCase() === baleNo && String(row?.assigned_employee || "").trim() === assignedEmployee
          ? { ...row, status: "shelved_in_store", shelved_at: row.shelved_at || new Date().toISOString() }
          : row
      ));
      directHangDispatchBaleState = ensureDirectHangDispatchBaleState().map((row) => (
        String(row?.bale_no || "").trim().toUpperCase() === baleNo
          ? { ...row, status: "completed", assigned_employee: assignedEmployee }
          : row
      ));
      directHangDispatchOrderState = ensureDirectHangDispatchOrderState().map((row) => (
        String(row?.transfer_no || "").trim().toUpperCase() === String(bale.transfer_no || "").trim().toUpperCase()
          ? {
              ...row,
              completed_dispatch_bale_count: String(bale.status || "").trim().toLowerCase() === "completed"
                ? Number(row.completed_dispatch_bale_count || 0)
                : Number(row.completed_dispatch_bale_count || 0) + 1,
              status: "completed",
            }
          : row
      ));
      persistDirectHangStoreItemState();
      persistDirectHangDispatchBaleState();
      persistDirectHangDispatchOrderState();
      await refreshStoreDispatchBaleDirectoryFromForm();
      const completionPlan = getStoreClerkCompletionNavigationPlan(baleNo);
      refreshStoreClerkHomeWithContext({
        store_code: storeCode,
        assigned_employee: assignedEmployee,
        last_action_message: completionPlan.completionMessage,
      });
      await refreshDirectHangWorkbench({ finalized: true });
      showTransientInlineNotice("#directHangStoreWorkbenchNotice", `当前直挂 bale 已完成上架。`, "success", 1800);
      const panelKey = getPanelKeyByTitle("store", completionPlan.panelTitle);
      if (panelKey) {
        setActivePanel(panelKey);
        focusElement("#storeClerkHomeForm");
      }
    }
  } catch (error) {
    const message = formatErrorMessage(error);
    writeOutput("#directHangStoreWorkbenchOutput", message);
    renderErrorSummary("#directHangStoreWorkbenchSummary", message);
  }
});

document.addEventListener("click", async (event) => {
  const target = event.target instanceof HTMLElement ? event.target : null;
  if (!(target instanceof HTMLElement)) {
    return;
  }
  const openCreatorButton = target.closest("[data-sorting-compress-category]");
  const acceptanceButton = target.closest("[data-compression-task-open]");
  const closeCreatorButton = target.closest("#sortingCompressionCreatorClose");
  const reprintBaleButton = target.closest("[data-store-prep-bale-reprint]");
  if (!openCreatorButton && !acceptanceButton && !closeCreatorButton && !reprintBaleButton) {
    return;
  }
  try {
    if (closeCreatorButton instanceof HTMLElement) {
      closeSortingCompressionCreator();
      renderSortingStockSummary(sortingStockState);
      return;
    }
    if (openCreatorButton instanceof HTMLElement) {
      await openSortingCompressionCreator({
        groupKey: String(openCreatorButton.dataset.sortingCompressGroupKey || "").trim(),
        taskType: String(openCreatorButton.dataset.sortingCompressTaskType || "store_dispatch").trim(),
      });
      return;
    }
    if (acceptanceButton instanceof HTMLElement) {
      openCompressionTaskForAcceptance(acceptanceButton.dataset.compressionTaskOpen || "");
      return;
    }
    if (reprintBaleButton instanceof HTMLElement) {
      const baleNo = String(reprintBaleButton.dataset.storePrepBaleReprint || "").trim().toUpperCase();
      const row = storePrepBaleState.find((item) => String(item?.bale_no || "").trim().toUpperCase() === baleNo) || null;
      if (!row) {
        throw new Error(`没有找到 ${baleNo} 的已打成包记录。`);
      }
      await directPrintStorePrepBaleHistoricalBarcode(row);
      return;
    }
  } catch (error) {
    const message = formatErrorMessage(error);
    writeOutput("#compressionTaskOutput", message);
    if (acceptanceButton instanceof HTMLElement) {
      renderErrorSummary("#compressionTaskAcceptanceSummary", message);
      return;
    }
    if (openCreatorButton instanceof HTMLElement || reprintBaleButton instanceof HTMLElement) {
      renderErrorSummary("#sortingStockNotice", message);
      return;
    }
    renderErrorSummary("#compressionTaskManagerSummary", message);
  }
});

document.addEventListener("click", async (event) => {
  const button = event.target instanceof HTMLElement ? event.target.closest("[data-inline-supplier-submit]") : null;
  if (!(button instanceof HTMLElement)) {
    return;
  }
  const formId = button.dataset.inlineSupplierSubmit;
  const form = formId ? document.querySelector(`#${formId}`) : null;
  if (!(form instanceof HTMLFormElement)) {
    return;
  }
  try {
    const payload = getInlineSupplierPayload(form);
    const result = await request("/suppliers", {
      method: "POST",
      body: JSON.stringify(payload),
    });
    writeOutput("#supplierOutput", result);
    renderSupplierResultSummary("create", result);
    await loadConfig();
    applySupplierSelectionToForm(formId, result.name || payload.name);
    const summarySelector = FORM_SUMMARY_SELECTORS[`#${formId}`];
    if (summarySelector) {
      const summaryTarget = document.querySelector(summarySelector);
      if (summaryTarget instanceof HTMLElement) {
        summaryTarget.classList.remove("empty-state");
      }
    }
  } catch (error) {
    const message = formatErrorMessage(error);
    writeOutput("#supplierOutput", message);
    renderErrorSummary("#supplierResultSummary", message);
    const summarySelector = FORM_SUMMARY_SELECTORS[`#${formId}`];
    if (summarySelector) {
      renderErrorSummary(summarySelector, message);
    }
  }
});

