document.querySelectorAll("input[name='selection_mode']").forEach((input) => {
  input.addEventListener("change", () => {
    if (getReturnSelectionMode() === "all") {
      selectedReturnBarcodes = new Set(returnCandidatesState.map((row) => row.barcode));
      renderReturnCandidates(returnCandidatesState);
      return;
    }
    if (selectedReturnBarcodes.size === returnCandidatesState.length) {
      selectedReturnBarcodes = new Set();
      renderReturnCandidates(returnCandidatesState);
      return;
    }
    syncReturnSelectionSummary();
  });
});

