document.addEventListener("click", (event) => {
  const button = event.target instanceof HTMLElement ? event.target.closest("[data-bale-template-component-select]") : null;
  if (!(button instanceof HTMLElement)) {
    const fontStepButton = event.target instanceof HTMLElement ? event.target.closest("[data-template-font-component][data-template-font-step]") : null;
    if (!(fontStepButton instanceof HTMLElement)) {
      return;
    }
    const componentId = String(fontStepButton.dataset.templateFontComponent || "").trim();
    const step = Number(fontStepButton.dataset.templateFontStep || 0);
    const draft = ensureLabelTemplateEditorDraft();
    const component = (Array.isArray(draft.layout?.components) ? draft.layout.components : []).find((row) => row.id === componentId);
    if (!component || !Number.isFinite(step)) {
      return;
    }
    updateLabelTemplateComponentById(componentId, "font_size", Number(component.font_size || 6) + step);
    return;
  }
  labelTemplateEditorState.selectedComponentId = String(button.dataset.baleTemplateComponentSelect || "").trim() || "headline";
  renderBaleTemplateEditor();
});

document.addEventListener("change", (event) => {
  const target = event.target instanceof HTMLElement ? event.target : null;
  if (!target) {
    return;
  }
  if (target.matches("#labelTemplateForm [name='paper_preset']")) {
    applyLabelTemplatePaperPreset(target.value);
    return;
  }
  if (target.matches("#labelTemplateForm [name='width_mm'], #labelTemplateForm [name='height_mm']")) {
    const draft = syncLabelTemplateDraftFromForm();
    const guessPreset = labelTemplateFlow.guessPaperPreset || (() => "custom");
    draft.paper_preset = guessPreset(draft.width_mm, draft.height_mm);
    const presetSelect = document.querySelector("#labelTemplateForm [name='paper_preset']");
    if (presetSelect instanceof HTMLSelectElement) {
      presetSelect.value = draft.paper_preset;
    }
    renderBaleTemplateEditor();
    return;
  }
  if (target.matches("#baleTemplateInspector [data-template-component-prop]")) {
    updateSelectedLabelTemplateComponent(
      target.dataset.templateComponentProp || "",
      target instanceof HTMLInputElement && target.type === "checkbox" ? target.checked : target.value,
    );
  }
});

