document.addEventListener("pointerdown", (event) => {
  const resizeHandle = event.target instanceof HTMLElement ? event.target.closest("[data-bale-template-resize-handle]") : null;
  const block = event.target instanceof HTMLElement ? event.target.closest("[data-bale-template-canvas-component]") : null;
  if (!(block instanceof HTMLElement)) {
    return;
  }
  const componentId = String(block.dataset.baleTemplateCanvasComponent || "").trim();
  const canvas = document.querySelector("#baleTemplateCanvas");
  const draft = ensureLabelTemplateEditorDraft();
  if (!(canvas instanceof HTMLElement)) {
    return;
  }
  const component = (Array.isArray(draft.layout?.components) ? draft.layout.components : []).find((item) => item.id === componentId);
  if (!component) {
    return;
  }
  labelTemplateEditorState.selectedComponentId = componentId;
  labelTemplateEditorState.drag = {
    componentId,
    mode: resizeHandle ? "resize" : "move",
    pointerId: event.pointerId,
    startClientX: event.clientX,
    startClientY: event.clientY,
    startXmm: Number(component.x_mm || 0),
    startYmm: Number(component.y_mm || 0),
    startWmm: Number(component.w_mm || 0),
    startHmm: Number(component.h_mm || 0),
    scale: canvas.getBoundingClientRect().width / Math.max(Number(draft.width_mm || 60), 1),
  };
  renderBaleTemplateEditor();
  event.preventDefault();
});

document.addEventListener("pointermove", (event) => {
  const drag = labelTemplateEditorState.drag;
  if (!drag || drag.pointerId !== event.pointerId) {
    return;
  }
  const draft = syncLabelTemplateDraftFromForm();
  const normalizeLayout = labelTemplateFlow.normalizeBaleTemplateLayout || ((layout) => layout || {});
  const updateComponent = labelTemplateFlow.updateBaleTemplateComponent || ((layout, componentId, patch) => ({
    ...layout,
    components: (Array.isArray(layout?.components) ? layout.components : []).map((component) => (
      component.id === componentId ? { ...component, ...patch } : component
    )),
  }));
  const deltaXmm = (event.clientX - drag.startClientX) / Math.max(Number(drag.scale || 1), 0.0001);
  const deltaYmm = (event.clientY - drag.startClientY) / Math.max(Number(drag.scale || 1), 0.0001);
  const patch = drag.mode === "resize"
    ? {
        w_mm: drag.startWmm + deltaXmm,
        h_mm: drag.startHmm + deltaYmm,
      }
    : {
        x_mm: drag.startXmm + deltaXmm,
        y_mm: drag.startYmm + deltaYmm,
      };
  draft.layout = normalizeLayout(
    updateComponent(draft.layout || {}, drag.componentId, patch),
    draft.width_mm,
    draft.height_mm,
  );
  renderBaleTemplateEditor();
});

document.addEventListener("pointerup", (event) => {
  if (labelTemplateEditorState.drag && labelTemplateEditorState.drag.pointerId === event.pointerId) {
    labelTemplateEditorState.drag = null;
  }
});

document.addEventListener("pointercancel", (event) => {
  if (labelTemplateEditorState.drag && labelTemplateEditorState.drag.pointerId === event.pointerId) {
    labelTemplateEditorState.drag = null;
  }
});

document.addEventListener("click", (event) => {
  const button = event.target instanceof HTMLElement ? event.target.closest("[data-dev-edit], [data-dev-toggle-status], [data-dev-move], [data-dev-delete]") : null;
  if (!(button instanceof HTMLElement)) {
    return;
  }
  ensureDevTrackerState();
  if (button.dataset.devEdit) {
    const row = devTrackerState.items.find((item) => item.id === button.dataset.devEdit);
    if (!row) {
      return;
    }
    hydrateDevTaskForm(row);
    focusElement("#devTaskForm");
    return;
  }
  if (button.dataset.devToggleStatus) {
    const row = devTrackerState.items.find((item) => item.id === button.dataset.devToggleStatus);
    if (!row) {
      return;
    }
    row.status = row.status === "done" ? "todo" : "done";
    persistDevTrackerState();
    renderDevTrackerSummary();
    showTransientSummary("#devTrackerSummary", `${row.title} 已更新为${getDevStatusLabel(row.status)}。`, 1200);
    return;
  }
  if (button.dataset.devMove) {
    const direction = button.dataset.devDirection === "down" ? "down" : "up";
    const row = moveDevTask(button.dataset.devMove, direction);
    if (!row) {
      return;
    }
    renderDevTrackerSummary();
    showTransientSummary("#devTrackerSummary", `${row.title} 已${direction === "down" ? "下移" : "上移"}。`, 1200);
    return;
  }
  if (button.dataset.devDelete) {
    const row = devTrackerState.items.find((item) => item.id === button.dataset.devDelete);
    if (!row) {
      return;
    }
    if (!window.confirm(`确认删除“${row.title}”吗？`)) {
      return;
    }
    deleteDevTask(row.id);
    if (String(document.querySelector("#devTaskForm [name='task_id']")?.value || "").trim() === row.id) {
      hydrateDevTaskForm(null);
    }
    renderDevTrackerSummary();
    showTransientSummary("#devTrackerSummary", `${row.title} 已删除。`, 1200);
  }
});

document.addEventListener("click", (event) => {
  const button = event.target instanceof HTMLElement ? event.target.closest("[data-ops-exception-edit], [data-ops-exception-action]") : null;
  if (!(button instanceof HTMLElement)) {
    return;
  }
  if (button.dataset.opsExceptionEdit) {
    const row = ensureOpsExceptionTicketState().find((item) => item.anomaly_no === button.dataset.opsExceptionEdit);
    if (!row) {
      return;
    }
    hydrateOpsExceptionDeskForm(row);
    focusElement("#opsExceptionDeskForm");
    return;
  }
  const anomalyNo = String(button.dataset.anomalyNo || "").trim().toUpperCase();
  const action = String(button.dataset.opsExceptionAction || "").trim();
  const row = ensureOpsExceptionTicketState().find((item) => item.anomaly_no === anomalyNo);
  if (!row) {
    return;
  }
  const now = new Date().toISOString();
  if (action === "claim") {
    row.owner_name = currentSession.user?.full_name || currentSession.user?.username || row.owner_name;
    row.owner_role = currentSession.user?.role_code || row.owner_role;
    row.updated_at = now;
    persistOpsExceptionTicketState();
    renderOpsExceptionDeskSummary(`异常单 ${row.anomaly_no} 已认领。`);
    return;
  }
  if (action === "start") {
    row.status = "in_progress";
    row.acknowledged_at = row.acknowledged_at || now;
    row.owner_name = row.owner_name || currentSession.user?.full_name || currentSession.user?.username || "";
    row.owner_role = row.owner_role || currentSession.user?.role_code || "";
    row.updated_at = now;
    persistOpsExceptionTicketState();
    renderOpsExceptionDeskSummary(`异常单 ${row.anomaly_no} 已进入处理中。`);
    return;
  }
  if (action === "close") {
    row.status = "closed";
    row.closed_at = now;
    row.resolution_note = row.resolution_note || "现场已补证据并关闭。";
    row.updated_at = now;
    persistOpsExceptionTicketState();
    renderOpsExceptionDeskSummary(`异常单 ${row.anomaly_no} 已关闭。`);
    return;
  }
  if (action === "reopen") {
    row.status = "open";
    row.closed_at = "";
    row.updated_at = now;
    persistOpsExceptionTicketState();
    renderOpsExceptionDeskSummary(`异常单 ${row.anomaly_no} 已重新打开。`);
  }
});

