document.querySelectorAll("[data-action]").forEach((button) => {
  button.addEventListener("click", async () => {
    try {
      const action = button.dataset.action;
      if (action === "load-print-jobs") {
        writeOutput("#labelPrintOutput", "正在读取打印任务...");
      }
      if (action === "load-dashboard") {
        await loadDashboard();
        return;
      }
      if (action === "reset-test-history") {
        await resetTestHistory();
        return;
      }
      if (action === "generate-warehouse-mainflow-demo") {
        await generateWarehouseMainflowDemo();
        return;
      }
      if (action === "generate-store-replenishment-demo") {
        await generateStoreReplenishmentDemo();
        return;
      }
      if (action === "barcode-resolver-test-all") {
        await testBarcodeResolverAllContexts();
        return;
      }
      if (action === "load-config") {
        await loadConfig();
        return;
      }
      if (action === "load-rack-template" || action === "load-store-racks") {
        await loadRackView(action);
        return;
      }
      await loadTable(action);
    } catch (error) {
      const action = button.dataset.action;
      if (action === "load-print-jobs") {
        writeOutput("#labelPrintOutput", formatErrorMessage(error));
        renderErrorSummary("#labelPrintResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-config") {
        writeOutput("#storesOutput", formatErrorMessage(error));
        renderErrorSummary("#configSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-inbound-shipments") {
        writeOutput("#inboundShipmentOutput", formatErrorMessage(error));
        renderErrorSummary("#inboundShipmentHistorySummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-parcel-batches") {
        writeOutput("#parcelBatchOutput", formatErrorMessage(error));
        renderErrorSummary("#parcelBatchResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-sorting-tasks") {
        writeOutput("#sortingTaskOutput", formatErrorMessage(error));
        renderErrorSummary("#sortingTaskResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-raw-bales") {
        writeOutput("#rawBaleStockOutput", formatErrorMessage(error));
        renderErrorSummary("#rawBaleStockSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-sorting-stock") {
        writeOutput("#sortingStockOutput", formatErrorMessage(error));
        renderErrorSummary("#sortingStockNotice", formatErrorMessage(error));
        return;
      }
      if (action === "load-stores") {
        writeOutput("#storeOutput", formatErrorMessage(error));
        renderErrorSummary("#storeResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-suppliers") {
        writeOutput("#supplierOutput", formatErrorMessage(error));
        renderErrorSummary("#supplierResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-cargo-types") {
        writeOutput("#cargoTypeOutput", formatErrorMessage(error));
        renderErrorSummary("#cargoTypeResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "reset-test-history") {
        renderErrorSummary("#testResetSummary", formatErrorMessage(error));
        return;
      }
      if (action === "generate-warehouse-mainflow-demo") {
        renderErrorSummary("#warehouseMainflowDemoSummary", formatErrorMessage(error));
        return;
      }
      if (action === "generate-store-replenishment-demo") {
        renderErrorSummary("#storeReplenishmentDemoSummary", formatErrorMessage(error));
        return;
      }
      if (action === "barcode-resolver-test-all") {
        writeOutput("#barcodeResolverTestOutput", "");
        renderErrorSummary("#barcodeResolverTestSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-store-operating-summary") {
        document.querySelector("#storeOperatingSummary").innerHTML = `<div class="empty-state">${escapeHtml(formatErrorMessage(error))}</div>`;
        return;
      }
      if (action === "load-price-rules") {
        writeOutput("#priceRuleOutput", formatErrorMessage(error));
        renderErrorSummary("#priceRuleResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-bale-print-console") {
        writeOutput("#balePrinterConsoleOutput", formatErrorMessage(error));
        renderErrorSummary("#balePrinterConsoleSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-mpesa-collections" || action === "load-mpesa-customer-insights") {
        writeOutput("#mpesaOutput", formatErrorMessage(error));
        renderErrorSummary("#mpesaResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-offline-sync-batches") {
        writeOutput("#offlineSyncOutput", formatErrorMessage(error));
        renderErrorSummary("#offlineSyncResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-void-requests") {
        writeOutput("#saleVoidOutput", formatErrorMessage(error));
        return;
      }
      if (action === "load-refund-requests") {
        writeOutput("#saleRefundOutput", formatErrorMessage(error));
        return;
      }
      if (action === "load-payment-anomalies") {
        writeOutput("#paymentAnomalyOutput", formatErrorMessage(error));
        return;
      }
      if (action === "load-price-alerts") {
        writeOutput("#priceAlertOutput", formatErrorMessage(error));
        return;
      }
      if (action === "load-bale-sales-workbench") {
        writeOutput("#baleSalesWorkbenchOutput", formatErrorMessage(error));
        renderErrorSummary("#baleSalesWorkbenchSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-bale-sales-pricing") {
        writeOutput("#baleSalesPricingOutput", formatErrorMessage(error));
        renderErrorSummary("#baleSalesPricingSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-bale-sales-outbound") {
        writeOutput("#baleSalesOutboundOutput", formatErrorMessage(error));
        renderErrorSummary("#baleSalesOutboundSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-return-candidates") {
        writeOutput("#returnOutput", formatErrorMessage(error));
        return;
      }
      if (action === "load-users" || action === "load-roles") {
        writeOutput("#userOutput", formatErrorMessage(error));
        renderErrorSummary("#userResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-stores") {
        writeOutput("#storeOutput", formatErrorMessage(error));
        renderErrorSummary("#storeResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-price-rules") {
        writeOutput("#priceRuleOutput", formatErrorMessage(error));
        renderErrorSummary("#priceRuleResultSummary", formatErrorMessage(error));
        return;
      }
      if (action === "load-rack-template" || action === "load-store-racks") {
        writeOutput("#rackOutput", formatErrorMessage(error));
        return;
      }
      writeOutput("#tableOutput", formatErrorMessage(error));
    }
  });
});

